-- Poems batch 409
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-522','永遇乐','无名氏','宋','宋词','song-ci','永遇乐','[]','万法由心，应观法界，一切心造。',129,'宋词/ci.song.3000.json','["万法由心，应观法界，一切心造。", "老子瞿昙，同归去揆，不离心是道。", "自从识得，坎离交济，炼药粗知昏晓。", "云腾雨飞，蟾宫兔走，丹阙更无烦恼。", "气中真液，液中真气，和合不多不少。", "种出黄芽，炼成赤水，龙虎交围绕。", "七返九还，工夫到后，还我旧时年少。", "待三千、功圆行满，恁时是了。"]'),
('song-ci-523','永遇乐','无名氏','宋','宋词','song-ci','永遇乐','[]','学道修心，存神炼性，直要轻举。',130,'宋词/ci.song.3000.json','["学道修心，存神炼性，直要轻举。", "补脑还精，流水不腐，户枢终不蠹。", "日魂月魄，抟归炉鼎，真气自然流聚。", "把心猿缚住，意马追回，迥无尘虑。", "定中明有，阳龙阴火，水火透时为度。", "八段奇文，千口活法，向上有一路。", "吕公高尚，未离人世，有分也须相遇。", "约十洲三岛，骖鸾跨鹤，大家同去。"]'),
('song-ci-524','永遇乐','无名氏','宋','宋词','song-ci','永遇乐','[]','养水养精，养神养血，先须养气。',130,'宋词/ci.song.3000.json','["养水养精，养神养血，先须养气。", "日月阴阳，六爻八卦，细看参同契。", "灵躯灵宝，千言万语，不过坎离两字。", "向昆仑顶上，返本还元，要明终始。", "一身虽小，如同天地，八万四千馀里。", "玄牝之门，生生万化，都在冲和内。", "此真真外，别无真谛，方信道一而已。", "异时见锺吕，如有未明，请师指示。"]'),
('song-ci-525','渔家傲','无名氏','宋','宋词','song-ci','渔家傲','[]','至道不遥只在迩。',72,'宋词/ci.song.3000.json','["至道不遥只在迩。", "毫厘差失如千里。", "道是难来元却易。", "如相契。", "一超直入如来地。", "水火交时为既济。", "三尸六贼都回避。", "只此长生仍久视。", "身口意。", "化成一点冲和气。"]'),
('song-ci-526','渔家傲','无名氏','宋','宋词','song-ci','渔家傲','[]','神是性兮气是命。',72,'宋词/ci.song.3000.json','["神是性兮气是命。", "神不外驰气自定。", "幸有崔公入药镜。", "如究竟。", "全真固蒂归根静。", "主客内明方外应。", "灵台粲发天光莹。", "两个壶中一片景。", "急修省。", "莫待临渴去掘井。"]'),
('song-ci-527','渔家傲','无名氏','宋','宋词','song-ci','渔家傲','[]','精养灵根神守气。',72,'宋词/ci.song.3000.json','["精养灵根神守气。", "天然子母何曾离。", "昼夜六时长在意。", "三田内。", "温温天地中和水。", "十二楼前白雪腻。", "九宫台畔黄芽遂。", "日月山头朝上帝。", "神光起。", "腾身直出烟霄外。"]'),
('song-ci-528','渔家傲','无名氏','宋','宋词','song-ci','渔家傲','[]','我有光珠无买价。',72,'宋词/ci.song.3000.json','["我有光珠无买价。", "光明常照芝田下。", "更没之乎并者也。", "知音寡。", "世间谁是能行者。", "一万精光浑守舍。", "四百四病都齐罢。", "透出火龙归造化。", "回仙驾。", "更无一点尘随马。"]'),
('song-ci-529','促拍满路花','无名氏','宋','宋词','song-ci','促拍满路花','[]','抱元能守一，四大自轻安。',102,'宋词/ci.song.3000.json','["抱元能守一，四大自轻安。", "心中须返照，几曾闲。", "金乌衔耀，飞入烂银盘。", "心心心是道，只在心心，更於何处求仙。", "又何须衣冕，燕处欲超然。", "荣华能几日，便凋残。", "修真甚易，积行累功难。", "劝君强为善，五浊三途，便为云岛神山。"]'),
('song-ci-530','促拍满路花','无名氏','宋','宋词','song-ci','促拍满路花','[]','人能常清静，天涤悉皆归。',103,'宋词/ci.song.3000.json','["人能常清静，天涤悉皆归。", "一真含众妙，入希夷。", "昭文不会，气候有成亏。", "妄心寂灭尽，困睡饥餐，更无作用施为。", "自然，炉鼎就，光彩透帘帏。", "玉池神水涌，上生肥。", "如人饮水，冷暖自家知。", "自家性命事，自家了得，自家性命便宜。"]'),
('song-ci-531','促拍满路花','无名氏','宋','宋词','song-ci','促拍满路花','[]','若论修养事，知有几多门。',102,'宋词/ci.song.3000.json','["若论修养事，知有几多门。", "谛当归宿处，是灵根。", "至真至道，简易合乾坤。", "坎离并水火，止是筌蹄，粹然一点长存。", "个中如荐得，悟了五千言。", "金晶飞肘后，透昆仑。", "清江九曲，一棹破烟昏。", "水击三千里，九万鹏程，化成元是冥鲲。"]'),
('song-ci-532','沁园春','衣白山人','宋','宋词','song-ci','沁园春','[]','一粒金丹，大如黍米，定中降胎。',140,'宋词/ci.song.3000.json','["一粒金丹，大如黍米，定中降胎。", "运阴阳根本，东龙西虎，结凝金水，择地深栽。", "九载无亏，三田功满，卦气周圆炉鼎开。", "偷元化，用自然宗祖，全在灵台。", "真才。", "休恋尘埃。", "况颖悟明堂婴未孩。", "幸淮滨相遇，灵丹付了，亲留玄旨，期进仙阶。", "此去何时，水云高会，更上烟霞岐路哉。", "人间世，任王侯贵显，同委蒿莱。"]'),
('song-ci-533','失调名','吕岩','宋','宋词','song-ci','失调名','["\u5cb3\u9633\u697c"]','鼎里坎离，壶中天地，满怀风月，一吸虚空。',95,'宋词/ci.song.3000.json','["鼎里坎离，壶中天地，满怀风月，一吸虚空。", "尘寰里，何人识我，开口问鸿濛。", "云中。", "三弄笛，岳阳楼外，天远霞红。", "笑骑黄鹤，暂过海陵东。", "拂袖呵呵归去，銮和玉珮，风响乔松。", "君若要，知吾踪迹，试与问仙翁。"]'),
('song-ci-534','西江月','吕岩','宋','宋词','song-ci','西江月','[]','葆炼中分相火，行持外借方鞋。',58,'宋词/ci.song.3000.json','["葆炼中分相火，行持外借方鞋。", "清虚爽彻御□□。", "□□□□□□。", "□□□□□□，□□灵宝为胎。", "十分无极至真来。", "恍惚芝骈羽盖。"]'),
('song-ci-535','西江月','吕岩','宋','宋词','song-ci','西江月','[]','一日清欢何往，十年旧事重拈。',58,'宋词/ci.song.3000.json','["一日清欢何往，十年旧事重拈。", "细风斜日到江南。", "春满平湖潋滟。", "黄简手题龙篆，绿舆前控鸾骖。", "玉清真軿署仙衔。", "列职灵台书监。"]'),
('song-ci-536','霜天晓角','吕岩','宋','宋词','song-ci','霜天晓角','[]','乾坤未裂。',54,'宋词/ci.song.3000.json','["乾坤未裂。", "有物如何别。", "解把鸿濛擘破，说不知、知不说。", "妙诀。", "真难彻。", "知音世所绝。", "要识阴阳颠倒，月中日、日中月。"]'),
('song-ci-537','贺新郎','熊禾','宋','宋词','song-ci','贺新郎','[]','旧事凭谁诉。',142,'宋词/ci.song.3000.json','["旧事凭谁诉。", "记锦宫、初试浓妆，前身天女。", "玉辇行春娇侍夜，浴殿温泉轻注。", "一点点、猩红啼吐。", "绣屋篝香春睡足，细温存，怕遣惊风雨。", "春孟散，暗凝伫。", "韶华寂寞今何许。", "想故宫、柳亦凝愁，倚栏停舞。", "欲趁啼鹃归月下，可奈川回山阻。", "倩万里、鹄来衔子。", "工部无诗虽结恨，道无香、更恨痴人语。", "拌绝艳，付黄土。"]'),
('song-ci-538','临江仙','李之仪','宋','宋词','song-ci','临江仙','[]','清润奇峰名韫玉，温其质并琼瑶。',70,'宋词/ci.song.3000.json','["清润奇峰名韫玉，温其质并琼瑶。", "中分瀑布写云涛。", "双峦呈翠色，气象两相高。", "珍重幽人诚好事，绿窗聊助风骚。", "寄言俗客莫相嘲。", "物轻人意重，千里赠鹅毛。"]'),
('song-ci-539','点绛唇','李之仪','宋','宋词','song-ci','点绛唇','[]','匀妆了。',15,'宋词/ci.song.3000.json','["匀妆了。", "背人微笑。", "风入玲珑罩。"]'),
('song-ci-540','水调歌头','叶梦得','宋','宋词','song-ci','水调歌头','[]','何处难忘酒，朱夏日偏长。',122,'宋词/ci.song.3000.json','["何处难忘酒，朱夏日偏长。", "湖山地胜潇湘，十里芰荷香。", "柳外新蝉惊晚，楼上疏帘垂翠，簟枕晚生凉。", "纨扇摇霜月，曲水泛流觞。", "流年去，今古梦，几千场。", "虚名浮利，输却几许好时光。", "幸有碧云深处，存取朱颜绿鬓，流落又何妨。", "莫厌人世间，频入醉中乡。", "蔺卿全璧我蹉跎。"]'),
('song-ci-541','失调名','黄庭坚','宋','宋词','song-ci','失调名','[]','屋角数声鸦噪柳。',8,'宋词/ci.song.3000.json','["屋角数声鸦噪柳。"]'),
('song-ci-542','失调名','黄庭坚','宋','宋词','song-ci','失调名','[]','旧家杨柳依依绿，长锁春来庭院。',15,'宋词/ci.song.3000.json','["旧家杨柳依依绿，长锁春来庭院。"]'),
('song-ci-543','菩萨蛮','黄庭坚','宋','宋词','song-ci','菩萨蛮','[]','轻风袅断沈烟炷。',52,'宋词/ci.song.3000.json','["轻风袅断沈烟炷。", "霏微尽日寒塘雨。", "残绣没心情。", "鸟啼花外声。", "离愁难自制。", "年少乖盟誓。", "寂寞掩朱门。", "罗衣空泪痕。"]'),
('song-ci-544','渔家傲','黄庭坚','宋','宋词','song-ci','渔家傲','[]','荡漾生涯身已老。',72,'宋词/ci.song.3000.json','["荡漾生涯身已老。", "短蓑箬笠扁舟小。", "深入水云人不到。", "吟复笑。", "一轮明月长相照。", "谁谓阿师来问道。", "一桡直与传心要。", "船子踏翻才是了。", "波渺渺。", "长鲸万古无人钓。"]'),
('song-ci-545','南乡子','黄叔达','宋','宋词','song-ci','南乡子','[]','落帽晚风回。',66,'宋词/ci.song.3000.json','["落帽晚风回。", "又报黄花一番开。", "扶杖老人心未老，堪咍。", "漫有才情付与谁。", "芳意正徘徊。", "传与西风且慢吹。", "明日馀尊还共倒，重来。", "未必秋香一夜衰。"]'),
('song-ci-546','惜花容','盼盼','宋','宋词','song-ci','惜花容','[]','少年看花双鬓绿。',64,'宋词/ci.song.3000.json','["少年看花双鬓绿。", "走马章台管弦逐。", "而今老更惜花深，终日看花看不足。", "坐中美女颜如玉。", "为我一歌金缕曲。", "归时压得帽檐敧，头上春风红蔌蔌。"]'),
('song-ci-547','绿头鸭・多丽','晁端礼','宋','宋词','song-ci','绿头鸭・多丽','[]','锦堂深，兽炉轻喷沈烟。',173,'宋词/ci.song.3000.json','["锦堂深，兽炉轻喷沈烟。", "紫檀槽、金泥花面，美人斜抱当筵。", "挂罗绶、素肌莹玉，近鸾翅、云鬓梳蝉。", "玉笋轻拢，龙香细抹，凤凰飞出四条弦。", "碎牙板、烦襟消尽，秋气满庭轩。", "今宵月，依稀向人，欲斗婵娟。", "变新声、能翻往事，眼前风景依然。", "路漫漫、汉妃出塞，夜悄悄、商妇移船。", "马上愁思，江边怨感，分明都向曲中传。", "困无力、劝人金盏，须要倒垂莲。", "拼沈醉，身世恍然，一梦游仙。"]'),
('song-ci-548','绿头鸭・多丽','晁端礼','宋','宋词','song-ci','绿头鸭・多丽','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','晚云收，淡天一片琉璃。',173,'宋词/ci.song.3000.json','["晚云收，淡天一片琉璃。", "烂银盘、来从海底，皓色千里澄辉。", "莹无尘、素娥淡伫，静可数、丹桂参差。", "玉露初零，金风未凛，一年无似此佳时。", "露坐久，疏莹时度，乌鹊正南飞。", "瑶台冷，栏干凭暖，玉下迟迟。", "念佳人，音尘别后，对此应解相思。", "最关情、漏声正永，暗断肠、花影偷移。", "料得来宵，清光未减，阴晴天气又争知。", "共凝恋、如今别后，还是隔年期。", "人强健，清尊素影，长愿相随。"]'),
('song-ci-549','望海潮','晁端礼','宋','宋词','song-ci','望海潮','[]','高阳方面，河间都会，三关地最称雄。',129,'宋词/ci.song.3000.json','["高阳方面，河间都会，三关地最称雄。", "粉堞万层，金城百雉，楼横一带长虹。", "烟素敛晴空。", "正望迷平野，目断飞鸿。", "易水风烟，范阳山色有无中。", "安边暂倚元戎。", "看纶巾对酒，羽扇摇风。", "金勒少年，吴钩壮士，宁论卫霍前功。", "乃眷在清衷。", "恐凤池虚久，归去匆匆。", "幸有佳人锦瑟，玉笋且轻拢。"]'),
('song-ci-550','水龙吟','晁端礼','宋','宋词','song-ci','水龙吟','[]','夜来深雪前村路，应是早梅初绽。',126,'宋词/ci.song.3000.json','["夜来深雪前村路，应是早梅初绽。", "故人赠我，江头春信，南枝向暖。", "疏影横斜，暗香浮动，月明溪浅。", "向亭边驿畔，行人立马，频回首、空肠断。", "别有玉溪仙馆。", "寿阳人、初匀妆面。", "天教占了，百花头上，和羹未晚。", "最是关情处，高楼上、一声羌管。", "仗谁人向道，何如留取，倚朱栏看。"]'),
('song-ci-551','水龙吟','晁端礼','宋','宋词','song-ci','水龙吟','[]','岭梅香雪飘零尽，繁杏枝头犹未。',126,'宋词/ci.song.3000.json','["岭梅香雪飘零尽，繁杏枝头犹未。", "小桃一种，妖娆偏占，春工用意。", "微喷丹砂，半含朝露，粉墙低倚。", "似谁家丱女，娇痴怨别，空凝睇、东风里。", "好是佳人半醉。", "近横波、一枝争媚。", "元都观里，武陵溪上，空随流水。", "惆怅如红雨，风不定、五更天气。", "念当年门里，如今陌上，洒离人泪。"]'),
('song-ci-552','水龙吟','晁端礼','宋','宋词','song-ci','水龙吟','[]','小桃零落春将半。',126,'宋词/ci.song.3000.json','["小桃零落春将半。", "双燕却来池馆。", "名园相倚，初开繁杏，一枝遥见。", "竹外斜穿，柳间深映，粉愁香怨。", "任红敧宋玉，墙头千里，曾牵惹、人肠断。", "常记山城斜路，喷清香、日迟风暖。", "春阴挫后，马前惆怅，满枝红浅。", "深院帘垂雨，愁人处、碎红千片。", "料明年更发，多应更好，约邻翁看。"]'),
('song-ci-553','水龙吟','晁端礼','宋','宋词','song-ci','水龙吟','[]','倦游京洛风尘，夜来病酒无人问。',126,'宋词/ci.song.3000.json','["倦游京洛风尘，夜来病酒无人问。", "九衢雪小，千门月淡，元宵灯近。", "香散眉梢，冻消池面，一番春信。", "记南楼醉里，西城宴阙，都不管、人春困。", "屈指流年未几，早人惊、潘郎双鬓。", "当时体态，如今情绪，多应瘦损。", "马上墙头，纵教瞥见，也难相认。", "凭栏干，但有盈盈泪眼，把罗襟搵。"]'),
('song-ci-554','上林春・一落萦','晁端礼','宋','宋词','song-ci','上林春・一落萦','[]','霖雨成功，堂称继美，旧说安阳家世。',126,'宋词/ci.song.3000.json','["霖雨成功，堂称继美，旧说安阳家世。", "峻岳降神，长庚应梦，佳辰况当秋霁。", "玉函金篆，帝锡与、寿眉齯齿。", "向清时、便告老，尽取貂蝉轻弃。", "把朝庭旧勋屈指。", "有谁人似此，能全终始。", "谤书顿释，先芬未泯，君王自为知己。", "看花临水。", "算已号、醉吟居士。", "奈苍生，尚满望、谢公重起。"]'),
('song-ci-555','上林春・一落萦','晁端礼','宋','宋词','song-ci','上林春・一落萦','[]','伊洛清波，嵩山秀色，共与皇家为瑞。',126,'宋词/ci.song.3000.json','["伊洛清波，嵩山秀色，共与皇家为瑞。", "挺生异质，亲逢盛旦，簪缨旧传家世。", "雁炉烟里，罩一段、照人清气。", "灿金章、映紫绶，自是真官标致。", "把朝廷缙绅屈指。", "有谁人似得，多才多艺。", "片言悟主，封侯赐璧，君王自为知己。", "暂来卧治。", "况廊庙、正多虚位。", "看登庸，辅圣主、万年康济。"]'),
('song-ci-556','满庭芳','晁端礼','宋','宋词','song-ci','满庭芳','[]','天与疏慵，人怜憔悴，分甘抛弃簪缨。',118,'宋词/ci.song.3000.json','["天与疏慵，人怜憔悴，分甘抛弃簪缨。", "有时乘兴，波上叶舟轻。", "十里横塘过雨，荷香细、苹末风清。", "真如画，残霞淡日，偏向柳梢明。", "凝情。", "尘网外，鲈鱼旋鲙。", "芳酒深倾。", "又算来、何须身后浮名。", "无限沧浪好景，蓑笠下、且遣馀生。", "长歌去，机心尽矣，鸥鹭莫相惊。"]'),
('song-ci-557','满庭芳','晁端礼','宋','宋词','song-ci','满庭芳','[]','绿绕群峰，红摇千柄，夜来暑雨初收。',118,'宋词/ci.song.3000.json','["绿绕群峰，红摇千柄，夜来暑雨初收。", "共君乘兴，轻舸信悠悠。", "且尽一尊别酒，荷香里、满酌轻讴。", "明朝去，征帆夜落，何处好汀洲。", "风流。", "吾小阮，朝辞东观，夕向南州。", "况圣时、争教贾傅淹留。", "若过寻阳亭上，琵琶泪、莫洒清秋。", "堤边柳，从今爱惜，留待系归舟。"]'),
('song-ci-558','满庭芳','晁端礼','宋','宋词','song-ci','满庭芳','[]','北渚澄兰，南山凝翠，望中浑似仙乡。',118,'宋词/ci.song.3000.json','["北渚澄兰，南山凝翠，望中浑似仙乡。", "万家烟霭，朱户锁垂杨。", "好是飞泉漱玉，回环遍、小曲深坊。", "西风里，芙蕖带雨，飘散满城香。", "微凉。", "湖上好，桥虹倒影，月练飞光。", "命玳簪促席，云鬓分行。", "谁似风流太守，端解道、春草池塘。", "须留恋，神京纵好，此地也难忘。"]'),
('song-ci-559','满庭芳','晁端礼','宋','宋词','song-ci','满庭芳','["\u897f\u6e56"]','雪满貂裘，风摇金辔，笑看锦带吴钩。',118,'宋词/ci.song.3000.json','["雪满貂裘，风摇金辔，笑看锦带吴钩。", "照人清鬓，年少定封侯。", "此去马啼何处，山万叠、济水南州。", "君知否，卢郎未老，曾是恣狂游。", "风流。", "佳丽地，十年屈指，一梦回头。", "最难忘，西湖北渚澄秋。", "玉砌雕栏好在，桃共李、能忆人不。", "衰翁也，多情为我，将恨寄红楼。"]'),
('song-ci-560','满庭芳','晁端礼','宋','宋词','song-ci','满庭芳','[]','浅约鸦黄，轻匀螺黛，故教取次梳妆。',120,'宋词/ci.song.3000.json','["浅约鸦黄，轻匀螺黛，故教取次梳妆。", "减轻琶面，新样小鸾凰。", "每为花娇玉嫩，容对客、斜倚银床。", "春来病，兰薰半歇，一管舞衣裳。", "悲凉。", "人事改，三春秾艳，一夜繁霜。", "似人归洛浦，云散高唐。", "痛念你、平生分际，辜负我、临老风光。", "罗裙在，凭谁为我，求取返魂香。"]'),
('song-ci-561','雨中花・夜行船','晁端礼','宋','宋词','song-ci','雨中花・夜行船','[]','倦贰文昌，乐请左符，双旌去指东藩。',119,'宋词/ci.song.3000.json','["倦贰文昌，乐请左符，双旌去指东藩。", "有腰金新宠，昼锦荣观。", "独步文章，家传素业，世宝青毡。", "动欢声和气，里巷初惊，侍从衣冠。", "朱门映柳，绮窗临水，盛游应记当年。", "端解道、香留罗袜，墨在蛮笺。", "惆怅江边侧帽，寻似花底遗鞭。", "不如沈醉，莫思身外，且斗樽前。"]'),
('song-ci-562','雨中花・夜行船','晁端礼','宋','宋词','song-ci','雨中花・夜行船','[]','豆蔻梢头，鸳鸯帐里，扬州一梦初惊。',118,'宋词/ci.song.3000.json','["豆蔻梢头，鸳鸯帐里，扬州一梦初惊。", "忆当时相见，双眼偏明。", "南浦绿波，西城杨柳，痛悔多情。", "望征鞍不见，况是并州，自古高城。", "几多映月凭肩私语，傍花和泪深盟。", "争信道、三年虚负，一事无成。", "瑶珮空传好好，秦筝闻说琼琼。", "此心在了，半边明镜，终遇今生。"]'),
('song-ci-563','雨中花・夜行船','晁端礼','宋','宋词','song-ci','雨中花・夜行船','[]','流水知音，轻裘共敝，相逢才换星霜。',119,'宋词/ci.song.3000.json','["流水知音，轻裘共敝，相逢才换星霜。", "多少风亭棋酒，画阁丝簧。", "纤指声犹馀响，红粉泪已成行。", "怅绿波浦上，芳草堤边，又整归航。", "新移槛竹，手种庭花，未容烂熳飞觞。", "归去也、重趋丹禁，密侍清光。", "醉帽斜萦御柳，朝衣浓惹天香。", "帝城春好，多应不念，水郭渔乡。"]'),
('song-ci-564','玉楼宴','晁端礼','宋','宋词','song-ci','玉楼宴','[]','记红颜日、向瑶阶，得俊饮、散蓬壶。',127,'宋词/ci.song.3000.json','["记红颜日、向瑶阶，得俊饮、散蓬壶。", "绣鞍纵骄马，故坠鞭柳径，缓辔花衢。", "斗帐兰釭曲，曾是振、声名上都。", "醉倒旗亭，更深未归，笑倩人扶。", "光阴到今二纪，算难寻前好，懒访仙居。", "近来似闻道，向雾关云洞，自乐清虚。", "月帔与星冠，不念我、华鬚皓鬓。", "纵教重有相逢，似得旧时无。"]'),
('song-ci-565','醉蓬莱','晁端礼','宋','宋词','song-ci','醉蓬莱','[]','正中秋初过，淡碧云容，嫩凉天气。',120,'宋词/ci.song.3000.json','["正中秋初过，淡碧云容，嫩凉天气。", "紫府真仙，暂谪居尘世。", "慕道高情，照人清骨，是寿星标致。", "德在民心，勋藏帝室，清芬相继。", "庭有芝兰，世调鼎鼐，晋美乌衣，汉称韦氏。", "未必当时，解功成身退。", "天下苍生，未知此意，望谢公重起。", "善颂阴资，何须更觅，西山灵剂。"]'),
('song-ci-566','醉蓬莱','晁端礼','宋','宋词','song-ci','醉蓬莱','[]','看梅梢初动，池面冰澌，小春时候。',120,'宋词/ci.song.3000.json','["看梅梢初动，池面冰澌，小春时候。", "当日生贤，庆黄家忠厚。", "龙种殊常，照人眉宇，似汝阳端秀。", "世取贤科，胪传圣语，增光华胃。", "天汉灵源，最为亲近，茅土真封，旧相传授。", "开府新恩，拜除书非久。", "鸣佩拖绅，曳香摇翠，向画堂称寿。", "物外光阴，樽前笑语，年年依旧。"]'),
('song-ci-567','醉蓬莱','晁端礼','宋','宋词','song-ci','醉蓬莱','[]','乍酒醒孤馆，梦断幽窗，嫩凉天气。',120,'宋词/ci.song.3000.json','["乍酒醒孤馆，梦断幽窗，嫩凉天气。", "潇洒情怀，想乡关迢递。", "一枕清风，半帘残月，是闷人滋味。", "南浦离多，东阳带缓，新来憔悴。", "因念当时，乱花深径，画楫环溪，屡陪欢醉。", "踪迹飘流，顿相望千里。", "水远山高，雁沈鱼阻，奈信音难寄。", "吟社阑珊，酒徒零落，重寻无计。"]'),
('song-ci-568','金人捧露盘','晁端礼','宋','宋词','song-ci','金人捧露盘','[]','天锡禹圭尧瑞，君王受厘，未央宫殿。',168,'宋词/ci.song.3000.json','["天锡禹圭尧瑞，君王受厘，未央宫殿。", "三五庆元宵，扫春寒、花外蕙风轻扇。", "龙阙前瞻，凤楼背耸，中有鳌峰见。", "渐紫宙、星河晚。", "放桂华浮动，金莲开遍。", "御帘卷。", "须臾万乐喧天，群仙扶辇。", "云间，都人望天表，正仙葩竞插，异香飘散。", "春宵苦长短。", "指花阴，愁听漏传银箭。", "京国繁华，太平盛事，野老何因见。", "但时效华封祝，愿岁岁闻道，金舆游宴。", "暗魂断。", "天涯望极长安远。"]'),
('song-ci-569','玉女摇仙佩','晁端礼','宋','宋词','song-ci','玉女摇仙佩','[]','宫梅弄粉，御柳摇金，又喜皇州春早。',170,'宋词/ci.song.3000.json','["宫梅弄粉，御柳摇金，又喜皇州春早。", "盛世生贤，真仙应运，当日来从三岛。", "车马喧青晓。", "看千锺赐饮，中人传诏。", "最好是、芝兰并砌，鸣佩腰金，彩衣相照。", "炉烟袅。", "高堂半卷珠帘，神仙飘缈。", "须信槐庭荫美，凤沼波澄，屈指十年三到。", "九叙重歌，元圭再锡，已把成功来告。", "四海瞻仪表。", "庆君臣会集，诗符天保。", "况自有、仙风道骨，玉函金篆，阴功须报。", "方知道。", "八千岁月椿难老。"]'),
('song-ci-570','蓦山溪','晁端礼','宋','宋词','song-ci','蓦山溪','[]','轻衫短帽，重入长安道。',102,'宋词/ci.song.3000.json','["轻衫短帽，重入长安道。", "屈指十年中，一回来、一回渐老。", "朋游在否，落托更能无，朱弦悄。", "知音少。", "拨断相思调。", "花边柳外，潇洒愁重到。", "深院锁春风，悄无人、桃花自笑。", "金钗一股，拟欲问音尘，天杳杳。", "波渺渺。", "何处寻蓬岛。"]'),
('song-ci-571','蓦山溪','晁端礼','宋','宋词','song-ci','蓦山溪','[]','栏干十二，倚遍还重倚。',102,'宋词/ci.song.3000.json','["栏干十二，倚遍还重倚。", "一曲一般愁，对芳草、伤春千里。", "绮窗深处，还解忆人无，碧云辞，红叶字。", "曾仗东风寄。", "缭墙深院，无路通深意。", "纵使得新声，又争知、相如名字。", "从来风韵，潇洒不禁愁，拈梨花，看菊蕊。", "应也成憔悴。"]'),
('song-ci-572','蓦山溪','晁端礼','宋','宋词','song-ci','蓦山溪','[]','广寒宫殿，千里同云晓。',102,'宋词/ci.song.3000.json','["广寒宫殿，千里同云晓。", "飞雪满空来，翦云英、群仙齐到。", "乱飘僧舍，密处洒歌楼，闲日少。", "风光好。", "且共宾朋笑。", "华堂深处，满满觥船掉。", "梅蕊拆来看，已偷得、春风些小。", "绮罗香暖，不怕卷珠帘，沈醉了。", "樽前倒。", "红袖休来叫。"]'),
('song-ci-573','蓦山溪','晁端礼','宋','宋词','song-ci','蓦山溪','[]','春来心事，分付千锺酒。',102,'宋词/ci.song.3000.json','["春来心事，分付千锺酒。", "午醉梦还醒，两眉愁、才消又有。", "天涯远梦，归路日中迷，楚云深，孤馆静，潇洒梨花手。", "回文歌罢，幽恨新兼旧。", "帘影卷斜阳，乱红飞、风摇暮柳。", "独携此意，和泪上层楼，尽平芜，穷远目，认断千山首。"]'),
('song-ci-574','喜迁莺','晁端礼','宋','宋词','song-ci','喜迁莺','[]','嫩柳初摇翠。',128,'宋词/ci.song.3000.json','["嫩柳初摇翠。", "怪朝来早有，飞花零坠。", "洞门斜开，珠帘初卷，惊起谢娘吟缀。", "蕊珠宫殿晓，谁乱把、云英揉碎。", "气候晚，被寒风卷渡，龙沙千里。", "沈醉。", "深院里。", "粉面照人，疑是瑶池会。", "润拂炉烟，寒欺酒力，低压管弦声沸。", "艳阳过半也，应是好、郊原新霁。", "待更与上层楼，遍倚栏干十二。"]'),
('song-ci-575','喜迁莺','晁端礼','宋','宋词','song-ci','喜迁莺','[]','伫立蘅皋暮，冻云乍敛，霜飙微列。',128,'宋词/ci.song.3000.json','["伫立蘅皋暮，冻云乍敛，霜飙微列。", "怅饮杯深，阳关声苦，愁见画船催发。", "夜来红泪烛，还解惜、王孙轻别。", "怅望处，乍金丝冷落，兰薰销歇。", "闻说。", "归兴切。", "华鬓未生，得意浓时节。", "画楫门开，斑衣追逐，晓日凤凰双阙。", "帝城春信早，随处有、江梅攀折。", "烂熳赏，也多应忘了，东堂风月。"]'),
('song-ci-576','喜迁莺','晁端礼','宋','宋词','song-ci','喜迁莺','[]','清和时序。',126,'宋词/ci.song.3000.json','["清和时序。", "望桂影渐生，薰风微度。", "挺秀金芝，传芳玉叶，天上瑞麟重睹，竞爽谢庭兰玉，信美西壅鸳鸯。", "庆门里，把丹枝争折，青云平步。", "声誉。", "喧盛世，人咏少年，古锦囊中句。", "艺祖诸孙，宗王贤子，偏爱汝阳眉宇。", "画堂令辰称寿，愿与冈陵同固。", "更看取，继汧公勋业，东平茅土。"]'),
('song-ci-577','沁园春','晁端礼','宋','宋词','song-ci','沁园春','[]','络纬催凉，断虹收雨，庭梧报秋。',140,'宋词/ci.song.3000.json','["络纬催凉，断虹收雨，庭梧报秋。", "绕郡城、千顷烟波绿，正鱼肥酒美，名冠东州。", "芰荷风细，蒹葭烟淡，宛在潇湘南岸头。", "凝望处，似桃源洞口，初泛兰舟。", "贤侯。", "酝藉风流。", "向庭讼闲时多宴游。", "有信陵家世，梁园客右，才华高掩，沈谢何刘。", "政声朝奏，除书夕至，即看归趋丹凤楼。", "须眷恋，况新堂莹澈，好共迟留。"]'),
('song-ci-578','水调歌头','晁端礼','宋','宋词','song-ci','水调歌头','[]','忆昔红颜日，金玉等泥沙。',114,'宋词/ci.song.3000.json','["忆昔红颜日，金玉等泥沙。", "青楼紫陌，惟解惜月与贪花。", "谁信如今憔悴，尘暗金徽玉轸，藓污匣中蛇。", "一事都无就，双鬓只堪嗟。", "恨无情，乌与兔，送年华。", "不如归去，无限云水好生涯。", "未用轻蓑短棹，犹有青鞋黄帽，行处即吾家。", "回首人间世，幽意在青霞。"]'),
('song-ci-579','金盏倒垂莲','晁端礼','宋','宋词','song-ci','金盏倒垂莲','[]','流水漂花，记同寻阆苑，曾宴桃源。',112,'宋词/ci.song.3000.json','["流水漂花，记同寻阆苑，曾宴桃源。", "痛饮狂歌，金盏倒垂莲。", "未省负、佳时良夜，烂游风月三年。", "别后空报瑶琴，谁听朱弦。", "风流少年儒将，有威名震虏，谈笑安边。", "寄我新诗，何事赋归田。", "想歌酒、情怀如旧，后房应也依然。", "此外莫问升沈，且斗樽前。"]'),
('song-ci-580','百宝装・新燕过妆楼','晁端礼','宋','宋词','song-ci','百宝装・新燕过妆楼','[]','枫叶初丹，苹花渐老，蘅皋谁系扁舟。',126,'宋词/ci.song.3000.json','["枫叶初丹，苹花渐老，蘅皋谁系扁舟。", "故人思我，征棹少淹留。", "一尊潋滟西风里，共醉倒、同销万古愁。", "况今宵自有，明月照人，逼近中秋。", "常爱短李家声，金闺彦士，才高沈谢何刘。", "片帆初卷，歌吹是扬州。", "此心自难拘形役，恨未能、相从烂熳游。", "酒醒时，路遥人远，为我频上高楼。"]'),
('song-ci-581','玉胡蝶・玉蝴蝶','晁端礼','宋','宋词','song-ci','玉胡蝶・玉蝴蝶','[]','淡淡春阳天气，夜来一霎，微雨初晴。',124,'宋词/ci.song.3000.json','["淡淡春阳天气，夜来一霎，微雨初晴。", "向暖犹寒，时候又是清明。", "乱沾衣、桃花雨闹，微弄袖、杨柳风轻。", "晓莺声。", "唤回幽梦，犹困春酲。", "牵萦。", "伤春怀抱，东郊烟暖，南浦波平。", "况有良朋，载酒同放彩舟行。", "劝人归、啼禽有意，催棹去、烟水无情。", "黯销凝。", "暮云回首，何处高城。"]'),
('song-ci-582','木兰花・玉楼春','晁端礼','宋','宋词','song-ci','木兰花・玉楼春','[]','苦春宵漏短，梦回晚、酒醒迟。',126,'宋词/ci.song.3000.json','["苦春宵漏短，梦回晚、酒醒迟。", "正小雨初收，馀寒未放，怯试单衣。", "娇痴。", "最尤殢处，被罗襟、印了宿妆眉。", "潇洒春工斗巧，算来不在花枝。", "芳菲。", "正好踏春，携素手、暂分飞。", "料恨月愁花，多应瘦损，风柳腰肢。", "归期。", "况春未老，过南园、尚及牡丹时。", "拼却栏边醉倒，共伊插满头归。"]'),
('song-ci-583','金盏子','晁端礼','宋','宋词','song-ci','金盏子','[]','断魂凝睇。',123,'宋词/ci.song.3000.json','["断魂凝睇。", "望故国迢迢，倦摇征辔。", "恨满西风，有千里云山，万重烟水。", "遥夜枕冷衾寒，数更筹无寐。", "想伊家、应也背著孤灯，暗弹珠泪。", "屈指。", "重算归期，知他是何时见去里。", "翻思绣阁旧时，无一事，只管爱争闲气。", "及至恁地单栖，却千般追悔。", "从今后，彼此记取，厌厌况味。"]'),
('song-ci-584','洞仙歌','晁端礼','宋','宋词','song-ci','洞仙歌','[]','年时此际，向扁舟同载。',103,'宋词/ci.song.3000.json','["年时此际，向扁舟同载。", "风送征帆暮天外。", "对沙汀宿鹭，与波上轻鸥，双双处，相唤相呼自在。", "如今重整棹，烟景依然，谁念轻分绣罗带。", "向蓬窗独坐，不觉徊徨，鸥与鹭、想一齐惊怪。", "怎生得、今宵梦还家，又譬如秉烛，夜阑相对。"]'),
('song-ci-585','安公子','晁端礼','宋','宋词','song-ci','安公子','[]','帝里重阳好。',125,'宋词/ci.song.3000.json','["帝里重阳好。", "又对短发来吹帽。", "满目风光还似旧，奈樽前人老。", "暗忆当年，伴侣同倾倒。", "夸俊游、争买千金笑。", "到如今憔悴，恰似华胥一觉。", "此恨何时了。", "旧游屈指愁重到。", "小曲深坊闲信马，掩朱扉悄悄。", "怎得个多情，为我传音耗。", "但向伊、耳边轻轻道。", "道近来应是，望了卢郎年少。"]'),
('song-ci-586','庆寿光','晁端礼','宋','宋词','song-ci','庆寿光','[]','丹扆疏恩，庆闱受命，圣朝广孝非常。',123,'宋词/ci.song.3000.json','["丹扆疏恩，庆闱受命，圣朝广孝非常。", "大邑高封，名兼寿考辉光。", "闾巷相传盛事，焕丝五色成章。", "崇新栋，天语荣夸，共瞻积善华堂。", "灵龟荐祉，紫鸾称寿，千锺泛酒，百和焚香。", "况有新教歌舞，妙选丝篁。", "馀庆从今沓至，看儿孙、朱紫成行。", "闻说道，贤得阴功，姓名仍在仙乡。"]'),
('song-ci-587','黄鹂绕碧树','晁端礼','宋','宋词','song-ci','黄鹂绕碧树','[]','鸳瓦霜轻，玳帘风细，高门瑞气非烟。',122,'宋词/ci.song.3000.json','["鸳瓦霜轻，玳帘风细，高门瑞气非烟。", "积厚源深，有长庚应梦，乔岳生贤。", "妙龄秀发，庆谢庭、兰玉争妍。", "名动缙绅，况文章政术，俱是家传。", "别有阴功厚德，向东州、治狱平反。", "玉函高篆，仙风道骨，锡与长年。", "最好素秋新霁，对画堂、高启宾筵。", "何妨纵乐笙歌，剩举觥船。"]'),
('song-ci-588','永遇乐','晁端礼','宋','宋词','song-ci','永遇乐','[]','龙阁先芬，凤毛荣继，当世英妙。',125,'宋词/ci.song.3000.json','["龙阁先芬，凤毛荣继，当世英妙。", "峻岳储灵，长庚应梦，还庆佳辰到。", "黄花浥露，碧瓦凝霜，香馥郡齐清晓。", "忆当年、青云平步，共喜骤跻华要。", "阴功厚德，玉符金篆，锡与世间难老。", "注意方浓，分符屡请，雅志人应少。", "棠阴无讼，乐府新教，正醉山频倒。", "有谁莱衣游戏，萱堂寿考。"]'),
('song-ci-589','满江红','晁端礼','宋','宋词','song-ci','满江红','[]','五两风轻，移舟向、斜阳岛外。',115,'宋词/ci.song.3000.json','["五两风轻，移舟向、斜阳岛外。", "最好是、潇湘烟景，自然心会。", "倒影芙蓉明镜底，更折花嗅西风里。", "待问君、明日向何州，东南指。", "人生事，谁如意。", "剩拼取，尊前醉。", "想升沈有命，去来非己。", "菊老松深三径在，田园已有归来计。", "问甚时、重此望归舟，远相对。"]'),
('song-ci-590','春晴','晁端礼','宋','宋词','song-ci','春晴','[]','燕子来时，清明过了，桃花乱飘红雨。',105,'宋词/ci.song.3000.json','["燕子来时，清明过了，桃花乱飘红雨。", "倦客凄凉，千里云山将暮。", "泪眸回望，人在玉楼深处。", "向此多应念远，凭栏无语。", "芳菲可惜轻负。", "空鞭弄游丝，帽冲飞絮。", "恨满东风，谁识此时情绪。", "数声啼鸟，劝我不如归去。", "纵写香笺，仗谁寄与。"]'),
('song-ci-591','河满子','晁端礼','宋','宋词','song-ci','河满子','[]','满浦亭前杨柳，一年两度攀条。',86,'宋词/ci.song.3000.json','["满浦亭前杨柳，一年两度攀条。", "瞬息光阴都几许，离情常是迢迢。", "须信沈腰易瘦，争教潘鬓相饶。", "不忍重寻香径，还来独立溪桥。", "唯有无情东去水，来时曾傍兰桡。", "今夜欲求好梦，望中莫遣魂销。"]'),
('song-ci-592','醉桃源・阮郎归','晁端礼','宋','宋词','song-ci','醉桃源・阮郎归','[]','又是青春将暮。',40,'宋词/ci.song.3000.json','["又是青春将暮。", "望极桃溪归路。", "洞户悄无人，空锁一庭红雨。", "凝伫。", "凝伫。", "人面不知何处。"]'),
('song-ci-593','一丛花','晁端礼','宋','宋词','song-ci','一丛花','[]','谪仙海上驾鲸鱼。',94,'宋词/ci.song.3000.json','["谪仙海上驾鲸鱼。", "谈笑下蓬壶。", "神寒骨重真男子，是我家、千里龙驹。", "经纶器业，文章光焰，流辈更谁如。", "渊明元与世情疏。", "松菊爱吾庐。", "他年定契非熊卜，也未应、鹤发樵渔。", "手栽露桃，亲移云杏，真是种星榆。"]'),
('song-ci-594','感皇恩','晁端礼','宋','宋词','song-ci','感皇恩','[]','蜀锦满林花，三年重到。',81,'宋词/ci.song.3000.json','["蜀锦满林花，三年重到。", "应被花枝笑人老。", "半开微谢，占得几多时好。", "便须拼痛饮、花前倒。", "醉中但记，红围绿绕。", "人面花光斗相照。", "缭墙重院，爱惜遮藏须早。", "免如攀折柳，临官道。"]'),
('song-ci-595','御街行','晁端礼','宋','宋词','song-ci','御街行','[]','柳条弄色梅飘粉。',90,'宋词/ci.song.3000.json','["柳条弄色梅飘粉。", "还是元宵近。", "小楼深巷月胧明，记得恁时风景。", "庭花影转，珠帘人静，依旧厌厌闷。", "如今对酒翻成恨。", "春瘦罗衣褪。", "王孙何处草萋萋，辜负小欢幽兴。", "谁知此际，有人灯下，偷把归期问。"]'),
('song-ci-596','踏莎行','晁端礼','宋','宋词','song-ci','踏莎行','[]','萱草栏干，榴花庭院。',68,'宋词/ci.song.3000.json','["萱草栏干，榴花庭院。", "悄无人语重帘卷。", "屏山掩梦不多时，斜风雨细江南岸。", "昼漏初传，林莺百啭。", "日长暗记残香篆。", "洞房消息有谁知，几回欲问梁间燕。"]'),
('song-ci-597','踏莎行','晁端礼','宋','宋词','song-ci','踏莎行','[]','柳暗重门，花深小院。',68,'宋词/ci.song.3000.json','["柳暗重门，花深小院。", "盆池昨夜新荷卷。", "银床斜倚小屏风，吴波澄淡春山远。", "纨扇风轻，薰炉烟断。", "日高睡起眉山浅。", "尘侵鸾镜懒匀妆，谁人与整钗头燕。"]'),
('song-ci-598','踏莎行','晁端礼','宋','宋词','song-ci','踏莎行','[]','衰柳残荷，长山远水。',68,'宋词/ci.song.3000.json','["衰柳残荷，长山远水。", "扁舟荡漾烟波里。", "离杯莫厌百分斟，船头转便三千里。", "红日初斜，西风渐起。", "琵琶休洒青衫泪。", "区区游宦亦何为，林泉早作归来计。"]'),
('song-ci-599','蝶恋花','晁端礼','宋','宋词','song-ci','蝶恋花','[]','潋滟长波迎鹢首。',70,'宋词/ci.song.3000.json','["潋滟长波迎鹢首。", "雨淡烟轻，过了清明候。", "岸草汀花浑似旧。", "行人只是添清瘦。", "沈水香消罗袂透。", "双橹声中，午梦初惊后。", "枕上懵腾犹病酒。", "卷帘数尽长堤柳。"]'),
('song-ci-600','蝶恋花','晁端礼','宋','宋词','song-ci','蝶恋花','[]','骨秀肌香冰雪莹。',70,'宋词/ci.song.3000.json','["骨秀肌香冰雪莹。", "潇洒风标，赋得温柔性。", "鬆髻遗钿慵不整。", "花时长是厌厌病。", "枕上晓来残酒醒。", "一带屏山，千里江南景。", "指点烟村横小艇。", "何时携手重寻胜。"]'),
('song-ci-601','定风波','晁端礼','宋','宋词','song-ci','定风波','[]','花倚东风柳弄春。',73,'宋词/ci.song.3000.json','["花倚东风柳弄春。", "分明浅笑与轻嚬。", "更忆当时声细细，偎人。", "秦筝轻衬砑罗裙。", "别后此欢谁更共。", "春梦。", "只凭胡蝶伴飞魂。", "独倚高楼还日暮。", "情绪。", "浮烟漠漠雨昏昏。"]'),
('song-ci-602','江城子','晁端礼','宋','宋词','song-ci','江城子','[]','幽香闲艳露华浓。',86,'宋词/ci.song.3000.json','["幽香闲艳露华浓。", "晚妆慵。", "略匀红。", "春困厌厌，常爱鬓云鬆。", "早是自来莲步小，新样子，为谁弓。", "画堂西下小栏东。", "醉醒中。", "苦匆匆。", "卷上珠帘，依旧半床空。", "香灺满炉人未寝，花弄月，竹摇风。"]'),
('song-ci-603','江城子','晁端礼','宋','宋词','song-ci','江城子','[]','石榴双叶忆同寻。',86,'宋词/ci.song.3000.json','["石榴双叶忆同寻。", "卜郎心。", "向谁深。", "长恁娇痴，尤殢怎生禁。", "内样双眉新画得，还印了，在罗襟。", "相思幽怨付鸣琴。", "望来音。", "久沈沈。", "若论当初，谁信有如今。", "瘦尽标容羞见也，明镜子，任尘侵。"]'),
('song-ci-604','临江仙','晁端礼','宋','宋词','song-ci','临江仙','[]','今夜征帆何处落，烟村几点人家。',70,'宋词/ci.song.3000.json','["今夜征帆何处落，烟村几点人家。", "莫惊双泪向风斜。", "渔人西塞曲，商女后庭花。", "从此五湖归去好，一杯酒送生涯。", "多情犹解惜年华。", "春闺重见处，霜鬓不须嗟。"]'),
('song-ci-605','西江月','晁端礼','宋','宋词','song-ci','西江月','[]','去路湘桃破萼，归时乳燕巢梁。',58,'宋词/ci.song.3000.json','["去路湘桃破萼，归时乳燕巢梁。", "不成一事又还乡。", "也是经春游荡。", "香炉重燃鸂鶒，罗衾再拂鸳鸯。", "今宵应解话愁肠。", "指点尘生绣帐。"]'),
('song-ci-606','西江月','晁端礼','宋','宋词','song-ci','西江月','[]','洛浦神仙流品，姑山冰雪肌肤。',58,'宋词/ci.song.3000.json','["洛浦神仙流品，姑山冰雪肌肤。", "谁家池馆雨晴初。", "肠断风标白鹭。", "国艳枉教无语，玉颜不待施朱。", "采菱人散夜蟾孤。", "冷落西溪风露。"]'),
('song-ci-607','诉衷情','晁端礼','宋','宋词','song-ci','诉衷情','[]','红窗小艇雨馀天。',54,'宋词/ci.song.3000.json','["红窗小艇雨馀天。", "李郭未神仙。", "片时篷底幽梦，即是五湖船。", "追往事，惜流年。", "恨风烟。", "向人依旧，两行垂杨，一片新蝉。"]'),
('song-ci-608','诉衷情','晁端礼','宋','宋词','song-ci','诉衷情','[]','吴宫绝艳楚宫腰。',54,'宋词/ci.song.3000.json','["吴宫绝艳楚宫腰。", "怯挂紫檀槽。", "纤纤玉笋轻拈，莺语弄春娇。", "松钿带，亸金翘。", "暗香飘。", "红牙拍碎，绛蜡烧残，月淡天高。"]'),
('song-ci-609','诉衷情','晁端礼','宋','宋词','song-ci','诉衷情','[]','金盆水冷又重煨。',54,'宋词/ci.song.3000.json','["金盆水冷又重煨。", "不肯傍妆台。", "从教髻鬟鬆慢，斜亸卷云钗。", "莲步稳，黛眉开。", "后园回。", "手挼柳带，鬓插梅梢，探得春来。"]'),
('song-ci-610','清平乐','晁端礼','宋','宋词','song-ci','清平乐','[]','朦胧月午。',54,'宋词/ci.song.3000.json','["朦胧月午。", "点滴梨花雨。", "青翼欺人多谩语。", "消息知他真否。", "兽炉鸳被重熏。", "故将灯火挑昏。", "最恨西风摇幕，误人几度迎门。"]'),
('song-ci-611','清平乐','晁端礼','宋','宋词','song-ci','清平乐','[]','深沈玉宇。',54,'宋词/ci.song.3000.json','["深沈玉宇。", "枕簟清无暑。", "睡起花阴初转午。", "一霎飞云过雨。", "雨馀隐隐残雷。", "夕阳却照庭槐。", "莫把绣帘垂下，妨它双燕归来。"]'),
('song-ci-612','清平乐','晁端礼','宋','宋词','song-ci','清平乐','[]','琐窗朱户。',54,'宋词/ci.song.3000.json','["琐窗朱户。", "曾是娇眠处。", "只有馀香留得住。", "满地花钿翠羽。", "三年宋玉东邻。", "断肠月夕烟春。", "看取画屏深处，题诗欲付何人。"]'),
('song-ci-613','清平乐','晁端礼','宋','宋词','song-ci','清平乐','[]','清樽泛菊。',54,'宋词/ci.song.3000.json','["清樽泛菊。", "共剪西窗烛。", "一抹朱弦新按曲。", "更遣歌喉细逐。", "明朝匹马西风。", "黄云衰草重重。", "试问剑歌悲壮，何如玉指轻拢。"]'),
('song-ci-614','浣溪沙','晁端礼','宋','宋词','song-ci','浣溪沙','[]','误入仙家小洞来。',48,'宋词/ci.song.3000.json','["误入仙家小洞来。", "碧桃花落乱浮杯。", "满身罗绮裛香煤。", "醉倒任眠深迳里，醒时须插满头归。", "更收馀蕊酿新醅。"]'),
('song-ci-615','浣溪沙','晁端礼','宋','宋词','song-ci','浣溪沙','[]','紫蔓凝阴绿四垂。',48,'宋词/ci.song.3000.json','["紫蔓凝阴绿四垂。", "暗香撩乱扑罗衣。", "醉眠惟有落花知。", "玉笋纤纤初嗅罢，乌云娜娜乱簪时。", "此般风韵雅相宜。"]'),
('song-ci-616','浣溪沙','晁端礼','宋','宋词','song-ci','浣溪沙','[]','阆苑瑶台指旧居。',48,'宋词/ci.song.3000.json','["阆苑瑶台指旧居。", "当年一念别仙都。", "庆门曾梦得明珠。", "赋畀已教尘累浅，修持更与俗缘疏。", "慧心从此悟真如。"]'),
('song-ci-617','浣溪沙','晁端礼','宋','宋词','song-ci','浣溪沙','[]','似火山榴映翠娥。',48,'宋词/ci.song.3000.json','["似火山榴映翠娥。", "依依香汗浥轻罗。", "恼人无奈是横波。", "金凿落倾欢事少，玉搔头袅闷时多。", "不留人住意如何。"]'),
('song-ci-618','浣溪沙','晁端礼','宋','宋词','song-ci','浣溪沙','[]','一见郎来双眼明。',56,'宋词/ci.song.3000.json','["一见郎来双眼明。", "春风楼上玉箫声。", "谁信同心双结子、苦难成。", "瑶珮空传张好好，钿筝谁继薛琼琼。", "若是今生无此分、有来生。"]'),
('song-ci-619','浣溪沙','晁端礼','宋','宋词','song-ci','浣溪沙','[]','清润风光雨后天。',48,'宋词/ci.song.3000.json','["清润风光雨后天。", "蔷薇花谢绿窗前。", "碧琉璃瓦欲生烟。", "十里闲情凭蝶梦，一春幽怨付鲲弦。", "小楼今夜月重圆。"]'),
('song-ci-620','浣溪沙','晁端礼','宋','宋词','song-ci','浣溪沙','[]','昼漏迟迟出建章。',48,'宋词/ci.song.3000.json','["昼漏迟迟出建章。", "惊回残梦日犹长。", "风微歌吹度昭阳。", "沈水烧残金鸭冷，胭脂匀罢紫绵香。", "一枝花影上东廊。"]'),
('song-ci-621','浣溪沙','晁端礼','宋','宋词','song-ci','浣溪沙','[]','湘簟纱厨午睡醒。',48,'宋词/ci.song.3000.json','["湘簟纱厨午睡醒。", "起来庭院雨初晴。", "夕阳偏向柳梢明。", "懒炷薰炉沈水冷，罢摇纨扇晚凉生。", "莫将闲事恼卿卿。"]'),
('song-ci-622','菩萨蛮','晁端礼','宋','宋词','song-ci','菩萨蛮','[]','薄衾小枕重门闭。',52,'宋词/ci.song.3000.json','["薄衾小枕重门闭。", "孤灯照著人无寐。", "风雨夜来多。", "春寒可奈何。", "深闺香暖处。", "还解怜人否。", "只道不来归。", "那知心似飞。"]'),
('song-ci-623','菩萨蛮','晁端礼','宋','宋词','song-ci','菩萨蛮','[]','午阴未转晴窗暖。',52,'宋词/ci.song.3000.json','["午阴未转晴窗暖。", "无风著地杨花满。", "睡起日犹长。", "卷帘红杏香。", "春心无处定。", "又作花时病。", "芳草伴离愁。", "绵绵早晚休。"]'),
('song-ci-624','菩萨蛮','晁端礼','宋','宋词','song-ci','菩萨蛮','[]','百花未报芳菲信。',52,'宋词/ci.song.3000.json','["百花未报芳菲信。", "一枝探得春风近。", "只有雪争光。", "更无花似香。", "孤标天赋与。", "冷艳谁能顾。", "庭院好深藏。", "莫教开路傍。"]'),
('song-ci-625','菩萨蛮','晁端礼','宋','宋词','song-ci','菩萨蛮','[]','卷帘风入双双燕。',52,'宋词/ci.song.3000.json','["卷帘风入双双燕。", "燕双双入风帘卷。", "明月晓啼莺。", "莺啼晓月明。", "断肠空望远。", "远望空肠断。", "楼上几多愁。", "愁多几上楼。"]'),
('song-ci-626','菩萨蛮','晁端礼','宋','宋词','song-ci','菩萨蛮','[]','远山眉映横波脸。',52,'宋词/ci.song.3000.json','["远山眉映横波脸。", "脸波横映眉山远。", "云鬓插花新。", "新花插鬓云。", "断魂离思远。", "远思离魂断。", "门掩未黄昏。", "昏黄未掩门。"]'),
('song-ci-627','一落索','晁端礼','宋','宋词','song-ci','一落索','[]','正向溪堂欢笑。',58,'宋词/ci.song.3000.json','["正向溪堂欢笑。", "忽惊传新诏。", "马啼准拟乐郊行，又却近、长安道。", "鹳鹊楼边初到。", "未花残莺老。", "崔徽歌舞有馀风，应忘了、东平好。"]'),
('song-ci-628','虞美人','晁端礼','宋','宋词','song-ci','虞美人','[]','木兰舟稳桃花浪。',66,'宋词/ci.song.3000.json','["木兰舟稳桃花浪。", "重到清溪上。", "刘郎惆怅武陵迷。", "无限落英飞絮、水东西。", "玉觞潋滟谁相送。", "一觉扬州梦。", "不知何物最多情。", "惟有南山不改、旧时青。"]'),
('song-ci-629','虞美人','晁端礼','宋','宋词','song-ci','虞美人','[]','短亭过尽长亭到。',66,'宋词/ci.song.3000.json','["短亭过尽长亭到。", "未忍过征棹。", "天涯自是别离身。", "更折一枝杨柳、赠行人。", "淮阴堤上残阳里，暮草连空翠。", "一樽别酒苦匆匆。", "还似陇头流水、各西东。"]'),
('song-ci-630','一斛珠','晁端礼','宋','宋词','song-ci','一斛珠','[]','伤春怀抱。',67,'宋词/ci.song.3000.json','["伤春怀抱。", "清明过后莺声老。", "劝君莫向愁人道。", "又被香轮，碾破青青草。", "夜来风雨连清晓。", "秋千院落无人到。", "梦回酒醒愁多少。", "犹赖春寒，未放花开了。"]'),
('song-ci-631','少年游','晁端礼','宋','宋词','song-ci','少年游','[]','建溪灵草已先尝。',60,'宋词/ci.song.3000.json','["建溪灵草已先尝。", "欢意尚难忘。", "未放笙歌，暂留簪珮。", "犹有紫芝汤。", "醉中纤手殷勤捧，欲去断人肠。", "绛蜡迎归，绣鞍扶下，笑语尽闻香。"]'),
('song-ci-632','鹊桥仙','晁端礼','宋','宋词','song-ci','鹊桥仙','[]','多情应解，留连春意，满地萦花惹絮。',68,'宋词/ci.song.3000.json','["多情应解，留连春意，满地萦花惹絮。", "王孙何在不归来，又遍满、闲门要路。", "咸阳原上，姑苏台下，肠断绿波南浦。", "迢迢归思碧连云，解送我、春山尽处。"]'),
('song-ci-633','点绛唇','晁端礼','宋','宋词','song-ci','点绛唇','[]','洞户深沈，起来闲绕回郎转。',50,'宋词/ci.song.3000.json','["洞户深沈，起来闲绕回郎转。", "凤箫声远。", "小院杨花满。", "旧曲重寻，移遍秦筝雁。", "芳心乱。", "栏干凭暖。", "目向天涯断。"]'),
('song-ci-634','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','并蒂芙蓉本自双。',64,'宋词/ci.song.3000.json','["并蒂芙蓉本自双。", "晓来波上斗新妆。", "朱匀檀口都无语，酒入圆腮各是香。", "辞汉曲，别高唐。", "芳心应解妒鸳鸯。", "不封虢国并秦国，应嫁刘郎与阮郎。"]'),
('song-ci-635','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','红紫飘零绿满城。',64,'宋词/ci.song.3000.json','["红紫飘零绿满城。", "春风於此独留情。", "谁将十幅吴绫被，扑向熏笼一夜明。", "风不定，雨初晴。", "晓来苔上拾残英。", "连教贮向鸳鸯枕，犹有馀香入梦清。"]'),
('song-ci-636','武陵春','晁端礼','宋','宋词','song-ci','武陵春','[]','湖上风光寒食近，准拟醉花枝。',56,'宋词/ci.song.3000.json','["湖上风光寒食近，准拟醉花枝。", "不忍东风烂熳时。", "红泪湿胭脂。", "情知今后游从少，鸾镜懒重窥。", "金凤衔花旧绣衣。", "憔悴舞腰肢。"]'),
('song-ci-637','苏幕遮','晁端礼','宋','宋词','song-ci','苏幕遮','[]','碧桃花，春婉娩。',76,'宋词/ci.song.3000.json','["碧桃花，春婉娩。", "未断尘缘，暂别瑶池宴。", "谪限迢迢应未满。", "乘月骖鸾，曾有深深愿。", "帝城赊，凤楼远。", "长寿杯深，此际谁人劝。", "闷倚屏山凝泪眼。", "百和烟中，细想千娇面。"]'),
('song-ci-638','朝中措','晁端礼','宋','宋词','song-ci','朝中措','[]','短亭杨柳接长亭。',57,'宋词/ci.song.3000.json','["短亭杨柳接长亭。", "攀折赠君行。", "莫怪尊前无语，大多分外多情。", "何须苦计，时间利禄，身后功名。", "且尽十分芳酒，共倾一梦浮生。"]'),
('song-ci-639','丑奴儿・采桑子','晁端礼','宋','宋词','song-ci','丑奴儿・采桑子','[]','小庭数朵寒梅放，雪缀霜稜。',52,'宋词/ci.song.3000.json','["小庭数朵寒梅放，雪缀霜稜。", "装点香英。", "玉软琼娇两未胜。", "佳人皓腕争攀取，插向壶冰。", "素色相乘。", "不羡高花万万层。"]'),
('song-ci-640','丑奴儿・采桑子','晁端礼','宋','宋词','song-ci','丑奴儿・采桑子','[]','来朝匹马萧萧去，且醉芳卮。',52,'宋词/ci.song.3000.json','["来朝匹马萧萧去，且醉芳卮。", "明夜天涯。", "浅酌低吟欲殢谁。", "归来应过重阳也，菊有残枝。", "纤手重携。", "未必秋香一夜衰。"]'),
('song-ci-641','惜双双・惜分飞','晁端礼','宋','宋词','song-ci','惜双双・惜分飞','[]','天上星杓春又到。',68,'宋词/ci.song.3000.json','["天上星杓春又到。", "应律管、微阳已报。", "暖信惊梅早。", "昨夜南枝，先得芳菲耗。", "迟日曈胧光破晓。", "馥绣幄、麝炉烟袅。", "为寿金壶倒。", "四坐簪缨，共比松筠老。"]'),
('song-ci-642','脱银袍','晁端礼','宋','宋词','song-ci','脱银袍','[]','纤条绿沁。',80,'宋词/ci.song.3000.json','["纤条绿沁。", "春色为伊难禁。", "传芳意、东君信任。", "燕愁莺懒，怕轻寒犹禁。", "护占得、幽香转甚。", "粉面初匀，冰肌未饮。", "何须爱、妖桃胜锦。", "夜阑人静，任月华来浸。", "待抱著、花枝醉寝。"]'),
('song-ci-643','行香子','晁端礼','宋','宋词','song-ci','行香子','[]','别恨绵绵。',84,'宋词/ci.song.3000.json','["别恨绵绵。", "屈指三年。", "再相逢、情分依然。", "君初霜鬓，我已华颠。", "况其间有，多少恨，不堪言。", "小庭幽槛，菊蕊阑斑。", "近清宵、月已婵娟。", "莫思身外，且斗樽前。", "愿花长好，人长健，月长圆。"]'),
('song-ci-644','小重山','晁端礼','宋','宋词','song-ci','小重山','[]','朱户深深小洞房。',70,'宋词/ci.song.3000.json','["朱户深深小洞房。", "曲屏龟甲样，画潇湘。", "纱轻蓝嫩镂牙床。", "人如玉，一见已心凉。", "午枕梦悠扬。", "流莺声唤觉，日犹长。", "几回烟断玉炉香。", "庭花影，不肯上东廊。"]'),
('song-ci-645','雨霖铃','晁端礼','宋','宋词','song-ci','雨霖铃','[]','槐阴添绿。',123,'宋词/ci.song.3000.json','["槐阴添绿。", "雨馀花落，酒病相续。", "闲寻双杏凝伫，池塘暖、鸳鸯浴。", "却向窗昼卧，正春睡难足。", "叹好梦、一一无凭，帐掩金花座凝目。", "当时共赏移红烛。", "向花间、小饮杯盘促。", "蔷薇花下曾记，双凤带、索题诗曲。", "别后厌厌，应是香肌，瘦减罗幅。", "问燕子、不肯传情，甚入华堂宿。"]'),
('song-ci-646','玉叶重黄','晁端礼','宋','宋词','song-ci','玉叶重黄','[]','玉纤初拈梅花蕊。',64,'宋词/ci.song.3000.json','["玉纤初拈梅花蕊。", "早忆著、上元天气。", "重寻旧曲声韵，收拾放灯欢计。", "况人生、百岁能几。", "任东风、笑我双鬓里。", "重来花下醉也，不减旧时风味。"]'),
('song-ci-647','金蕉叶','晁端礼','宋','宋词','song-ci','金蕉叶','[]','楼头已报咚咚鼓。',74,'宋词/ci.song.3000.json','["楼头已报咚咚鼓。", "华堂渐、停杯投箸。", "更闻急管频催，凤口香销炷。", "花映玉山倾处。", "主人无计留宾住。", "溪泉泛、越瓯春乳。", "醉魂一啜都醒，绛蜡迎归去。", "更看后房歌舞。"]'),
('song-ci-648','南歌子','晁端礼','宋','宋词','song-ci','南歌子','[]','月到中秋夜，还胜别夜圆。',62,'宋词/ci.song.3000.json','["月到中秋夜，还胜别夜圆。", "高河瑟瑟转金盘。", "三十六宫深处、卷帘看。", "香雾云鬟湿，清辉玉臂寒。", "寻常岂是不婵娟。", "吟赏莫辞终夕、动经年。"]'),
('song-ci-649','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','霜压天街不动尘。',64,'宋词/ci.song.3000.json','["霜压天街不动尘。", "千官环珮贺成禋。", "三竿阊阖楼边日，五色蓬莱顶上云。", "随步辇，卷香裀。", "六宫红粉倍添春。", "乐章近与中声合，一片仙韶特地新。"]'),
('song-ci-650','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','数骑飞尘入凤城。',64,'宋词/ci.song.3000.json','["数骑飞尘入凤城。", "朔方诸部奏河清。", "圜扉木索频年静，大晟箫韶九奏成。", "流协气，溢欢声。", "更将何事卜升平。", "天颜不禁都人看，许近黄金辇路行。"]'),
('song-ci-651','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','阆苑瑶台路暗通。',64,'宋词/ci.song.3000.json','["阆苑瑶台路暗通。", "皇州佳气正葱葱。", "半天楼殿朦胧月，午夜笙歌淡荡风。", "车流水，马游龙。", "万家行乐醉醒中。", "何须更待元宵到，夜夜莲灯十里红。"]'),
('song-ci-652','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','洛水西来泛绿波。',64,'宋词/ci.song.3000.json','["洛水西来泛绿波。", "北瞻丹阙正嵯峨。", "先皇秘聿无人解，圣子神孙果众多。", "民物阜，岁时和。", "帝居不用壮山河。", "卜年卜世过周室，亿万斯年入咏歌。"]'),
('song-ci-653','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','壁水溶溶漾碧漪。',64,'宋词/ci.song.3000.json','["壁水溶溶漾碧漪。", "桥门清晓驻鸾旗。", "三千儒服鸳兼鹭，十万犀兵虎与貔。", "春服就，舞雩归。", "四方争颂育莪诗。", "熙丰教养今成效，已见夔龙集凤池。"]'),
('song-ci-654','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','八彩眉开喜色新。',64,'宋词/ci.song.3000.json','["八彩眉开喜色新。", "边陲来奏捷书频。", "百蛮洞穴皆王土，万里戎羌尽汉臣。", "丹转毂，锦拖绅。", "充庭列贡集珠珍。", "宫花御柳年年好，万岁声中过一春。"]'),
('song-ci-655','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','圣泽昭天下漏泉。',64,'宋词/ci.song.3000.json','["圣泽昭天下漏泉。", "君王慈孝自天然。", "四民有养跻仁寿，九族咸亲迈古先。", "歌舜日，咏尧年。", "竞翻玉管播朱弦。", "须知大观崇宁事，不愧生民下武篇。"]'),
('song-ci-656','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','日日仙韶度曲新。',64,'宋词/ci.song.3000.json','["日日仙韶度曲新。", "万机多暇宴游频。", "歌馀兰麝生纨扇，舞罢珠玑落绣絪。", "金屋暖，璧台春。", "意中情态掌中身。", "近来谁解辞同辇，似说昭阳第一人。"]'),
('song-ci-657','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','万国梯航贺太平。',64,'宋词/ci.song.3000.json','["万国梯航贺太平。", "天人协赞甚分明。", "两阶羽舞三苗格，九鼎神金一铸成。", "仙鹤唳，玉芝生。", "包茅三脊已充庭。", "翠华脉脉东封事，日观云深万仞青。"]'),
('song-ci-658','鹧鸪天','晁端礼','宋','宋词','song-ci','鹧鸪天','[]','金碧觚稜斗极边。',64,'宋词/ci.song.3000.json','["金碧觚稜斗极边。", "集英深殿听胪传。", "齐开雉扇双分影，不动金炉一喷烟。", "红锦地，碧罗天。", "升平楼上语喧喧。", "依稀曾听钧天奏，耳冷人间四十年。"]'),
('song-ci-659','并蒂芙蓉','晁端礼','宋','宋词','song-ci','并蒂芙蓉','[]','太液波澄，向鉴中照影，芙蓉同蒂。',118,'宋词/ci.song.3000.json','["太液波澄，向鉴中照影，芙蓉同蒂。", "千柄绿荷深，并丹脸争媚。", "天心眷临圣日，殿宇分明敞嘉瑞。", "弄香嗅蕊。", "愿君王，寿与南山齐比。", "池边屡回翠辇，拥群仙醉赏，凭栏凝思。", "萼绿揽飞琼，共波上游戏。", "西风又看露下，更结双双新莲子。", "斗状竞美。", "问鸳鸯、向谁留意。"]'),
('song-ci-660','寿星明・沁园春','晁端礼','宋','宋词','song-ci','寿星明・沁园春','[]','露湿晴花，散红香清影，建章宫殿。',121,'宋词/ci.song.3000.json','["露湿晴花，散红香清影，建章宫殿。", "玉宇风来，银河云敛，天外老人星现。", "向晓千官入，称庆山呼鳌抃。", "凤髓香飘，龙墀翡翠，帘栊高卷。", "朝罢仗卫再整，肃鸣鞘，又向瑶池高宴。", "海寓承平，君臣相悦，乐奏徵招初遍。", "治极将何报，检玉泥金封禅。", "见说山中居民，待看雕辇。"]'),
('song-ci-661','黄河清','晁端礼','宋','宋词','song-ci','黄河清','[]','晴景初升风细细。',119,'宋词/ci.song.3000.json','["晴景初升风细细。", "云收天淡如洗。", "望外凤凰双阙，葱葱佳气。", "朝罢香烟满袖，近臣报、天颜有喜。", "夜来连得封章，奏大河、彻底清泚。", "君王寿与天齐，馨香动上穹，频降嘉瑞。", "大晟奏功，六乐初调清徵。", "合殿春风乍转，万花覆、千官尽醉。", "内家传敕，重开宴、未央宫里。"]'),
('song-ci-662','舜韶新','晁端礼','宋','宋词','song-ci','舜韶新','[]','晨光射牖，新燕子、一一穿帘飞去。',122,'宋词/ci.song.3000.json','["晨光射牖，新燕子、一一穿帘飞去。", "露唏鸳瓦，萧瑟风生琼宇。", "香篆烟消昼永，锁深院、榴花半吐。", "映绛绡、冰雪肌肤，自是清凉无暑。", "浮荣何用萦怀，冷笑看、车马喧喧尘土。", "地偏心远，终日何妨扃户。", "一枕江南好梦，泛孤棹、轻烟细雨。", "被数声、幽鸟惊回，砌下槐阴亭午。"]'),
('song-ci-663','上林春・一落萦','晁端礼','宋','宋词','song-ci','上林春・一落萦','[]','相识来来，真个为伊，尽把精神役破。',126,'宋词/ci.song.3000.json','["相识来来，真个为伊，尽把精神役破。", "啼殢性□，娇痴做处，双眉镇长愁锁。", "为伊恁地，便诸事、自来饶过。", "暂时间未覰得，又早孜煎无那。", "想从来、性气恁麽。", "那堪更等闲，经时抛亸。", "料得那里、千僝万僽，嗔我也思量我。", "再归见了，算应是、絮得些个。", "但初心、尚未改，任从摧挫。"]'),
('song-ci-664','雨中花・夜行船','晁端礼','宋','宋词','song-ci','雨中花・夜行船','[]','小小中庭，深深洞户，谁人笑里相迎。',119,'宋词/ci.song.3000.json','["小小中庭，深深洞户，谁人笑里相迎。", "有三年窥宋，一顾倾城。", "舞态方浓，箫声未阕，又黯离情。", "怎奈向，赢得多情怀抱，薄幸声名。", "良宵记得，醉中携手，画楼月皎风清。", "难忘处、凭肩私语，和泪深盟。", "假使钗分金股，休论井引银瓶。", "但知记取，此心常在，好事须成。"]'),
('song-ci-665','醉蓬莱','晁端礼','宋','宋词','song-ci','醉蓬莱','[]','向重门深闭，永夜孤眠，梦魂飞过。',120,'宋词/ci.song.3000.json','["向重门深闭，永夜孤眠，梦魂飞过。", "梦里分明，共玉人双卧。", "粉淡香浓，翠深红浅，是那回梳裹。", "楚雨难成，巫云易散，依前惊破。", "无绪无聊，向谁分诉，独语独言，自家摧挫。", "梦也多磨，更那堪真个。", "暗数残更，半敧孤枕，对夜深灯火。", "怨泪频弹，愁肠屡断，伊还知麽。"]'),
('song-ci-666','吴音子','晁端礼','宋','宋词','song-ci','吴音子','[]','细想当初事，又非是、取次相知。',124,'宋词/ci.song.3000.json','["细想当初事，又非是、取次相知。", "一年来、覰著尚迟。", "疑□时、敢共些儿。", "似恁秤停期克了，便一成望不相离。", "却何期、恩情陡变，中路分飞。", "都缘我自心肠软，润就得、转转娇痴。", "如今未中再偎随。", "选不甚，且从待他疏狂心性，足变堆垛，更吃禁持。", "管取你回心，却有投奔人时。"]'),
('song-ci-667','洞仙歌','晁端礼','宋','宋词','song-ci','洞仙歌','[]','眼来眼去，未肯分明道。',102,'宋词/ci.song.3000.json','["眼来眼去，未肯分明道。", "有意于人甚不早。", "谩教我、心下终日悬悬，星□事，知他何时是了。", "几回猜伊意，也是难为，拟待偷怜又胆小。", "奈何我已狂迷，怎肯乾休，情深后、不免求告。", "但只教、时时得些儿，便拼了一生，为伊烦恼。"]'),
('song-ci-668','安公子','晁端礼','宋','宋词','song-ci','安公子','[]','渐渐东风暖。',125,'宋词/ci.song.3000.json','["渐渐东风暖。", "杏梢梅萼红深浅。", "正好花前携素手，却云飞雨散。", "是即是、从来好事多磨难。", "就中我与你才相见。", "便世间烦恼，受了千千万万。", "回首空肠断。", "甚时与你同欢宴。", "但得人心长在了，管天须开眼。", "又只恐、日疏日远衷肠变。", "便忘了、当本深深愿。", "待寄封书去，更与丁宁一遍。"]'),
('song-ci-669','河满子','晁端礼','宋','宋词','song-ci','河满子','[]','草草时间欢笑，厌厌别后情怀。',86,'宋词/ci.song.3000.json','["草草时间欢笑，厌厌别后情怀。", "留下一场烦恼去，今回不比前回。", "幸自一成休也，阿谁教你重来。", "眠梦何曾安稳，身心没处安排。", "今世因缘如未断，终期他日重谐。", "但愿人心长在，到头天眼须开。"]'),
('song-ci-670','踏莎行','晁端礼','宋','宋词','song-ci','踏莎行','[]','骂女嗔男，呼奴喝爪。',68,'宋词/ci.song.3000.json','["骂女嗔男，呼奴喝爪。", "新来司户多心躁。", "家中幸自好熙熙，眉儿皱著乾烦恼。", "饱喜饥嗔，多愁早老。", "古人言语分明道。", "剩须将息少孜煎，人生万事何时了。"]'),
('song-ci-671','临江仙','晁端礼','宋','宋词','song-ci','临江仙','[]','火冷灯□山驿静，无人与暖香衾。',68,'宋词/ci.song.3000.json','["火冷灯□山驿静，无人与暖香衾。", "阿谁教你惜人深。", "一成迷后，不忘有如今。", "枕畔耳边都悄悄，忆伊模样声音。", "些儿年纪正难禁。", "盟言虽在，只恐我痴心。"]'),
('song-ci-672','清平乐','晁端礼','宋','宋词','song-ci','清平乐','[]','娇羞未惯。',54,'宋词/ci.song.3000.json','["娇羞未惯。", "长是低花面。", "笑里爱将红袖掩。", "遮却双双笑靥。", "早来帘下逢伊。", "怪生频整衫儿。", "元是那回欢会，齿痕犹在凝脂。"]'),
('song-ci-673','一落索','晁端礼','宋','宋词','song-ci','一落索','[]','道著明朝分袂。',59,'宋词/ci.song.3000.json','["道著明朝分袂。", "早眉头攒翠。", "不言不语只偎人，满眼里、汪汪地。", "向道不须如此。", "转吞声饮气。", "一团儿肌骨不禁春，甚有得、许多泪。"]'),
('song-ci-674','一斛珠','晁端礼','宋','宋词','song-ci','一斛珠','[]','相思最苦。',67,'宋词/ci.song.3000.json','["相思最苦。", "别来有甚好情绪。", "夜间无限凄惶处。", "睡不著时，没个人言语。", "所恨不能飞上路。", "书书直怪迟归去。", "外边闲事无心覰。", "直自我咱，怕你恶肠肚。"]'),
('song-ci-675','少年游','晁端礼','宋','宋词','song-ci','少年游','[]','眼来眼去又无言。',60,'宋词/ci.song.3000.json','["眼来眼去又无言。", "教我怎生团。", "又不分明，许人一句，纵未也心安。", "是即自古常言道，色须是艰难。", "愿早得来，虽然容易，管不等闲看。"]'),
('song-ci-676','鹊桥仙','晁端礼','宋','宋词','song-ci','鹊桥仙','[]','从来因被，薄情相误，误得人来已怕。',72,'宋词/ci.song.3000.json','["从来因被，薄情相误，误得人来已怕。", "那回时、有愿不昏沈，甚近日、依前又也。", "你莫撋就，偎随人便，却骑墙两下。", "自家懑、都望有前程，背地里、莫教人咒骂。"]'),
('song-ci-677','点绛唇','晁端礼','宋','宋词','song-ci','点绛唇','[]','我也从来，唤作真个收拾定。',50,'宋词/ci.song.3000.json','["我也从来，唤作真个收拾定。", "据伊情性。", "怎到如今恁。", "撋就百般，终是心肠狠。", "应难更。", "是我薄命。", "不怨奴薄幸。"]'),
('song-ci-678','卜算子','晁端礼','宋','宋词','song-ci','卜算子','[]','恩义重如山，情意深如海。',56,'宋词/ci.song.3000.json','["恩义重如山，情意深如海。", "假使黄金北斗高，这一分、何由买。", "领家看取彩。", "莫要胡厮赖。", "堂印旁边更碧油，但管取、无人赛。"]'),
('song-ci-679','柳初新','晁端礼','宋','宋词','song-ci','柳初新','[]','些儿柄把天来大。',102,'宋词/ci.song.3000.json','["些儿柄把天来大。", "闷损也、还知麽。", "共伊合下、深盟厚约，比望收因结果。", "这好事、难成易破。", "到如今、彼此无那。", "终日行行坐坐。", "未曾识、展眉则个。", "若还不是、前生注定，甚得许多摧挫。", "去你行、有甚罪过。", "送一场、烦恼与我。"]'),
('song-ci-680','步蟾宫','晁端礼','宋','宋词','song-ci','步蟾宫','[]','昨宵争个甚闲事。',72,'宋词/ci.song.3000.json','["昨宵争个甚闲事。", "又不道、被谁调戏。", "任孜孜、求告不回头，诮满眼、汪汪地泪。", "奴哥一向不赌是。", "算谁敢、共他争气。", "且偎随、须有喜欢时，待款款、说些道理。"]'),
('song-ci-681','千秋岁','晁端礼','宋','宋词','song-ci','千秋岁','[]','飞云骤雨。',87,'宋词/ci.song.3000.json','["飞云骤雨。", "草草成暌阻。", "寸肠结尽千千缕。", "别离谁是没，惟我於中苦。", "最苦是，看奴未足抛奴去。", "一句临歧语。", "忍泪奴听取。", "身可舍，情难负。", "纵非瓶断绠，也是钗分股。", "再见了，知他似得如今否。"]'),
('song-ci-682','人娇','晁端礼','宋','宋词','song-ci','人娇','[]','旋剔银灯，高褰斗帐。',80,'宋词/ci.song.3000.json','["旋剔银灯，高褰斗帐。", "孜孜地、看伊模样。", "端相一饷，揉搓一饷。", "不会得、知他甚家娘养。", "不见些儿，行思坐想。", "分飞后、怎生□向。", "天天若许，长长偎傍。", "顶带著、一生也即不枉。"]'),
('song-ci-683','遍地花','晁端礼','宋','宋词','song-ci','遍地花','[]','密约幽欢试思忖。',71,'宋词/ci.song.3000.json','["密约幽欢试思忖。", "教人又、怎生安稳。", "算都来、些子精神，诮烦恼、看看瘦损。", "也拟待、罗织伊家，图开解、较些可闷。", "把从前、已往寻思，又无可、教人得恨。"]'),
('song-ci-684','梁州令','晁端礼','宋','宋词','song-ci','梁州令','[]','各自寻思取。',58,'宋词/ci.song.3000.json','["各自寻思取。", "更莫怨他人做。", "如今剗地怕相逢，愁多正在相逢处。", "人前不敢分明语。", "暗里频回顾。", "罗襟滴泪无数。", "匆匆又是空归去。"]'),
('song-ci-685','滴滴金','晁端礼','宋','宋词','song-ci','滴滴金','[]','庞儿周正心儿得。',57,'宋词/ci.song.3000.json','["庞儿周正心儿得。", "眼儿单、鼻儿直。", "口儿香、发儿黑。", "脚儿一折。", "从来薄命多阻隔。", "未曾有恁相识。", "除非烧香做功德。", "且图消得。"]'),
('song-ci-686','失调名','晁端礼','宋','宋词','song-ci','失调名','[]','花前月下堪垂泪，水边楼上总关心。',16,'宋词/ci.song.3000.json','["花前月下堪垂泪，水边楼上总关心。"]'),
('song-ci-687','蓦山溪','晁端礼','宋','宋词','song-ci','蓦山溪','[]','风流心胆，直把春偿酒。',102,'宋词/ci.song.3000.json','["风流心胆，直把春偿酒。", "选得一枝花，绮罗中、算来未有。", "名园翠苑，风月最佳时，夜迢迢，车款款，是处曾携手。", "重来一梦，池馆皆依旧。", "幽恨写新诗，托何人、章台问柳。", "渔舟归后，云锁武陵溪，水潺潺，花片片，舣棹空回首。"]'),
('song-ci-688','好事近','曾肇','宋','宋词','song-ci','好事近','[]','岁晚凤山阴，看尽楚天冰雪。',53,'宋词/ci.song.3000.json','["岁晚凤山阴，看尽楚天冰雪。", "不待牡丹时候，又使人轻别。", "如今归去老江南，扁舟载风月。", "不似画梁双燕，有重来时节。"]'),
('song-ci-689','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','归去。',45,'宋词/ci.song.3000.json','["归去。", "携笼女。", "南陌柔桑三月暮。", "使君春思如飞絮。", "五马徘徊频驻。", "蚕饥日晚空留顾。", "笑指秦楼归去。"]'),
('song-ci-690','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','双桨。',45,'宋词/ci.song.3000.json','["双桨。", "小舟荡。", "唤取莫愁迎叠浪。", "武陵豪客青楼上。", "不道风高江广。", "千金难买倾城样。", "那听绕梁清唱。"]'),
('song-ci-691','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','草草。',45,'宋词/ci.song.3000.json','["草草。", "最年少。", "袖户银屏人窈窕。", "瑶琴暗写相思调。", "一曲关心多少。", "临邛客舍成都道。", "苦恨相逢不早。"]'),
('song-ci-692','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','烟暖。',45,'宋词/ci.song.3000.json','["烟暖。", "武陵晚。", "洞里春长花烂熳。", "红英满地溪流浅。", "渐听云中鸡犬。", "刘朗迷路香风远。", "误到蓬莱仙馆。"]'),
('song-ci-693','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','春艳。',45,'宋词/ci.song.3000.json','["春艳。", "桃花脸。", "笑倚银屏施宝靥。", "良人少有平戎胆。", "归路光生弓剑。", "青楼春永香帏掩。", "独把韶华都占。"]'),
('song-ci-694','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','相慕。',45,'宋词/ci.song.3000.json','["相慕。", "酒家女。", "巧笑明眸年十五。", "当垆春永寻芳去。", "门外落花飞絮。", "银鞍白马金吾子。", "多谢结裙情素。"]'),
('song-ci-695','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','肠断。',45,'宋词/ci.song.3000.json','["肠断。", "浙江岸。", "楼上青帘新酒软。", "吴姬绰约开金盏。", "的的娇波流盼。", "采菱歌罢行云散。", "望断侬家心眼。"]'),
('song-ci-696','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','苏小。',45,'宋词/ci.song.3000.json','["苏小。", "最娇妙。", "几度尊前曾调笑。", "云情雨态知多少。", "悔恨相逢不早。", "刘郎襟韵正年少。", "风月今宵偏好。"]'),
('song-ci-697','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','梦悄。',45,'宋词/ci.song.3000.json','["梦悄。", "翠屏晓。", "帐里薰炉残蜡照。", "赏心乐事能多少。", "忍听阳关声调。", "明朝门外长安道。", "怅望王孙芳草。"]'),
('song-ci-698','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','时节。',45,'宋词/ci.song.3000.json','["时节。", "白银阙。", "洞里春晴百和爇。", "兰心底事多悲切。", "消尽一团冰雪。", "明皇恩爱云山绝。", "谁道蓬莱安悦。"]'),
('song-ci-699','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','调笑。',45,'宋词/ci.song.3000.json','["调笑。", "楚江渺。", "粉面修眉花斗好。", "擎荷折柳争相调。", "惊起鸳鸯多少。", "渔歌齐唱催残照。", "一叶归舟轻小。"]'),
('song-ci-700','调笑转踏・调笑令','郑仅','宋','宋词','song-ci','调笑转踏・调笑令','[]','声切。',45,'宋词/ci.song.3000.json','["声切。", "恨难说。", "千里潮平春浪阔。", "梅风不解相思结。", "忍送落花飞雪。", "多才一去芳音绝。", "更对珠帘新月。"]'),
('song-ci-701','西江月','蔡京','宋','宋词','song-ci','西江月','[]','八十一年住世，四千里外无家。',58,'宋词/ci.song.3000.json','["八十一年住世，四千里外无家。", "如今流落向天涯。", "梦到瑶池阙下。", "玉殿五回命相，彤庭几度宣麻。", "止因贪此恋荣华。", "便有如今事也。"]'),
('song-ci-702','西江月','苏琼','宋','宋词','song-ci','西江月','[]','韩愈文章盖世，谢安情性风流。',58,'宋词/ci.song.3000.json','["韩愈文章盖世，谢安情性风流。", "良辰美景在西楼。", "敢劝一卮芳酒。", "记得南宫高第，弟兄争占鳌头。", "金炉玉殿瑞烟浮。", "高占甲科第九。"]'),
('song-ci-703','茶瓶儿','李元膺','宋','宋词','song-ci','茶瓶儿','[]','去年相逢深院宇。',68,'宋词/ci.song.3000.json','["去年相逢深院宇。", "海棠下、曾歌金缕。", "歌罢花如雨。", "翠罗衫上，点点红无数。", "今岁重寻携手处。", "空物事、人非春暮。", "回首青门路。", "乱红飞絮，相逐东风去。"]'),
('song-ci-704','洞仙歌','李元膺','宋','宋词','song-ci','洞仙歌','[]','廉纤细雨，殢东风如困。',103,'宋词/ci.song.3000.json','["廉纤细雨，殢东风如困。", "萦断千丝为谁恨。", "向楚宫一梦，千古悲凉，无处问。", "愁到而今未尽。", "分明都是泪，泣柳沾花，常与骚人伴孤闷。", "记当年，得意处，酒力方融，怯轻寒、玉炉香润。", "又岂识、情怀苦难禁，对点滴檐声，夜寒灯晕。"]'),
('song-ci-705','洞仙歌','李元膺','宋','宋词','song-ci','洞仙歌','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','雪云散尽，放晓晴池院。',102,'宋词/ci.song.3000.json','["雪云散尽，放晓晴池院。", "杨柳于人便青眼。", "更风流多处，一点梅心、相映远。", "约略嚬轻笑浅。", "一年春好处，不在浓芳，小艳疏香最娇软。", "到清明时候，百紫千红花正乱。", "已失春风一半。", "蚤占取韶光，共追游，但莫管春寒，醉红自暖。"]'),
('song-ci-706','蓦山溪','李元膺','宋','宋词','song-ci','蓦山溪','[]','溪堂欢燕。',102,'宋词/ci.song.3000.json','["溪堂欢燕。", "惯捧玻璃盏。", "今日祖西城，更忍把、一杯重劝。", "别离情味，自古不堪秋，催泪雨，湿西风，肠共危弦断。", "夕阳去路，五马旌旗乱。", "便是古都春，应醉恋，曲江池馆。", "须知别后，叠翠倚阑情，青嶂晚，碧云深，日近长安远。"]'),
('song-ci-707','鹧鸪天','李元膺','宋','宋词','song-ci','鹧鸪天','[]','寂寞秋千两绣旗。',64,'宋词/ci.song.3000.json','["寂寞秋千两绣旗。", "日长花影转阶迟。", "燕惊午梦周遮语，蝶困春游落拓飞。", "思往事，入颦眉。", "柳梢阴重又当时。", "薄情风絮难拘束，飞过东墙不肯归。"]'),
('song-ci-708','菩萨蛮','李元膺','宋','宋词','song-ci','菩萨蛮','[]','彩旗画柱清明后。',52,'宋词/ci.song.3000.json','["彩旗画柱清明后。", "花前姊妹争携手。", "先紧绣罗裙。", "轻衫束领巾。", "琐绳金钏响。", "渐出花梢上。", "笑里问高低。", "盘云亸玉螭。"]'),
('song-ci-709','一落索','李元膺','宋','宋词','song-ci','一落索','[]','天上粉云如扫。',58,'宋词/ci.song.3000.json','["天上粉云如扫。", "放小楼清晓。", "古今何处想风流，最潇洒，龙山帽。", "人似年华易老。", "且芳樽频倒。", "西风于我更多情，露金靥，篱边笑。"]'),
('song-ci-710','浣溪沙','李元膺','宋','宋词','song-ci','浣溪沙','[]','乞与安仁掠鬓霜。',48,'宋词/ci.song.3000.json','["乞与安仁掠鬓霜。", "不须红线小机窗。", "剪刀疏下蜀罗长。", "纤手捻残针缕细，金钗翻过齿痕香。", "同心小绾寄思量。"]'),
('song-ci-711','浣溪沙','李元膺','宋','宋词','song-ci','浣溪沙','[]','饮散兰堂月未中。',48,'宋词/ci.song.3000.json','["饮散兰堂月未中。", "骅骝娇簇绛纱笼。", "玳簪促坐客从容。", "已醉人间千日酒，赐来天上密云龙。", "蓬仙清兴欲乘风。"]'),
('song-ci-712','调笑令','吕南公','宋','宋词','song-ci','调笑令','[]','行客。',40,'宋词/ci.song.3000.json','["行客。", "行客。", "身世东西南北。", "家林迢递不归。", "岁时悲盛泪垂。", "垂泪。", "垂泪。", "两鬓与霜相似。"]'),
('song-ci-713','调笑令','吕南公','宋','宋词','song-ci','调笑令','[]','华草。',40,'宋词/ci.song.3000.json','["华草。", "华草。", "秀发乘春更好。", "深心密竹纷纷。", "妖韶随处动人。", "人动。", "人动。", "王孙公子情重。"]'),
('song-ci-714','瑶台第一层','赵顼','宋','宋词','song-ci','瑶台第一层','[]','西母池边宴罢，赠南枝、步玉霄。',120,'宋词/ci.song.3000.json','["西母池边宴罢，赠南枝、步玉霄。", "绪风和扇，冰华发秀，雪质孤高。", "汉陂呈练影，问是谁、独立江皋。", "便凝望、壶中珪璧，天下琼瑶。", "清标。", "曾陪胜赏，坐望愁、解使尘消。", "况双成与乳丹点染，都付香梢。", "寿妆酥冷，郢韵佩举，麝卷云绡。", "乐逍遥。", "凤凰台畔，取次忆吹箫。"]'),
('song-ci-715','临江仙','吕希纯','宋','宋词','song-ci','临江仙','[]','□□□□□□□，□□□□□□。',70,'宋词/ci.song.3000.json','["□□□□□□□，□□□□□□。", "莫交闲虑到心头。", "有来忧不得，无后不须忧。", "□□□□□□□，□□□□□□。", "万般希望不如休。", "无来求不得，有后不须求。"]'),
('song-ci-716','蜡梅香','喻陟','宋','宋词','song-ci','蜡梅香','[]','晓日初长，正锦里轻阴，小寒天气。',125,'宋词/ci.song.3000.json','["晓日初长，正锦里轻阴，小寒天气。", "未报春消息，早瘦梅先发，浅苞纤蕊。", "搵玉匀香，天赋与，风流标致。", "问陇头人，音容万里。", "待凭谁寄。", "一样晓妆新，倚朱楼凝盼，素英如坠。", "映月临风处，度几声羌管，愁生乡思。", "电转光阴，须信道、飘零容易。", "且频欢赏，柔芳正好，满簪同醉。"]'),
('song-ci-717','渔家傲','朱服','宋','宋词','song-ci','渔家傲','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','小雨廉纤风细细。',72,'宋词/ci.song.3000.json','["小雨廉纤风细细。", "万家杨柳轻烟里。", "恋树湿花飞不起。", "愁无比。", "和春付与西流水。", "九十光阴能有几。", "金龟解尽留无计。", "寄语东城沽酒市。", "拼一醉。", "而今乐事他年泪。"]'),
('song-ci-718','无闷','丁注','宋','宋词','song-ci','无闷','[]','风急还收，云冻又开，海阔无人翦水。',123,'宋词/ci.song.3000.json','["风急还收，云冻又开，海阔无人翦水。", "算六出工夫，怎教容易。", "刚被郢歌楚舞。", "镇独向，尊前夸轻细。", "想谢庭诗咏，梁园赋赏，未成欢计。", "天意。", "是则是。", "便下得控持，柳梢梅蕊。", "又争奈、看看渐回春意。", "好趁东君未觉，预先把、园林都装缀。", "看是处，玉树琼枝，胜却万红千翠。"]'),
('song-ci-719','宝鼎现','刘弇','宋','宋词','song-ci','宝鼎现','[]','浓阴堆积，回野空旷，将回微煦。',192,'宋词/ci.song.3000.json','["浓阴堆积，回野空旷，将回微煦。", "还是觉、早梅依旧，清艳枝枝攒晓树。", "弄霁影、尽脂凝香蒂，琼削纤葩竞吐。", "对几处园林，芳菲消息，都因传去。", "取次台榭，等闲院落，偏宜独擅芳步。", "长恁恐、寿阳妆面，姑射冰肤成暗妒。", "笑杏坞、共桃蹊夸丽，一霎狂风骤雨。", "又争似、年年此际，先得东皇为主。", "好似雪里精神，曾解恼、游人吟顾。", "想当时折赠，端的凭谁付与。", "荡醉目、恨同云阻。", "画角声将暮。", "想异时成实，和羹止渴，还应得路。"]'),
('song-ci-720','洞仙歌','刘弇','宋','宋词','song-ci','洞仙歌','[]','凄凉楚弄，行客肠曾断。',101,'宋词/ci.song.3000.json','["凄凉楚弄，行客肠曾断。", "涛卷秋容暗淮甸。", "去年时、还是今日孤舟，烟浪里，身与江云共远。", "别来丹枕梦，几过沧洲，皓月而今为谁满。", "薄幸苦无端，误却婵娟，有人在、玉楼天半。", "最不愤、西风破帆来，甚时节，收拾望中心眼。"]'),
('song-ci-721','金明春・金明池','刘弇','宋','宋词','song-ci','金明春・金明池','[]','宝历延洪，昌辰开泰，崧岳储灵特异。',147,'宋词/ci.song.3000.json','["宝历延洪，昌辰开泰，崧岳储灵特异。", "贤才并、□时间出，尽一一惊人绝艺。", "捧乡书、气格飘飘，似阆苑神仙，参差相继。", "纵子墨文章，相如才调，骤觉雷声平地。", "太守宾兴当此际。", "正瑞霭寒轻，虚堂风细。", "舞腰旋、飞尘仿佛，歌管递、清声嘹唳。", "况相将、桂籍荣登，对酒面鳞红，何妨沈醉。", "但管取明年，宫花重戴，共赏金明春意。"]'),
('song-ci-722','内家娇','刘弇','宋','宋词','song-ci','内家娇','[]','绰约群芳里，阳和意，偏向一枝浓。',135,'宋词/ci.song.3000.json','["绰约群芳里，阳和意，偏向一枝浓。", "南国骤惊，动人奇艳，未饶西洛，百本千丛。", "斩新弄，晓来无比格，半坼断肠红。", "三月洞天，又还疑是，赋情楚客，窥见墙东。", "朱阑干、遍倚生愁，怕无计、奈雨禁风。", "别有瑞烟幕幕，时与遮笼。", "便纵使当日，文忠品第，赵昌模写，难更形容。", "应念故园桃李，羞怨春工。"]'),
('song-ci-723','安平乐慢','刘弇','宋','宋词','song-ci','安平乐慢','[]','细想劳生，等闲聚散，冉冉轻似秋烟。',126,'宋词/ci.song.3000.json','["细想劳生，等闲聚散，冉冉轻似秋烟。", "莲心暗苦，月意难圆。", "神京去路三千。", "当日风流，有妖饶枕上，软媚尊前。", "何计访蓬仙。", "断肠中、一叶晴川。", "到而今、追思往事，奈向梦也难到奴边。", "自恨不如兰灯，通宵尚照伊眠。", "恰道无缘。", "被人劝休莫瞒天。", "多应是、前生负你，今世使我偿填。"]'),
('song-ci-724','佳人醉','刘弇','宋','宋词','song-ci','佳人醉','[]','月到楼台第几。',88,'宋词/ci.song.3000.json','["月到楼台第几。", "十里金虫成缀。", "袅琅玕、争罥绛球起。", "试新妆、嬉春粉黛，盈盈暗香，接谁家秾李。", "拥缇骑。", "箫鼓沸三市。", "别指春风画隼，归度鳌山影里。", "闲红翠。", "挥觞不待、游人分袂。", "悄珠帘十二。"]'),
('song-ci-725','惜双双令・惜分飞','刘弇','宋','宋词','song-ci','惜双双令・惜分飞','[]','风外桔花香暗度。',62,'宋词/ci.song.3000.json','["风外桔花香暗度。", "飞絮绾、残春归去。", "酝造黄梅雨。", "冷烟晓占横塘路。", "翠屏人在天低处。", "惊梦断、行云无据。", "此恨凭谁诉。", "恁情却情危弦语。"]'),
('song-ci-726','清平乐','刘弇','宋','宋词','song-ci','清平乐','[]','东风依旧。',54,'宋词/ci.song.3000.json','["东风依旧。", "著意随堤柳。", "搓得鹅儿黄欲就。", "天色清明厮句。", "去年紫陌朱门。", "今朝雨魄云魂。", "断送一生憔悴，知他几个黄昏。"]'),
('song-ci-727','青门饮','时彦','宋','宋词','song-ci','青门饮','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','胡马嘶风，汉旗翻雪，彤云又吐，一竿残照。',130,'宋词/ci.song.3000.json','["胡马嘶风，汉旗翻雪，彤云又吐，一竿残照。", "古木连空，乱山无数，行尽暮沙衰草。", "星斗横幽馆，夜无眠、灯花空老。", "雾浓香鸭，冰凝泪烛，霜天难晓。", "长记晓妆才了，一杯未尽，离怀多少。", "醉里秋波，梦中朝雨，都是醒时烦恼。", "料有牵情处，忍思量、耳边曾道。", "甚时跃马归来，认得迎门轻笑。"]'),
('song-ci-728','瑶池宴令・越江吟','廖正一','宋','宋词','song-ci','瑶池宴令・越江吟','[]','飞花成阵。',65,'宋词/ci.song.3000.json','["飞花成阵。", "春心困。", "寸寸。", "别肠多少愁闷。", "无人问。", "偷啼自搵。", "残妆粉。", "抱瑶琴、寻出新韵。", "玉纤趁。", "南风未解幽愠。", "低云鬓。", "眉峰敛晕。", "娇和恨。"]'),
('song-ci-729','失调名','董武子','宋','宋词','song-ci','失调名','[]','畴昔寻芳秘殿西。',18,'宋词/ci.song.3000.json','["畴昔寻芳秘殿西。", "日压金铺，宫柳垂垂。"]'),
('song-ci-730','醉落魄・一斛珠','哑女','宋','宋词','song-ci','醉落魄・一斛珠','[]','风波未息。',67,'宋词/ci.song.3000.json','["风波未息。", "虚名浮利终无益。", "不如早去备蓑笠。", "高卧烟霞，千古企难及。", "君今既已装行色。", "定应雁塔题名籍。", "他年若到南雄驿。", "玉石休分，徒累卞和泣。"]'),
('song-ci-731','望海潮','秦观','宋','宋词','song-ci','望海潮','[]','星分牛斗，疆连淮海，扬州万井提封。',129,'宋词/ci.song.3000.json','["星分牛斗，疆连淮海，扬州万井提封。", "花发路香，莺啼人起，珠帘十里东风。", "豪俊气如虹。", "曳照春金紫，飞盖相从。", "巷入垂杨，画桥南北翠烟中。", "追思故国繁雄。", "有迷楼挂斗，月观横空。", "纹锦制帆，明珠溅雨，宁论爵马鱼龙。", "往事逐孤鸿。", "但乱云流水，萦带离宫。", "最好挥毫万字，一饮拼千锺。"]'),
('song-ci-732','望海潮','秦观','宋','宋词','song-ci','望海潮','[]','秦峰苍翠，耶溪潇洒，千岩万壑争流。',129,'宋词/ci.song.3000.json','["秦峰苍翠，耶溪潇洒，千岩万壑争流。", "鸳瓦雉城，谯门画戟，蓬莱燕阁三休。", "天际识归舟。", "泛五湖烟月，西子同游。", "茂草台荒，苎萝村冷起闲愁。", "何人览古凝眸。", "怅朱颜易失，翠被难留。", "梅市旧书，兰亭古墨，依稀风韵生秋。", "狂客鉴湖头。", "有百年台沼，终日夷犹。", "最好金龟换酒，相与醉沧洲。"]'),
('song-ci-733','望海潮','秦观','宋','宋词','song-ci','望海潮','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','梅英疏淡，冰澌溶泄，东风暗换年华。',129,'宋词/ci.song.3000.json','["梅英疏淡，冰澌溶泄，东风暗换年华。", "金谷俊游，铜驼巷陌，新晴细履平沙。", "长记误随车。", "正絮翻蝶舞，芳思交加。", "柳下桃蹊，乱分春色到人家。", "西园夜饮鸣笳。", "有华灯碍月，飞盖妨花。", "兰苑未空，行人渐老，重来是事堪嗟。", "烟暝酒旗斜。", "但倚楼极目，时见栖鸦。", "无奈归心。", "暗随流水到天涯。"]'),
('song-ci-734','望海潮','秦观','宋','宋词','song-ci','望海潮','[]','奴如飞絮，郎如流水，相沾便肯相随。',129,'宋词/ci.song.3000.json','["奴如飞絮，郎如流水，相沾便肯相随。", "微月户庭，残灯帘幕，匆匆共惜佳期。", "才话暂分携。", "早抱人娇咽，双泪红垂。", "画舸难停，翠帷轻别两依依。", "别来怎表相思。", "有分香帕子，合数松儿。", "红粉脆痕，青笺嫩约，丁宁莫遣人知。", "成病也因谁。", "更自言秋杪，亲去无疑。", "但恐生时注著，合有分于飞。"]'),
('song-ci-735','沁园春','秦观','宋','宋词','song-ci','沁园春','[]','宿霭迷空，腻云笼日，昼景渐长。',139,'宋词/ci.song.3000.json','["宿霭迷空，腻云笼日，昼景渐长。", "正兰皋泥润，谁家燕喜，蜜脾香少，触处蜂忙。", "尽日无人帘幕挂，更风递游丝时过墙。", "微雨后，有桃愁杏怨，红泪淋浪。", "风流寸心易感，但依依伫立，回尽柔肠。", "念小奁瑶鉴，重匀绛蜡，玉笼金斗，时熨沈香。", "柳下相将游冶处，便回首青楼成异乡。", "相忆事，纵蛮笺万叠，难写微茫。"]'),
('song-ci-736','水龙吟','秦观','宋','宋词','song-ci','水龙吟','[]','小楼连远横空，下窥绣毂雕鞍骤。',126,'宋词/ci.song.3000.json','["小楼连远横空，下窥绣毂雕鞍骤。", "朱帘半卷，单衣初试，清明时候。", "破暖轻风，弄晴微雨，欲无还有。", "卖花声过尽，斜阳院落，红成阵、飞鸳甃。", "玉佩丁东别后。", "怅佳期、参差难又。", "名缰利锁，天还知道，和天也瘦。", "花下重门，柳边深巷，不堪回首。", "念多情但有，当时皓月，向人依旧。"]'),
('song-ci-737','八六子','秦观','宋','宋词','song-ci','八六子','[]','倚危亭。',105,'宋词/ci.song.3000.json','["倚危亭。", "恨如芳草，萋萋剗尽还生。", "念柳外青骢别后，水边红袂分时，怆然暗惊。", "无端天与娉婷。", "夜月一帘幽梦，春风十里柔情。", "怎奈向、欢娱渐随流水，素弦声断，翠绡香减，那堪片片飞花弄晚，濛濛残雨笼晴。", "正销凝。", "黄鹂又啼数声。"]'),
('song-ci-738','风流子','秦观','宋','宋词','song-ci','风流子','[]','东风吹碧草，年华换、行客老沧洲。',135,'宋词/ci.song.3000.json','["东风吹碧草，年华换、行客老沧洲。", "见梅吐旧英，柳摇新绿，恼人春色，还上枝头。", "寸心乱，北随云黯黯，东逐水悠悠。", "斜日半山，暝烟两岸，数声横笛，一叶扁舟。", "青门同携手，前欢记、浑似梦里扬州。", "谁念断肠南陌，回首西楼。", "算天长地久，有时有尽，奈何绵绵，此恨难休。", "拟待倩人说与，生怕人愁。"]'),
('song-ci-739','梦扬州','秦观','宋','宋词','song-ci','梦扬州','[]','晚云收。',118,'宋词/ci.song.3000.json','["晚云收。", "正柳塘、烟雨初休。", "燕子未归，恻恻清寒如秋。", "小阑外、东风软，透绣帷、花蜜香稠。", "江南远，人何处，鹧鸪啼破春愁。", "长记曾陪燕游。", "酬妙舞清歌，丽锦缠头。", "殢酒为花，十载因谁淹留。", "醉鞭拂面归来晚，望翠楼、帘卷金钩。", "佳会阻，离情正乱，频梦扬州。"]'),
('song-ci-740','雨中花・夜行船','秦观','宋','宋词','song-ci','雨中花・夜行船','[]','指点虚无征路，醉乘斑虬，远访西极。',119,'宋词/ci.song.3000.json','["指点虚无征路，醉乘斑虬，远访西极。", "正天风吹落，满空寒白。", "玉女明星迎笑，何苦自淹尘域。", "正火轮飞上，雾卷烟开，洞观金碧。", "重重观阁，横枕鳌峰，水面倒衔苍石。", "随处有、奇香幽火，杳然难测。", "好是蟠桃熟后，阿环偷报消息。", "在青天碧海，一枝难遇，占取春色。"]'),
('song-ci-741','一丛花','秦观','宋','宋词','song-ci','一丛花','[]','年时今夜见师师。',95,'宋词/ci.song.3000.json','["年时今夜见师师。", "双颊酒红滋。", "疏帘半卷微灯外，露华上、烟袅凉风。", "簪髻乱抛，偎人不起，弹泪唱新词。", "佳期。", "谁料久参差。", "愁绪暗萦丝。", "想应妙舞清歌罢，又还对、秋色嗟咨。", "惟有画楼，当时明月，两处照相思。"]'),
('song-ci-742','鼓笛慢・水龙吟','秦观','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','乱花丛里曾携手，穷艳景，迷欢赏。',131,'宋词/ci.song.3000.json','["乱花丛里曾携手，穷艳景，迷欢赏。", "到如今谁把，雕鞍锁定，阻游人来往。", "好梦随春远，从前事、不堪思想。", "念香闺正杳，佳欢未偶，难留恋、空惆怅。", "永夜婵娟未满，叹玉楼，几时重上。", "那堪万里，却寻归路，指阳关孤唱。", "苦恨东流水，桃源路、欲回双桨。", "仗何人，细与丁宁问呵，我如今怎向。"]'),
('song-ci-743','促拍满路花','秦观','宋','宋词','song-ci','促拍满路花','[]','露颗添花色。',101,'宋词/ci.song.3000.json','["露颗添花色。", "月彩投窗隙。", "春思如中酒，恨无力。", "洞房咫尺，曾寄情鸾翼。", "云散无踪迹。", "罗帐薰残，梦回无处寻觅。", "轻红腻白。", "步步熏兰泽。", "约腕金环重，宜妆饰。", "未知安否，一向无消息。", "不似寻常忆。", "忆后教人，片时存济不得。"]'),
('song-ci-744','长相思','秦观','宋','宋词','song-ci','长相思','[]','铁瓮城高，蒜山渡阔，干云十二层楼。',128,'宋词/ci.song.3000.json','["铁瓮城高，蒜山渡阔，干云十二层楼。", "开尊待月，掩箔披风，依然灯火扬州。", "绮陌南头。", "记歌名宛转，乡号温柔。", "曲槛俯清流。", "想花阴、谁系兰舟。", "念凄绝秦弦，感深荆赋，相望几许凝愁。", "勤勤裁尺素，奈双鱼、难渡瓜洲。", "晓鉴堪羞。", "潘鬓点、吴霜渐稠。", "幸于飞、鸳鸯未老，不应同是悲秋。"]'),
('song-ci-745','满庭芳','秦观','宋','宋词','song-ci','满庭芳','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','山抹微云，天连衰草，画角声断谯门。',118,'宋词/ci.song.3000.json','["山抹微云，天连衰草，画角声断谯门。", "暂停征棹，聊共引离尊。", "多少蓬莱旧事，空回首、烟霭纷纷。", "斜阳外，寒鸦万点，流水绕孤村。", "销魂。", "当此际，香囊暗解，罗带轻分。", "谩赢得、青楼薄幸名存。", "此去何时见也，襟袖上、空惹啼痕。", "伤情处，高城望断，灯火已黄昏。"]'),
('song-ci-746','满庭芳','秦观','宋','宋词','song-ci','满庭芳','[]','红蓼花繁，黄芦叶乱，夜深玉露初零。',118,'宋词/ci.song.3000.json','["红蓼花繁，黄芦叶乱，夜深玉露初零。", "霁天空阔，云淡楚江清。", "独棹孤篷小艇，悠悠过、烟渚沙汀。", "金钩细，丝纶慢卷，牵动一潭星。", "时时，横短笛，清风浩月，相与忘形。", "任人笑生涯，泛梗飘萍。", "饮罢不妨醉卧，尘劳事、有耳谁听。", "江风静，日高未起，枕上酒微醒。"]'),
('song-ci-747','满庭芳','秦观','宋','宋词','song-ci','满庭芳','[]','碧水惊秋，黄云凝暮，败叶零乱空阶。',118,'宋词/ci.song.3000.json','["碧水惊秋，黄云凝暮，败叶零乱空阶。", "洞房人静，斜月照徘徊。", "又是重阳近也，几处处，砧杵声催。", "西窗下，风摇翠竹，疑是故人来。", "伤怀。", "增怅望，新欢易失，往事难猜。", "问篱边黄菊，知为谁开。", "谩道愁须殢酒，酒未醒、愁已先回。", "凭阑久，金波渐转，白露点苍苔。"]'),
('song-ci-748','江城子','秦观','宋','宋词','song-ci','江城子','[]','西城杨柳弄春柔。',86,'宋词/ci.song.3000.json','["西城杨柳弄春柔。", "动离忧。", "泪难收。", "犹记多情，曾为系归舟。", "碧野朱桥当日事，人不见，水空流。", "韶华不为少年留。", "恨悠悠。", "几时休。", "飞絮落花时候、一登楼。", "便做春江都是泪，流不尽，许多愁。"]'),
('song-ci-749','江城子','秦观','宋','宋词','song-ci','江城子','[]','南来飞燕北归鸿。',86,'宋词/ci.song.3000.json','["南来飞燕北归鸿。", "偶相逢。", "惨愁容。", "绿鬓朱颜，重见两衰翁。", "别后悠悠君莫问，无限事，不言中。", "小槽春酒滴珠红。", "莫匆匆。", "满金锺。", "饮散落花流水、各西东。", "后会不知何处是，烟浪远，暮云重。"]'),
('song-ci-750','江城子','秦观','宋','宋词','song-ci','江城子','[]','枣花金钏约柔荑。',86,'宋词/ci.song.3000.json','["枣花金钏约柔荑。", "昔曾携。", "事难期。", "咫尺玉颜，和泪锁春闺。", "恰似小园桃与李，虽同处，不同枝。", "玉笙初度颤鸾篦。", "落花飞。", "为谁吹。", "月冷风高，此恨只天知。", "任是行人无定处，重相见，是何时。"]'),
('song-ci-751','满园花・促拍满路花','秦观','宋','宋词','song-ci','满园花・促拍满路花','[]','一向沈吟久。',106,'宋词/ci.song.3000.json','["一向沈吟久。", "泪珠盈襟袖。", "我当初不和、苦撋就。", "惯纵得软顽，见底心先有。", "行待痴心守。", "甚捻著脉子，倒把人来僝僽。", "近日来、非常罗皂丑。", "佛也须眉皱。", "怎掩得众人口。", "待收了孛罗，罢了从来斗。", "从今后。", "休道共我，梦见也、不能得句。"]'),
('song-ci-752','迎春乐','秦观','宋','宋词','song-ci','迎春乐','[]','菖蒲叶叶知多少。',63,'宋词/ci.song.3000.json','["菖蒲叶叶知多少。", "惟有个、蜂儿妙。", "雨晴红粉齐开了。", "露一点、娇黄小。", "早是被、晓风力暴。", "更春共、斜阳俱老。", "怎得香香深处，作个蜂儿抱。"]'),
('song-ci-753','鹊桥仙','秦观','宋','宋词','song-ci','鹊桥仙','[]','纤云弄巧，飞星传恨，银汉迢迢暗度。',68,'宋词/ci.song.3000.json','["纤云弄巧，飞星传恨，银汉迢迢暗度。", "金风玉露一相逢，便胜却、人间无数。", "柔情似水，佳期如梦，忍顾鹊桥归路。", "两情若是长久时，又岂在、朝朝暮暮。"]'),
('song-ci-754','菩萨蛮','秦观','宋','宋词','song-ci','菩萨蛮','[]','虫声泣露惊秋枕。',52,'宋词/ci.song.3000.json','["虫声泣露惊秋枕。", "罗帏泪湿鸳鸯锦。", "独卧玉肌凉。", "残更与恨长。", "阴风翻翠幔。", "雨涩灯花暗。", "毕竟不成眠。", "鸦啼金井寒。"]'),
('song-ci-755','减字木兰花','秦观','宋','宋词','song-ci','减字木兰花','[]','天涯旧恨。',52,'宋词/ci.song.3000.json','["天涯旧恨。", "独自凄凉人不问。", "欲见回肠。", "断尽金炉小篆香。", "黛峨长敛。", "任是春风吹不展。", "困倚危楼。", "过尽飞鸿字字愁。"]'),
('song-ci-756','木兰花・玉楼春','秦观','宋','宋词','song-ci','木兰花・玉楼春','[]','秋容老尽芙蓉院。',64,'宋词/ci.song.3000.json','["秋容老尽芙蓉院。", "草上霜花匀似翦。", "西楼促坐酒杯深，风压绣帘香不卷。", "玉纤慵整银筝雁。", "红袖时笼金鸭暖。", "岁华一任委西风，独有春红留醉脸。"]'),
('song-ci-757','画堂春','秦观','宋','宋词','song-ci','画堂春','[]','落红铺尽水平池。',55,'宋词/ci.song.3000.json','["落红铺尽水平池。", "弄晴小雨霏霏。", "杏园憔悴杜鹃啼。", "无奈春归。", "柳外画楼独上，凭阑手拈花枝。", "放花无语对斜晖。", "此恨谁知。"]'),
('song-ci-758','千秋岁','秦观','宋','宋词','song-ci','千秋岁','[]','水边沙外。',87,'宋词/ci.song.3000.json','["水边沙外。", "城郭春寒退。", "花影乱，莺声碎。", "飘零疏酒盏，离别宽衣带。", "人不见，碧云暮合空相对。", "忆昔西池会。", "鹓鹭同飞盖。", "携手处，今谁在。", "日边清梦断，镜里朱颜改。", "春去也，飞红万点愁如海。"]'),
('song-ci-759','踏莎行','秦观','宋','宋词','song-ci','踏莎行','[]','雾失楼台，月迷津渡。',68,'宋词/ci.song.3000.json','["雾失楼台，月迷津渡。", "桃源望断无寻处。", "可堪孤馆闭春寒，杜鹃声里斜阳暮。", "驿寄梅花，鱼传尺素。", "砌成此恨无重数。", "郴江幸自绕郴山，为谁流下潇湘去。"]'),
('song-ci-760','蝶恋花','秦观','宋','宋词','song-ci','蝶恋花','[]','晓日窥轩双燕语。',70,'宋词/ci.song.3000.json','["晓日窥轩双燕语。", "似与佳人，共惜春将暮。", "屈指艳阳都几许。", "可无时霎闲风雨。", "流水落花无问处。", "只有飞云，冉冉来还去。", "持酒劝云云且住。", "凭君碍断春归路。"]'),
('song-ci-761','一落索','秦观','宋','宋词','song-ci','一落索','[]','杨花终日空飞舞。',59,'宋词/ci.song.3000.json','["杨花终日空飞舞。", "奈久长难驻。", "海潮虽是暂时来，却有个、堪凭处。", "紫府碧云为路。", "好相将归去。", "肯如薄幸五更风，不解与、花为主。"]'),
('song-ci-762','丑奴儿・采桑子','秦观','宋','宋词','song-ci','丑奴儿・采桑子','[]','夜来酒醒清无梦，愁倚阑干。',52,'宋词/ci.song.3000.json','["夜来酒醒清无梦，愁倚阑干。", "露滴轻寒。", "雨打芙蓉泪不乾。", "佳人别后音尘悄，瘦尽难拼。", "明月无端。", "已过红楼十二间。"]'),
('song-ci-763','南乡子','秦观','宋','宋词','song-ci','南乡子','[]','妙手写徽真。',66,'宋词/ci.song.3000.json','["妙手写徽真。", "水翦双眸点绛唇。", "疑是昔年窥宋玉，东邻。", "只露墙头一半身。", "往事已酸辛。", "谁记当年翠黛颦。", "尽道有些堪恨处，无情。", "任是无情也动人。"]'),
('song-ci-764','醉桃源・阮郎归','秦观','宋','宋词','song-ci','醉桃源・阮郎归','[]','碧天如水月如眉。',56,'宋词/ci.song.3000.json','["碧天如水月如眉。", "城头银漏迟。", "绿波风动画船移。", "娇羞初见时。", "银烛暗，翠帘垂。", "芳心两自知。", "楚台魂断晓云飞。", "幽欢难再期。"]'),
('song-ci-765','河传','秦观','宋','宋词','song-ci','河传','[]','乱花飞絮。',75,'宋词/ci.song.3000.json','["乱花飞絮。", "又望空斗合，离人愁苦。", "那更夜来，一霎薄情风雨。", "暗掩将、春色去。", "篱枯壁尽因谁做。", "若说相思，佛也眉儿聚。", "莫怪为伊，底死萦肠惹肚。", "为没教、人恨处。"]'),
('song-ci-766','河传','秦观','宋','宋词','song-ci','河传','[]','恨眉醉眼。',75,'宋词/ci.song.3000.json','["恨眉醉眼。", "甚轻轻覰著，神魂迷乱。", "常记那回，小曲阑干西畔。", "鬓云松、罗袜剗。", "丁香笑吐娇无限。", "语软声低，道我何曾惯。", "云雨未谐，早被东风吹散。", "闷损人、天不管。"]'),
('song-ci-767','浣溪沙','秦观','宋','宋词','song-ci','浣溪沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','漠漠轻寒上小楼。',48,'宋词/ci.song.3000.json','["漠漠轻寒上小楼。", "晓阴无赖似穷秋。", "淡烟流水画屏幽。", "自在飞花轻似梦，无边丝雨细如愁。", "宝帘闲挂小银钩。"]'),
('song-ci-768','浣溪沙','秦观','宋','宋词','song-ci','浣溪沙','[]','香靥凝羞一笑开。',48,'宋词/ci.song.3000.json','["香靥凝羞一笑开。", "柳腰如醉暖相挨。", "日长春困下楼台。", "照水有情聊整鬓，倚阑无绪更兜鞋。", "眼边牵系懒归来。"]'),
('song-ci-769','浣溪沙','秦观','宋','宋词','song-ci','浣溪沙','[]','霜缟同心翠黛连。',48,'宋词/ci.song.3000.json','["霜缟同心翠黛连。", "红绡四角缀金钱。", "恼人香爇是龙涎。", "枕上忽收疑是梦，灯前重看不成眠。", "又还一断恶因缘。"]'),
('song-ci-770','浣溪沙','秦观','宋','宋词','song-ci','浣溪沙','[]','脚上鞋儿四寸罗。',48,'宋词/ci.song.3000.json','["脚上鞋儿四寸罗。", "唇边朱粉一樱多。", "见人无语但回波。", "料得有心怜宋玉，只应无奈楚襄何。", "今生有分共伊麽。"]'),
('song-ci-771','浣溪沙','秦观','宋','宋词','song-ci','浣溪沙','[]','锦帐重重卷暮霞。',48,'宋词/ci.song.3000.json','["锦帐重重卷暮霞。", "屏风曲曲斗红牙。", "恨人何事苦离家。", "枕上梦魂飞不去，觉来红日又西斜。", "满庭芳草衬残花。"]'),
('song-ci-772','如梦令','秦观','宋','宋词','song-ci','如梦令','[]','门外鸦啼杨柳。',40,'宋词/ci.song.3000.json','["门外鸦啼杨柳。", "春色著人如酒。", "睡起熨沈香，玉腕不胜金斗。", "消瘦。", "消瘦。", "还是褪花时候。"]'),
('song-ci-773','如梦令','秦观','宋','宋词','song-ci','如梦令','[]','遥夜沈沈如水。',40,'宋词/ci.song.3000.json','["遥夜沈沈如水。", "风紧驿亭深闭。", "梦破鼠窥灯，霜送晓寒侵被。", "无寐。", "无寐。", "门外马嘶人起。"]'),
('song-ci-774','如梦令','秦观','宋','宋词','song-ci','如梦令','[]','幽梦匆匆破后。',40,'宋词/ci.song.3000.json','["幽梦匆匆破后。", "妆粉乱痕沾袖。", "遥想酒醒来，无奈玉销花瘦。", "回首。", "回首。", "绕岸夕阳疏柳。"]'),
('song-ci-775','如梦令','秦观','宋','宋词','song-ci','如梦令','[]','楼外残阳红满。',40,'宋词/ci.song.3000.json','["楼外残阳红满。", "春入柳条将半。", "桃李不禁风，回首落英无限。", "肠断。", "肠断。", "人共楚天俱远。"]'),
('song-ci-776','如梦令','秦观','宋','宋词','song-ci','如梦令','[]','池上春归何处。',40,'宋词/ci.song.3000.json','["池上春归何处。", "满目落花飞絮。", "孤馆悄无人，梦断月堤归路。", "无绪。", "无绪。", "帘外五更风雨。"]'),
('song-ci-777','阮郎归','秦观','宋','宋词','song-ci','阮郎归','[]','褪花新绿渐团枝。',56,'宋词/ci.song.3000.json','["褪花新绿渐团枝。", "扑人风絮飞。", "秋千未拆水平堤。", "落红成地衣。", "游蝶困，乳莺啼。", "怨春春怎知。", "日长早被酒禁持。", "那堪更别离。"]'),
('song-ci-778','阮郎归','秦观','宋','宋词','song-ci','阮郎归','[]','宫腰袅袅翠鬟松。',56,'宋词/ci.song.3000.json','["宫腰袅袅翠鬟松。", "夜堂深处逢。", "无端银烛殒秋风。", "灵犀得暗通。", "身有恨，恨无穷。", "星河沈晓空。", "陇头流水各西东。", "佳期如梦中。"]'),
('song-ci-779','阮郎归','秦观','宋','宋词','song-ci','阮郎归','[]','潇湘门外水平铺。',56,'宋词/ci.song.3000.json','["潇湘门外水平铺。", "月寒征棹孤。", "红妆饮罢少踟蹰。", "有人偷向隅。", "挥玉箸，洒真珠。", "梨花春雨馀。", "人人尽道断肠初。", "那堪肠已无。"]'),
('song-ci-780','阮郎归','秦观','宋','宋词','song-ci','阮郎归','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','湘天风雨破寒初。',58,'宋词/ci.song.3000.json','["湘天风雨破寒初。", "深沈庭院虚。", "丽谯吹罢《小单于》。", "迢迢清夜徂。", "乡梦断，旅魂孤。", "峥嵘岁又除。", "衡阳犹有雁传书。", "郴阳和雁无。"]'),
('song-ci-781','满庭芳','秦观','宋','宋词','song-ci','满庭芳','[]','北苑研膏，方圭圆璧，名动万里京关。',118,'宋词/ci.song.3000.json','["北苑研膏，方圭圆璧，名动万里京关。", "碎身粉骨，功合上凌烟。", "尊俎风流战胜，降春睡、开拓愁边。", "纤纤捧，香泉溅乳，金缕鹧鸪斑。", "相如，方病酒，一觞一咏，宾有群贤。", "便扶起灯前，醉玉颓山。", "搜揽胸中万卷，还倾动，三峡词源。", "归来晚，文君未寝，相对晓妆残。"]'),
('song-ci-782','满庭芳','秦观','宋','宋词','song-ci','满庭芳','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','晓色云开，春随人意，骤雨才过还晴。',119,'宋词/ci.song.3000.json','["晓色云开，春随人意，骤雨才过还晴。", "古台芳榭，飞燕蹴红英。", "舞困榆钱自落，秋千外、绿水桥平。", "东风里，朱门映柳，低底按小秦筝。", "多情。", "行乐处，珠钿翠盖，玉辔红缨。", "渐酒空金榼，花困蓬瀛。", "豆蔻梢头旧恨，十年梦，屈指堪惊。", "凭阑久，疏烟淡日，寂寞下芜城。"]'),
('song-ci-783','满庭芳','秦观','宋','宋词','song-ci','满庭芳','[]','雅燕飞觞，清谈挥座，使君高会群贤。',118,'宋词/ci.song.3000.json','["雅燕飞觞，清谈挥座，使君高会群贤。", "密云双凤，初破缕金团。", "窗外炉烟似动，开瓶试、一品香泉。", "轻淘起，香生玉尘，雪溅紫瓯圆。", "娇鬟。", "宜美盼，双擎翠袖，稳步红莲。", "坐中客翻愁，酒醒歌阑。", "点上纱笼画烛，花骢弄、月影当轩。", "频相顾，馀欢未尽，欲去且流连。"]'),
('song-ci-784','桃源忆故人','秦观','宋','宋词','song-ci','桃源忆故人','[]','玉楼深锁薄情种。',56,'宋词/ci.song.3000.json','["玉楼深锁薄情种。", "清夜悠悠谁共。", "羞见枕衾鸳凤。", "闷即和衣拥。", "无端画角严城动。", "惊破一番新梦。", "窗外月华霜重。", "听彻梅花弄。"]'),
('song-ci-785','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','回顾。',45,'宋词/ci.song.3000.json','["回顾。", "汉宫路。", "捍拨檀槽鸾对舞。", "玉容寂寞花无主。", "顾影偷弹玉箸。", "未央宫殿知何处。", "目送征鸿南去。"]'),
('song-ci-786','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','辇路。',45,'宋词/ci.song.3000.json','["辇路。", "江枫古。", "楼上吹箫人在否。", "菱花半璧香尘污。", "往日繁华何处。", "旧欢新爱谁是主。", "啼笑两难分付。"]'),
('song-ci-787','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','翡翠。',45,'宋词/ci.song.3000.json','["翡翠。", "好容止。", "谁使庸奴轻点缀。", "裴郎一见心如醉。", "笑里偷传深意。", "罗衣中夜与门吏。", "暗结城西幽会。"]'),
('song-ci-788','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','相慕。',45,'宋词/ci.song.3000.json','["相慕。", "无双女。", "当日尚书先曾许。", "王郎明俊神仙侣。", "肠断别离情苦。", "数年睽恨今复遇。", "笑指襄江归去。"]'),
('song-ci-789','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','肠断。',45,'宋词/ci.song.3000.json','["肠断。", "绣帘卷。", "妾愿身为梁上燕。", "朝朝暮暮长相见。", "莫遣恩迁情变。", "红绡粉泪知何限。", "万古空传遗怨。"]'),
('song-ci-790','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','恋恋。',45,'宋词/ci.song.3000.json','["恋恋。", "楼中燕。", "燕子楼空春色晚。", "将军一去音容远。", "空锁楼中深怨。", "春风重到人不见。", "十二阑干倚遍。"]'),
('song-ci-791','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','春梦。',45,'宋词/ci.song.3000.json','["春梦。", "神仙洞。", "冉冉拂墙花树动。", "西厢待月知谁共。", "更觉玉人情重。", "红娘深夜行云送。", "困亸钗横金凤。"]'),
('song-ci-792','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','柳岸。',45,'宋词/ci.song.3000.json','["柳岸。", "水清浅。", "笑折荷花呼女伴。", "盈盈日照新妆面。", "水调空传幽怨。", "扁舟日暮笑声远。", "对此令人肠断。"]'),
('song-ci-793','调笑令','秦观','宋','宋词','song-ci','调笑令','["\u897f\u6e56"]','眷恋。',45,'宋词/ci.song.3000.json','["眷恋。", "西湖岸。", "湖面楼台侵云汉。", "阿溪本是飞琼伴。", "风月朱扉斜掩。", "谢郎巧思诗裁翦。", "能动芳怀幽怨。"]'),
('song-ci-794','调笑令','秦观','宋','宋词','song-ci','调笑令','[]','心素。',45,'宋词/ci.song.3000.json','["心素。", "与谁语。", "始信别离情最苦。", "兰舟欲解春江暮。", "精爽随君归去。", "异时携手重来处。", "梦觉春风庭户。"]'),
('song-ci-795','虞美人','秦观','宋','宋词','song-ci','虞美人','[]','高城望断尘如雾。',66,'宋词/ci.song.3000.json','["高城望断尘如雾。", "不见联骖处。", "夕阳村外小湾头。", "只有柳花无数、送归舟。", "琼枝玉树频相见。", "只恨离人远。", "欲将幽事寄青楼。", "争奈无情江水、不西流。"]'),
('song-ci-796','虞美人','秦观','宋','宋词','song-ci','虞美人','[]','碧桃天上栽和露。',66,'宋词/ci.song.3000.json','["碧桃天上栽和露。", "不是凡花数。", "乱山深处水潆回。", "可惜一枝如画、为谁开。", "轻寒细雨情何限。", "不道春难管。", "为君沈醉又何妨。", "祗怕酒醒时候、断人肠。"]'),
('song-ci-797','虞美人','秦观','宋','宋词','song-ci','虞美人','[]','行行信马横塘畔。',66,'宋词/ci.song.3000.json','["行行信马横塘畔。", "烟水秋平岸。", "绿荷多少夕阳中。", "知为阿谁凝恨、背西风。", "红妆艇子来何处。", "荡桨偷相顾。", "鸳鸯惊起不无愁。", "柳外一双飞去、却回头。"]'),
('song-ci-798','点绛唇','秦观','宋','宋词','song-ci','点绛唇','[]','醉漾轻舟，信流引到花深处。',50,'宋词/ci.song.3000.json','["醉漾轻舟，信流引到花深处。", "尘缘相误。", "无计花间住。", "烟水茫茫，千里斜阳暮。", "山无数。", "乱红如雨。", "不记来时路。"]'),
('song-ci-799','点绛唇','秦观','宋','宋词','song-ci','点绛唇','[]','月转乌啼，画堂宫徵生离恨。',50,'宋词/ci.song.3000.json','["月转乌啼，画堂宫徵生离恨。", "美人愁闷。", "不管罗衣褪。", "清泪斑斑，挥断柔肠寸。", "嗔人问。", "背灯偷搵。", "拭尽残妆粉。"]'),
('song-ci-800','品令','秦观','宋','宋词','song-ci','品令','[]','幸自得。',62,'宋词/ci.song.3000.json','["幸自得。", "一分索强，教人难吃。", "好好地恶了十来日。", "恰而今、较些不。", "须管啜持教笑，又也何须肐织。", "衠倚赖脸儿得人惜。", "放软顽、道不得。"]'),
('song-ci-801','品令','秦观','宋','宋词','song-ci','品令','[]','掉又惧。',63,'宋词/ci.song.3000.json','["掉又惧。", "天然个品格。", "於中压一。", "帘儿下时把鞋儿踢。", "语低低、笑咭咭。", "每每秦楼相见，见了无限怜惜。", "人前强不欲相沾识。", "把不定、脸儿赤。"]'),
('song-ci-802','南歌子','秦观','宋','宋词','song-ci','南歌子','[]','玉漏迢迢尽，银潢淡淡横。',62,'宋词/ci.song.3000.json','["玉漏迢迢尽，银潢淡淡横。", "梦回宿酒未全醒。", "已被邻鸡催起、怕天明。", "臂上妆犹在，襟间泪尚盈。", "水边灯火渐人行。", "天外一钩残月、带三星。"]'),
('song-ci-803','南歌子','秦观','宋','宋词','song-ci','南歌子','[]','愁鬓香云坠，娇眸水玉裁。',62,'宋词/ci.song.3000.json','["愁鬓香云坠，娇眸水玉裁。", "月屏风幌为谁开。", "天外不知音耗、百般猜。", "玉露沾庭砌，金风动琯灰。", "相看有似梦初回。", "只恐又抛人去、几时来。"]'),
('song-ci-804','南歌子','秦观','宋','宋词','song-ci','南歌子','[]','香墨弯弯画，燕脂淡淡匀。',62,'宋词/ci.song.3000.json','["香墨弯弯画，燕脂淡淡匀。", "揉蓝衫子杏黄裙。", "独倚玉阑无语、点檀唇。", "人去空流水，花飞半掩门。", "乱山何处觅行云。", "又是一钩新月、照黄昏。"]'),
('song-ci-805','临江仙','秦观','宋','宋词','song-ci','临江仙','[]','千里潇湘挼蓝浦，蓝桡昔日曾经。',70,'宋词/ci.song.3000.json','["千里潇湘挼蓝浦，蓝桡昔日曾经。", "月高风定露华清。", "微波澄不动，冷浸一天星。", "独倚危樯情悄悄，遥闻妃瑟泠泠。", "新声寒尽古今情。", "曲终人不见，江上数峰青。"]'),
('song-ci-806','临江仙','秦观','宋','宋词','song-ci','临江仙','[]','髻子偎人娇不整，眼儿失睡微重。',68,'宋词/ci.song.3000.json','["髻子偎人娇不整，眼儿失睡微重。", "寻思模样早心忪。", "断肠携手，何事太匆匆。", "不忍残红犹在臂，翻疑梦里相逢。", "遥怜南埭上孤篷。", "夕阳流水，红满泪痕中。"]'),
('song-ci-807','好事近','秦观','宋','宋词','song-ci','好事近','[]','春路雨添花，花动一山春色。',53,'宋词/ci.song.3000.json','["春路雨添花，花动一山春色。", "行到小溪深处，有黄鹂千百。", "飞云当面化龙蛇，夭矫转空碧。", "醉卧古藤阴下，了不知南北。"]'),
('song-ci-808','失调名','秦观','宋','宋词','song-ci','失调名','[]','我会从事风流府。',8,'宋词/ci.song.3000.json','["我会从事风流府。"]'),
('song-ci-809','添春色・醉乡春','秦观','宋','宋词','song-ci','添春色・醉乡春','[]','唤起一声人悄。',59,'宋词/ci.song.3000.json','["唤起一声人悄。", "衾冷梦寒窗晓。", "瘴雨过，海棠晴，春色又添多少。", "社瓮酿成微笑。", "半缺瘿瓢共舀。", "觉健倒，急投床，醉乡广大人间小。"]'),
('song-ci-810','南柯子・南歌子','秦观','宋','宋词','song-ci','南柯子・南歌子','[]','霭霭迷春态，溶溶媚晓光。',62,'宋词/ci.song.3000.json','["霭霭迷春态，溶溶媚晓光。", "不应容易下巫阳。", "祗恐翰林前世、是襄王。", "暂为清歌驻，还因暮雨忙。", "瞥然飞去断人肠。", "空使兰台公子、赋高唐。"]'),
('song-ci-811','失调名','秦观','宋','宋词','song-ci','失调名','[]','天若有情，天也为人烦恼。',12,'宋词/ci.song.3000.json','["天若有情，天也为人烦恼。"]'),
('song-ci-812','失调名','秦观','宋','宋词','song-ci','失调名','[]','粽团桃柳，盈门共垒，把菖蒲、旋刻个人人。',20,'宋词/ci.song.3000.json','["粽团桃柳，盈门共垒，把菖蒲、旋刻个人人。"]'),
('song-ci-813','画堂春','秦观','宋','宋词','song-ci','画堂春','[]','东风吹柳日初长。',55,'宋词/ci.song.3000.json','["东风吹柳日初长。", "雨馀芳草斜阳。", "杏花零落燕泥香。", "睡损红妆。", "香篆暗消鸾凤，画屏萦绕潇湘。", "暮寒轻透薄罗裳。", "无限思量。"]'),
('song-ci-814','木兰花慢','秦观','宋','宋词','song-ci','木兰花慢','[]','过秦淮旷望，回萧洒、绝纤尘。',122,'宋词/ci.song.3000.json','["过秦淮旷望，回萧洒、绝纤尘。", "爱清景风蛩，吟鞭醉帽，时度疏林。", "秋来政情味淡，更一重烟水一重云。", "千古行人旧恨，尽应分付今人。", "渔村。", "望断横门。", "芦荻浦、雁先闻。", "对触目凄凉，红凋岸蓼，翠减汀苹。", "凭高正千嶂暗，便无情到此也销魂。", "江月知人念远，上楼来照黄昏。"]'),
('song-ci-815','御街行','秦观','宋','宋词','song-ci','御街行','[]','银烛生花如红豆。',98,'宋词/ci.song.3000.json','["银烛生花如红豆。", "这好事、而今有。", "夜阑人静曲屏深，借宝瑟、轻轻招手。", "一阵白苹风，故灭烛、教相就。", "花带雨、冰肌香透。", "恨啼鸟、辘轳声晓。", "岸柳微风吹残酒。", "断肠时、至今依旧。", "镜中消瘦。", "那人知后，怕你来僝僽。"]'),
('song-ci-816','青门饮','秦观','宋','宋词','song-ci','青门饮','[]','风起云间，雁横天末，严城画角，梅花三奏。',130,'宋词/ci.song.3000.json','["风起云间，雁横天末，严城画角，梅花三奏。", "塞草西风，冻云笼月，窗外晓寒轻透。", "人去香犹在，孤衾长闲馀绣。", "恨与宵长，一夜薰炉，添尽香兽。", "前事空劳回首。", "虽梦断春归，相思依旧。", "湘瑟声沈，庾梅信断，谁念画眉人瘦。", "一句难忘处，怎忍辜、耳边轻咒。", "任人攀折，可怜又学，章台杨柳。"]'),
('song-ci-817','夜游宫','秦观','宋','宋词','song-ci','夜游宫','[]','何事东君又去。',71,'宋词/ci.song.3000.json','["何事东君又去。", "空满院、落花飞絮。", "巧燕昵喃向谁语。", "何曾解、说伊家、些子苦。", "况是伤心绪。", "念个人、又成睽阻。", "一觉相思梦回处。", "连宵雨、更那堪、闻杜宇。"]'),
('song-ci-818','醉蓬莱','秦观','宋','宋词','song-ci','醉蓬莱','[]','见扬州独有，天下无双，号为琼树。',120,'宋词/ci.song.3000.json','["见扬州独有，天下无双，号为琼树。", "占断天风，岁花开两次。", "九朵一苞，攒成环玉，心似珠玑缀。", "瓣瓣玲珑，枝枝洁净，世上无花类。", "冷露朝凝，香风远送，信是琼瑶贵。", "料得天宫有，此地久难留住。", "翰苑才人，贵家公子，都要看花去。", "莫吝金钱，好寻诗伴，日日花前醉。"]'),
('song-ci-819','满江红','秦观','宋','宋词','song-ci','满江红','[]','越艳风流，占天上、人间第一。',116,'宋词/ci.song.3000.json','["越艳风流，占天上、人间第一。", "须信道、绝尘标致，倾城颜色。", "翠绾垂螺双髻小，柳柔花媚娇无力。", "笑从来、到处只闻名，今相识。", "脸儿美，鞋儿窄。", "玉纤嫩，酥胸白。", "自觉愁肠搅乱，坐中狂客。", "金缕和杯曾有分，宝钗落枕知何日。", "谩从今、一点在心头，空成忆。"]'),
('song-ci-820','一斛珠','秦观','宋','宋词','song-ci','一斛珠','[]','碧云寥廓。',67,'宋词/ci.song.3000.json','["碧云寥廓。", "倚阑怅望情离索。", "悲秋自怯罗衣薄。", "晓镜空悬，懒把青丝掠。", "江山满眼今非昨。", "纷纷木叶风中落。", "别巢燕子辞帘幕。", "有意东君，故把红丝缚。"]'),
('song-ci-821','西江月','米芾','宋','宋词','song-ci','西江月','[]','溪面荷香粲粲，林端远岫青青。',58,'宋词/ci.song.3000.json','["溪面荷香粲粲，林端远岫青青。", "楚天秋色太多情。", "云卷烟收风定。", "夜静冰娥欲上，梦回醉眼初醒。", "玉瓶未耻有新声。", "一曲请君来听。"]'),
('song-ci-822','菩萨蛮','米芾','宋','宋词','song-ci','菩萨蛮','[]','蒹葭风外烟笼柳。',52,'宋词/ci.song.3000.json','["蒹葭风外烟笼柳。", "数叠遥山眉黛秀。", "微雨过江来。", "烦襟为一开。", "沙边临望处。", "紫燕双飞语。", "举酒送飞云。", "夜凉愁梦频。"]'),
('song-ci-823','水调歌头','米芾','宋','宋词','song-ci','水调歌头','[]','砧声送风急，蟋蟀思高秋。',114,'宋词/ci.song.3000.json','["砧声送风急，蟋蟀思高秋。", "我来对景，不学宋玉解悲愁。", "收拾凄凉兴况，分付尊中醽醁，倍觉不胜幽。", "自有多情处，明月挂南楼。", "怅襟怀，横玉笛，韵悠悠。", "清时良夜，借我此地倒金瓯。", "可爱一天风物，遍倚阑干十二，宇宙若萍浮。", "醉困不知醒，敧枕卧江流。"]'),
('song-ci-824','渔家傲','米芾','宋','宋词','song-ci','渔家傲','[]','昔日丹阳行乐里。',72,'宋词/ci.song.3000.json','["昔日丹阳行乐里。", "紫金浮玉临无地。", "宝阁化成弥勒世。", "龙宫对。", "时时更有天花坠。", "浩渺一天秋水至。", "鲸鲵鼓鬣连山沸。", "员峤岱舆更贔屓。", "无根蒂。", "莫教龙伯邦人戏。"]'),
('song-ci-825','丑奴儿・采桑子','米芾','宋','宋词','song-ci','丑奴儿・采桑子','[]','踯蹰山下濡须水，我更委佗。',52,'宋词/ci.song.3000.json','["踯蹰山下濡须水，我更委佗。", "物阜时和。", "迨暇相逢笑复歌。", "江湖楼上凭阑久，极目沧波。", "天鉴如磨。", "偏映华簪雪一窝。"]'),
('song-ci-826','减字木兰花','米芾','宋','宋词','song-ci','减字木兰花','[]','云间皓月。',52,'宋词/ci.song.3000.json','["云间皓月。", "光照银淮来万折。", "海岱楼中。", "拂袖雄披楚岸风。", "醉馀清夜。", "羽扇纶巾人入画。", "江远淮长。", "举首宗英醒更狂。"]'),
('song-ci-827','减字木兰花','米芾','宋','宋词','song-ci','减字木兰花','[]','平生真赏。',52,'宋词/ci.song.3000.json','["平生真赏。", "纸上龙蛇三五行。", "富贵功名。", "老境谁堪宠辱惊。", "寸心谁语。", "只有当年袁与许。", "归到寥阳。", "玉简霞衣侍帝旁。"]'),
('song-ci-828','点绛唇','米芾','宋','宋词','song-ci','点绛唇','[]','莘野寥寥，渭滨漠漠情何限。',50,'宋词/ci.song.3000.json','["莘野寥寥，渭滨漠漠情何限。", "万重堆案。", "懒更重经眼。", "儿辈休惊，头上霜华满。", "功名晚。", "水云萧散。", "漫就驿亭看。"]'),
('song-ci-829','阮郎归','米芾','宋','宋词','song-ci','阮郎归','[]','双双鸳鸯戏苹洲。',56,'宋词/ci.song.3000.json','["双双鸳鸯戏苹洲。", "几行烟柳柔。", "一声长笛咽清秋。", "碧云生暮愁。", "钩月挂，绮霞收。", "浦南人泛舟。", "娟娟何处烛明眸。", "相望徒倚楼。"]'),
('song-ci-830','蝶恋花','米芾','宋','宋词','song-ci','蝶恋花','[]','千古涟漪清绝地。',70,'宋词/ci.song.3000.json','["千古涟漪清绝地。", "海岱楼高，下瞰秦淮尾。", "水浸碧天天似水。", "广寒宫阙人间世。", "霭霭春和生海市。", "鳌戴三山，顷刻随轮至。", "宝月圆时多异气。", "夜光一颗千金贵。"]'),
('song-ci-831','诉衷情','米芾','宋','宋词','song-ci','诉衷情','[]','薰风吹动满池莲。',54,'宋词/ci.song.3000.json','["薰风吹动满池莲。", "晓云楼阁鲜。", "绣阁华堂嘉会，齐拜玉炉烟。", "斟美酒，奉觥船。", "祝芳筵。", "宜春耐夏，多福壮严，富贵长年。"]'),
('song-ci-832','诉衷情','米芾','宋','宋词','song-ci','诉衷情','[]','劳生奔走困粗官。',54,'宋词/ci.song.3000.json','["劳生奔走困粗官。", "揽镜鬓毛斑。", "物外平生萧散，微宦兴阑珊。", "奇胜处，每平阑。", "定望远。", "好山如画，水绕云萦，无计成闲。"]'),
('song-ci-833','鹧鸪天','米芾','宋','宋词','song-ci','鹧鸪天','[]','暖日晴烘候小春。',64,'宋词/ci.song.3000.json','["暖日晴烘候小春。", "际天和气与精神。", "灵台静养千年寿，丹灶全无一点尘。", "寿彭祖，寿广成。", "华阳仙裔是今身。", "夜来银汉清如洗，南极星中见老人。"]'),
('song-ci-834','鹧鸪天','米芾','宋','宋词','song-ci','鹧鸪天','[]','云液无声白似银。',64,'宋词/ci.song.3000.json','["云液无声白似银。", "红霞一抹百花新。", "觞多莫压频频劝，一片花飞减却春。", "蜂翅乱，蝶眉颦。", "花间啼鸟劝游人。", "人生无事须行乐，富贵何时且健身。"]'),
('song-ci-835','浪淘沙','米芾','宋','宋词','song-ci','浪淘沙','[]','祝寿庆生申。',64,'宋词/ci.song.3000.json','["祝寿庆生申。", "德日维新。", "期颐眉寿寿长春。", "五福三灵禄永永，长寿仙人。", "遐算等庄椿。", "□德康宁。", "年年欢会笑欣欣。", "岁岁仰依□寿域，彭祖广成。"]'),
('song-ci-836','浣溪沙','米芾','宋','宋词','song-ci','浣溪沙','[]','日射平溪玉宇中。',48,'宋词/ci.song.3000.json','["日射平溪玉宇中。", "云横远渚岫重重。", "野花犹向涧边红。", "静看沙头鱼入网，闲支藜杖醉吟风。", "小春天气恼人浓。"]'),
('song-ci-837','醉太平','米芾','宋','宋词','song-ci','醉太平','[]','风炉煮茶。',46,'宋词/ci.song.3000.json','["风炉煮茶。", "霜刀剖瓜。", "暗香微透窗纱。", "是池中藕花。", "高梳髻鸦。", "浓妆脸霞。", "玉尖弹动琵琶。", "问香醪饮麽。"]'),
('song-ci-838','望云涯引','李甲','宋','宋词','song-ci','望云涯引','[]','秋容江上，岸花老，苹洲白。',98,'宋词/ci.song.3000.json','["秋容江上，岸花老，苹洲白。", "露湿蒹葭，浦屿渐增寒色。", "闲渔唱晚，鹜雁惊飞处，映远碛。", "数点轻帆，送天际归客。", "凤台人散，漫回首。", "沈消息。", "素鲤无凭，楼上暮云凝碧。", "时向西风下，认远笛。", "宋玉悲怀，未信金樽消得。"]'),
('song-ci-839','吊严陵','李甲','宋','宋词','song-ci','吊严陵','[]','蕙兰香泛，孤屿潮平，惊鸥散雪。',143,'宋词/ci.song.3000.json','["蕙兰香泛，孤屿潮平，惊鸥散雪。", "迤逦点破，澄江秋色。", "暝霭向敛，疏雨乍收，染出蓝峰千尺。", "渔舍孤烟锁寒碛。", "画鹢翠帆旋解，轻舣晴霞岸侧。", "正念往悲酸，怀乡惨切。", "何处引羌笛。", "追惜。", "当时富春佳地，严光钓址空遗迹。", "华星沈后，扁舟泛去，萧洒闲名图籍。", "离觞吊终寓目，意断魂消泪滴。", "渐洞天晚，回首暮云千古碧。"]'),
('song-ci-840','梦玉人引','李甲','宋','宋词','song-ci','梦玉人引','[]','渐东风暖，陇梅残，霁云碧。',103,'宋词/ci.song.3000.json','["渐东风暖，陇梅残，霁云碧。", "嫩草柔条，又回江城春色。", "乍促银签，便篆香纹蜡有馀迹。", "愁梦相兼，尽日高无力。", "这些离恨，依然是、酒醒又如织。", "料伊怀情，也应向人端的。", "何故近日，全然无消息。", "问伊看，伊教人到此，如何休得。"]'),
('song-ci-841','过秦楼','李甲','宋','宋词','song-ci','过秦楼','[]','卖酒炉边，寻芳原上，乱花飞絮悠悠。',134,'宋词/ci.song.3000.json','["卖酒炉边，寻芳原上，乱花飞絮悠悠。", "已蝶稀莺散，便拟把长绳、系日无由。", "谩道草忘忧。", "也徒将，酒解闲愁。", "正江南春尽，行人千里，苹满汀洲。", "有翠红径里，盈盈似簇，芳茵禊饮，时笑时讴。", "当暖风迟景，任相将永日，烂熳狂游。", "谁信盛狂中，有离情、忽到心头。", "向尊前拟问，双燕来时，曾过秦楼。"]'),
('song-ci-842','帝台春','李甲','宋','宋词','song-ci','帝台春','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','芳草碧色，萋萋遍南陌。',122,'宋词/ci.song.3000.json','["芳草碧色，萋萋遍南陌。", "暖絮乱红，也知人、春愁无力。", "忆得盈盈拾翠侣，共携赏、凤城寒食。", "到今来，海角逢春，天涯为客。", "愁旋释。", "还似织。", "泪暗拭。", "又偷滴。", "谩伫立、遍倚危阑，尽黄昏，也只是、暮云凝碧。", "拼则而已今拼了，忘则怎生便忘得。", "又还问鳞鸿，试重寻消息。"]'),
('song-ci-843','击梧桐','李甲','宋','宋词','song-ci','击梧桐','[]','杳杳春江阔。',135,'宋词/ci.song.3000.json','["杳杳春江阔。", "收细雨、风蹙波声无歇。", "雁去汀洲暖，岸芜静，翠染遥山一抹。", "群鸥聚散，征航来去，隔水相望楚越。", "对此、凝情久，念往岁上国，嬉游时节。", "斗草园林，卖花巷陌，触处风光奇绝。", "正恁浓欢里，悄不意、顿有天涯离别。", "看那梅生翠实，柳飘狂絮，没个人共折。", "把而今、愁烦滋味，教向谁说。"]'),
('song-ci-844','幔卷绸・慢卷绸','李甲','宋','宋词','song-ci','幔卷绸・慢卷绸','[]','绝羽沈鳞，埋花葬玉，杳杳悲前事。',137,'宋词/ci.song.3000.json','["绝羽沈鳞，埋花葬玉，杳杳悲前事。", "对一盏寒灯，数点流萤，悄悄画屏，巫山十二。", "蕣脸星眸，蕙情兰性，一旦成流水。", "便纵有、甘泉妙手，洪都方士何济。", "香闺宝砌。", "临妆处，迤逦苔痕翠。", "更不忍看伊，绣残鸳侣，而今尚有，啼红粉渍。", "好梦不来，断云飞去，黯黯情无际。", "谩饮尽香醪，奈向愁肠，消遣无计。"]'),
('song-ci-845','望春回','李甲','宋','宋词','song-ci','望春回','[]','霁霞散晓，射水村渐明，渔火方绝。',123,'宋词/ci.song.3000.json','["霁霞散晓，射水村渐明，渔火方绝。", "滩露夜潮痕，注冻濑凄咽。", "征鸿来时应负书，见疏柳、更忆伊同折。", "异乡憔悴，那堪更逢，岁穷时节。", "东风暗回暖律。", "算拆遍江梅，消尽岩雪。", "唯有这愁肠，也依旧千结。", "私言窃语些誓约，便眠思梦想无休歇。", "这些离恨，除非对著、说似明月。"]'),
('song-ci-846','少年游','李甲','宋','宋词','song-ci','少年游','[]','江国陆郎封寄后，独自冠群芳。',60,'宋词/ci.song.3000.json','["江国陆郎封寄后，独自冠群芳。", "折时雪里，带时灯下，香面讶争光。", "而今不怕吹羌管，一任更繁霜。", "玳筵赏处，玉纤整后，犹胜岭头香。"]'),
('song-ci-847','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','丽质仙娥生月殿。',70,'宋词/ci.song.3000.json','["丽质仙娥生月殿。", "谪向人间，未免凡情乱。", "宋玉墙东流美盼。", "乱花深处曾相见。", "密意浓欢方有便。", "不奈浮名，旋遣轻分散。", "最恨多才情太浅。", "等闲不念离人怨。"]'),
('song-ci-848','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','锦额重帘深几许。',70,'宋词/ci.song.3000.json','["锦额重帘深几许。", "绣履弯弯，未省离朱户。", "强出娇羞都不语。", "绛绡频掩酥胸素。", "黛浅愁红妆淡伫。", "怨绝情凝，不肯聊回顾。", "媚脸未匀新泪污。", "梅英犹带春朝露。"]'),
('song-ci-849','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','懊恼娇痴情未惯。',70,'宋词/ci.song.3000.json','["懊恼娇痴情未惯。", "不道看看，役得人肠断。", "万语千言都不管。", "兰房跬步如天远。", "废寝忘餐思想遍。", "赖有青鸾，不必凭鱼雁。", "密写香笺论缱绻。", "春词一纸芳心乱。"]'),
('song-ci-850','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','庭院黄昏春雨霁。',70,'宋词/ci.song.3000.json','["庭院黄昏春雨霁。", "一缕深心，百种成牵系。", "青翼蓦然来报喜。", "鱼笺微谕相容意。", "待月西厢人不寐。", "帘影摇光，朱户犹慵闭。", "花动拂墙红萼坠。", "分明疑是情人至。"]'),
('song-ci-851','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','屈指幽期惟恐误。',70,'宋词/ci.song.3000.json','["屈指幽期惟恐误。", "恰到春宵，明月当三五。", "红影压墙花密处。", "花阴便是桃源路。", "不谓兰诚金石固。", "敛袂怡声，恣把多才数。", "惆怅空回谁共语。", "只应化作朝云去。"]'),
('song-ci-852','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','数夕孤眠如度岁。',70,'宋词/ci.song.3000.json','["数夕孤眠如度岁。", "将谓今生，会合终无计。", "正是断肠凝望际。", "云心捧得嫦娥至。", "玉困花柔羞抆泪。", "端丽妖娆，不与前时比。", "人去月斜疑梦寐。", "衣香犹在妆留臂。"]'),
('song-ci-853','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','一梦行云还暂阻。',70,'宋词/ci.song.3000.json','["一梦行云还暂阻。", "尽把深诚，缀作新诗句。", "幸有青鸾堪密付。", "良宵从此无虚度。", "两意相欢朝又暮。", "争奈郎鞭，暂指长安路。", "最是动人愁怨处。", "离情盈抱终无语。"]'),
('song-ci-854','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','碧沼鸳鸯交颈舞。',70,'宋词/ci.song.3000.json','["碧沼鸳鸯交颈舞。", "正恁双栖，又遣分飞去。", "洒翰赠言终不许。", "援琴请尽奴衷素。", "曲未成声先怨慕。", "忍泪凝情，强作霓裳序。", "弹到离愁凄咽处。", "弦肠俱断梨花雨。"]'),
('song-ci-855','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','别后相思心目乱。',70,'宋词/ci.song.3000.json','["别后相思心目乱。", "不谓芳音，忽寄南来雁。", "却写花笺和泪卷。", "细书方寸教伊看。", "独寐良宵无计遣。", "梦里依稀，暂若寻常见。", "幽会未终魂已断。", "半衾如暖人犹远。"]'),
('song-ci-856','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','尺素重重封锦字。',70,'宋词/ci.song.3000.json','["尺素重重封锦字。", "未尽幽闺，别后心中事。", "佩玉采丝文竹器。", "愿君一见知深意。", "环玉长圆丝万系。", "竹上斓斑，总是相思泪。", "物会见郎人永弃。", "心驰魂去神千里。"]'),
('song-ci-857','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','梦觉高唐云雨散。',70,'宋词/ci.song.3000.json','["梦觉高唐云雨散。", "十二巫峰，隔断相思眼。", "不为旁人移步懒。", "为郎憔悴羞郎见。", "青翼不来孤凤怨。", "露失桃源，再会终无便。", "旧恨新愁无计遣。", "情深何似情俱浅。"]'),
('song-ci-858','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','镜破人离何处问。',70,'宋词/ci.song.3000.json','["镜破人离何处问。", "路隔银河，岁会知犹近。", "只道新来消瘦损。", "玉容不见空传信。", "弃掷前欢俱未忍。", "岂料盟言，陡顿无凭准。", "地久天长终有尽，绵绵不似无穷恨。"]'),
('song-ci-859','天仙子','赵令畤','宋','宋词','song-ci','天仙子','[]','宿雨洗空台榭莹。',80,'宋词/ci.song.3000.json','["宿雨洗空台榭莹。", "下尽珠帘寒未定。", "花开花落几番晴，春欲竟。", "愁未醒。", "池面杏花红透影。", "一纸短书言不尽。", "明月清风还记省。", "玉楼香断又天香，闲展兴。", "临好景。", "心似乱萍何处整。"]'),
('song-ci-860','浣溪沙','赵令畤','宋','宋词','song-ci','浣溪沙','[]','稳小弓鞋三寸罗。',48,'宋词/ci.song.3000.json','["稳小弓鞋三寸罗。", "歌唇清韵一樱多。", "灯前秀艳总横波。", "指下鸣泉清杳渺，掌中回旋小婆娑。", "明朝归路奈情何。"]'),
('song-ci-861','菩萨蛮','赵令畤','宋','宋词','song-ci','菩萨蛮','[]','轻鸥欲下春塘浴。',52,'宋词/ci.song.3000.json','["轻鸥欲下春塘浴。", "双双飞破春烟绿。", "两岸野蔷薇。", "翠笼薰绣衣。", "凭船闲弄水。", "中有相思意。", "忆得去年时。", "水边初别离。"]'),
('song-ci-862','菩萨蛮','赵令畤','宋','宋词','song-ci','菩萨蛮','[]','长淮渺渺寒烟白。',52,'宋词/ci.song.3000.json','["长淮渺渺寒烟白。", "凭阑人是霜台客。", "诗句妙春豪。", "风云不啻高。", "樽前人已老。", "馀恨连芳草。", "一曲酒醒时。", "梧桐月欲低。"]'),
('song-ci-863','菩萨蛮','赵令畤','宋','宋词','song-ci','菩萨蛮','[]','春风试手先梅蕊。',52,'宋词/ci.song.3000.json','["春风试手先梅蕊。", "頩姿冷艳明沙水。", "不受众芳知。", "端须月与期。", "清香闲自远。", "先向钗头见。", "雪后燕瑶池。", "人间第一枝。"]'),
('song-ci-864','好事近','赵令畤','宋','宋词','song-ci','好事近','[]','急雨涨溪浑，小树带山秋色。',53,'宋词/ci.song.3000.json','["急雨涨溪浑，小树带山秋色。", "轻棹暮天归路，袅芙蓉烟白。", "酒醒香冷梦回时，虫声正凄绝。", "只觉小窗风月，与昨宵都别。"]'),
('song-ci-865','小重山','赵令畤','宋','宋词','song-ci','小重山','[]','楼上风和玉漏迟。',70,'宋词/ci.song.3000.json','["楼上风和玉漏迟。", "秋千庭院静，百花飞。", "午窗才起暖金卮。", "匀面了，阑畔看春池。", "何事苦颦眉。", "碧云春信断，尽来时。", "鸳鸯游戏镇相随。", "云雾敛，新月挂天西。"]'),
('song-ci-866','小重山','赵令畤','宋','宋词','song-ci','小重山','[]','雨霁风高天气清。',70,'宋词/ci.song.3000.json','["雨霁风高天气清。", "玉盘浮出海，转空明。", "小窗帘影冷如冰。", "愁不寐，独自傍阶行。", "情似浪头轻。", "一番销欲尽，一番生。", "无言惆怅到参横。", "人欲起，鹎鵊几声鸣。"]'),
('song-ci-867','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','欲减罗衣寒未去。',70,'宋词/ci.song.3000.json','["欲减罗衣寒未去。", "不卷珠帘，人在深深处。", "红杏枝头花几许。", "啼痕止恨清明雨。", "尽日沈烟香一缕。", "宿酒醒迟，恼破春情绪。", "飞燕又将归信误。", "小屏风上西江路。"]'),
('song-ci-868','蝶恋花','赵令畤','宋','宋词','song-ci','蝶恋花','[]','卷絮风头寒欲尽。',70,'宋词/ci.song.3000.json','["卷絮风头寒欲尽。", "坠粉飘香，日日红成阵。", "新酒又添残酒困。", "今春不减前春恨。", "蝶去莺飞无处问。", "隔水高楼，望断双鱼信。", "恼乱横波秋一寸。", "斜阳只与黄昏近。"]'),
('song-ci-869','西江月','赵令畤','宋','宋词','song-ci','西江月','[]','人世一场大梦，我生魔了十年。',58,'宋词/ci.song.3000.json','["人世一场大梦，我生魔了十年。", "明窗千古探遗编。", "不救饥寒一点。", "更被维摩老子，不教此处容言。", "炉薰清炷坐安禅。", "物物头头显现。"]'),
('song-ci-870','满庭芳','赵令畤','宋','宋词','song-ci','满庭芳','[]','玉枕生凉，金缸传晓，败叶飞破清秋。',118,'宋词/ci.song.3000.json','["玉枕生凉，金缸传晓，败叶飞破清秋。", "雨馀翻浪，渺渺阻行舟。", "暂系汀洲侧畔，风夜起、荻叶添愁。", "银屏远，龙香渐尽，还是梦扬州。", "更筹。", "何太永，当年情事，今日堪酬。", "最苦恨红楼，笑我飘浮。", "为寄相思细字，教字字、愁蹙眉头。", "凄凉久，渔人唱晓，随月过横沟。"]'),
('song-ci-871','清平乐','赵令畤','宋','宋词','song-ci','清平乐','[]','春风依旧。',54,'宋词/ci.song.3000.json','["春风依旧。", "著意随堤柳。", "搓得蛾儿黄欲就。", "天气清明时候。", "去年紫陌青门。", "今霄雨魄云魂。", "断送一生憔悴，只销几个黄昏。"]'),
('song-ci-872','思远人','赵令畤','宋','宋词','song-ci','思远人','[]','素玉朝来有好怀。',64,'宋词/ci.song.3000.json','["素玉朝来有好怀。", "一枝梅粉照人开。", "晴云欲向杯中起，春色先从脸上来。", "深院落，小楼台。", "玉盘香篆看徘徊。", "须知月色撩人恨，数夜春寒不下阶。"]'),
('song-ci-873','临江仙','赵令畤','宋','宋词','song-ci','临江仙','[]','枝上粉香吹欲尽，依前庭院春风。',70,'宋词/ci.song.3000.json','["枝上粉香吹欲尽，依前庭院春风。", "更谁同绕摘芳丛。", "漏残金兽冷，信断锦屏空。", "看结灯花愁不睡，酒阑无梦相逢。", "凄凉长判一生中。", "不如云外月，永夜在房栊。"]'),
('song-ci-874','虞美人','赵令畤','宋','宋词','song-ci','虞美人','[]','画船稳泛春波渺。',66,'宋词/ci.song.3000.json','["画船稳泛春波渺。", "夕雨寒声小。", "紫烟深处数峰横。", "惊起一滩鸥鹭、照川明。", "西楼今夜归期误。", "恨入阑干暮。", "可堪春事满春怀。", "不似珠帘新燕、早归来。"]'),
('song-ci-875','浣溪沙','赵令畤','宋','宋词','song-ci','浣溪沙','[]','风急花飞昼掩门。',48,'宋词/ci.song.3000.json','["风急花飞昼掩门。", "一帘残雨滴黄昏。", "便无离恨也销魂。", "翠被任熏终不暖，玉杯慵举几番温。", "个般情事与谁论。"]'),
('song-ci-876','浣溪沙','赵令畤','宋','宋词','song-ci','浣溪沙','[]','槐柳春馀绿涨天。',48,'宋词/ci.song.3000.json','["槐柳春馀绿涨天。", "酒旗高插夕阳边。", "谁家墙里笑秋千。", "往事不堪楼上看，新愁多向曲中传。", "此情销得是何年。"]'),
('song-ci-877','浣溪沙','赵令畤','宋','宋词','song-ci','浣溪沙','[]','一朵梦云惊晓鸦。',48,'宋词/ci.song.3000.json','["一朵梦云惊晓鸦。", "数枝春雨带梨花。", "坐来残月冷窗纱。", "钗凤谩曾留得半，枕山犹是枕时斜。", "对花今日奈天涯。"]'),
('song-ci-878','浣溪沙','赵令畤','宋','宋词','song-ci','浣溪沙','[]','水满池塘花满枝。',48,'宋词/ci.song.3000.json','["水满池塘花满枝。", "乱香深里语黄鹂。", "东风轻软弄帘帏。", "日正长时春梦短，燕交飞处柳烟低。", "玉窗红子斗棋时。"]'),
('song-ci-879','浣溪沙','赵令畤','宋','宋词','song-ci','浣溪沙','[]','少日怀山老住山。',48,'宋词/ci.song.3000.json','["少日怀山老住山。", "一官休务得身闲。", "几年食息白云间。", "似我乐来真是少，见人忙处不相关。", "养真高静出尘寰。"]'),
('song-ci-880','鹧鸪天','赵令畤','宋','宋词','song-ci','鹧鸪天','[]','可是相逢意便深。',64,'宋词/ci.song.3000.json','["可是相逢意便深。", "为郎巧笑不须金。", "门前一尺春风髻，窗内三更夜雨衾。", "情渺渺，信沈沈。", "青莺无路寄芳音。", "山城钟鼓愁难听，不解襄王梦里寻。"]'),
('song-ci-881','鹧鸪天','赵令畤','宋','宋词','song-ci','鹧鸪天','[]','麝发雕炉小袖笼。',64,'宋词/ci.song.3000.json','["麝发雕炉小袖笼。", "天教我被此时同。", "橼经雪重香方满，菊到秋深色自浓。", "船槛内，月明中。", "插花归去莫匆匆。", "人生更在艰难内，胜事年来不易逢。"]'),
('song-ci-882','失调名','赵令畤','宋','宋词','song-ci','失调名','[]','脸薄难藏泪，眉长易觉愁。',12,'宋词/ci.song.3000.json','["脸薄难藏泪，眉长易觉愁。"]'),
('song-ci-883','临江仙','赵令畤','宋','宋词','song-ci','临江仙','[]','翠袖卷纱红映肉，无风玉骨生寒。',70,'宋词/ci.song.3000.json','["翠袖卷纱红映肉，无风玉骨生寒。", "可堪新晓雨初残。", "颦眉谁恼著，粉泪滴阑干。", "闻道谪仙歌妙语，新妆再发愁颜。", "雾帘云幕荐金盘。", "笔间长借句，直莫放春还。"]'),
('song-ci-884','乌夜啼','赵令畤','宋','宋词','song-ci','乌夜啼','[]','楼上萦帘弱絮，墙头凝月低花。',56,'宋词/ci.song.3000.json','["楼上萦帘弱絮，墙头凝月低花。", "年年春事关心事，肠断欲栖鸦。", "舞镜鸾衾翠减，啼珠凤蜡红斜。", "重门不锁相思梦，随意绕天涯。"]'),
('song-ci-885','天宁乐・金人捧露盘','贺铸','宋','宋词','song-ci','天宁乐・金人捧露盘','[]','斗储祥，虹流祉，兆黄虞。',104,'宋词/ci.song.3000.json','["斗储祥，虹流祉，兆黄虞。", "未□□、□圣真符。", "千龄叶应，九河清、神物出龟图。", "□□□□，□盛时、朝野欢娱。", "靡不覆，旋穹□，□□□，□坤舆。", "致万国、一变华胥。", "霞觞□□，□□□、□□□宸趋。", "五云长在，望子□、□□□□。"]'),
('song-ci-886','□□□・七娘子','贺铸','宋','宋词','song-ci','□□□・七娘子','[]','□波飞□□□向。',72,'宋词/ci.song.3000.json','["□波飞□□□向。", "□□□、□□□□样。", "拥鼻微吟，捋须遐想。", "□□□□□□上。", "会须加数□□酿。", "□□□、□□□□涨。", "美满孤帆，轻便双桨。", "中分□□□□往。"]'),
('song-ci-887','鸳鸯语・七娘子','贺铸','宋','宋词','song-ci','鸳鸯语・七娘子','[]','京江抵、海边吴楚。',73,'宋词/ci.song.3000.json','["京江抵、海边吴楚。", "铁瓮城、行胜无今古。", "北固陵高，西津横渡。", "几人携手分襟处。", "凄凉渌水桥南路。", "奈玉壶、难叩鸳鸯语。", "行雨行云，非花非雾。", "为谁来为谁还去。"]'),
('song-ci-888','璧月堂・小重山','贺铸','宋','宋词','song-ci','璧月堂・小重山','[]','梦草池南璧月堂。',70,'宋词/ci.song.3000.json','["梦草池南璧月堂。", "绿阴深蔽日，啭鹂黄。", "淡蛾轻鬓似宜妆。", "歌扇小，烟雨画潇湘。", "薄晚具兰汤。", "雪肌英粉腻，更生香。", "簟纹如水竟檀床。", "雕枕并，得意两鸳鸯。"]'),
('song-ci-889','群玉轩・小重山','贺铸','宋','宋词','song-ci','群玉轩・小重山','[]','群玉轩中迹已陈。',70,'宋词/ci.song.3000.json','["群玉轩中迹已陈。", "江南重喜见，广陵春。", "纤秾合度好腰身。", "歌水钓，清啭□□□。", "团扇掩樱唇。", "七双胡蝶子，表□□。", "□□□复旧东邻。", "风月夜，怜取眼前人。"]'),
('song-ci-890','□□□・小重山','贺铸','宋','宋词','song-ci','□□□・小重山','[]','隔水桃花□□□。',70,'宋词/ci.song.3000.json','["隔水桃花□□□。", "□□□□□，□□□。", "□妆飞鹊镜台前。", "□□□，□□□□□。", "□首已依然。", "断云疏雨后，更闻蝉。", "□□□叶付漪涟。", "驰寄与，人住玉溪边。"]'),
('song-ci-891','辨弦声・迎春乐','贺铸','宋','宋词','song-ci','辨弦声・迎春乐','[]','琼琼绝艺真无价。',63,'宋词/ci.song.3000.json','["琼琼绝艺真无价。", "指尖纤、态闲暇。", "几多方寸关情话。", "都付与、弦声写。", "三月十三寒食夜。", "映花月、絮风台榭。", "明月待欢来，久背面、秋千下。"]'),
('song-ci-892','攀鞍态・迎春乐','贺铸','宋','宋词','song-ci','攀鞍态・迎春乐','[]','逢迎一笑金难买。',63,'宋词/ci.song.3000.json','["逢迎一笑金难买。", "小樱唇、浅蛾黛。", "玉环风调依然在。", "想花下、攀鞍态。", "伫倚碧云如有待。", "望新月、为谁双拜。", "细语人不闻，微风动、罗裙带。"]'),
('song-ci-893','辟寒金・迎春乐','贺铸','宋','宋词','song-ci','辟寒金・迎春乐','[]','六华应腊妆吴苑。',63,'宋词/ci.song.3000.json','["六华应腊妆吴苑。", "小山堂、晚张燕。", "赏心不厌杯行缓。", "待月度、银河半。", "缥缈郢人歌已断。", "归路指、玉溪南馆。", "谁似辟寒金，聊借与、空床暖。"]'),
('song-ci-894','尔汝歌・清商怨','贺铸','宋','宋词','song-ci','尔汝歌・清商怨','[]','劳生羁宦未易处。',52,'宋词/ci.song.3000.json','["劳生羁宦未易处。", "赖醉□□□。", "白眼青天，忘形相尔汝。", "□□□□□□。", "□□□，送君南浦。", "雪暗沧江，□□□□□。"]'),
('song-ci-895','□□□・清商怨','贺铸','宋','宋词','song-ci','□□□・清商怨','[]','扬州商女□□□。',52,'宋词/ci.song.3000.json','["扬州商女□□□。", "□□□□□。", "□寄扁舟，江南湖北道。", "津头龙祠屡□。", "□信指、半春前到。", "笑倚危樯，朝来风色好。"]'),
('song-ci-896','半死桐・鹧鸪天','贺铸','宋','宋词','song-ci','半死桐・鹧鸪天','[]','重过阊门万事非。',64,'宋词/ci.song.3000.json','["重过阊门万事非。", "同来何事不同归。", "梧桐半死清霜后，头白鸳鸯失伴飞。", "原上草，露初晞。", "旧栖新垅两依依。", "空床卧听南窗雨，谁复挑灯夜补衣。"]'),
('song-ci-897','翦朝霞・鹧鸪天','贺铸','宋','宋词','song-ci','翦朝霞・鹧鸪天','[]','云弄轻阴谷雨乾。',64,'宋词/ci.song.3000.json','["云弄轻阴谷雨乾。", "半垂油幕护残寒。", "化工著意呈新巧，翦刻朝霞饤露盘。", "辉锦绣，掩芝兰。", "开元天宝盛长安。", "沈香亭子钩阑畔，偏得三郎带笑看。"]'),
('song-ci-898','避少年・鹧鸪天','贺铸','宋','宋词','song-ci','避少年・鹧鸪天','[]','谁爱松林水似天。',64,'宋词/ci.song.3000.json','["谁爱松林水似天。", "画船听雨奈无眠。", "清风明月休论价，卖与愁人直几钱。", "挥醉笔，扫吟笺。", "一时朋辈饮中仙。", "白头□□江湖上，袖手低回避少年。"]'),
('song-ci-899','□□□・鹧鸪天','贺铸','宋','宋词','song-ci','□□□・鹧鸪天','[]','留落吴门□□□。',64,'宋词/ci.song.3000.json','["留落吴门□□□。", "□□□□□□□。", "扁舟更入毗陵道，却□□□□□□。", "□□念，付清觞。", "樵青与我和沧浪。", "浮云□是无根物，南北东西不碍狂。"]'),
('song-ci-900','千叶莲・鹧鸪天','贺铸','宋','宋词','song-ci','千叶莲・鹧鸪天','["\u897f\u6e56"]','闻你侬嗟我更嗟。',64,'宋词/ci.song.3000.json','["闻你侬嗟我更嗟。", "春霜一夜扫秾华。", "永无清啭欺头管，赖有浓香著臂纱。", "侵海角，抵天涯。", "行云谁为不知家。", "秋风想见西湖上，化出白莲千叶花。"]'),
('song-ci-901','第一花・鹧鸪天','贺铸','宋','宋词','song-ci','第一花・鹧鸪天','[]','豆蔻梢头莫漫夸。',64,'宋词/ci.song.3000.json','["豆蔻梢头莫漫夸。", "春风十里旧繁华。", "金缕玉蕊皆殊艳，别有倾城第一花。", "春雀舫，紫云车。", "暗期归路指烟霞。", "无端却似堂前燕，飞入寻常百姓家。"]'),
