('song-ci-903','□□□・捣练子','贺铸','宋','宋词','song-ci','□□□・捣练子','[]','楼上鼓，转□□。',32,'宋词/ci.song.3000.json','["楼上鼓，转□□。", "□□□□□□□。", "思妇想无肠可断，□□□□□□□。"]'),
('song-ci-904','夜捣衣・捣练子','贺铸','宋','宋词','song-ci','夜捣衣・捣练子','[]','收锦字，下鸳机。',32,'宋词/ci.song.3000.json','["收锦字，下鸳机。", "净拂床砧夜捣衣。", "马上少年今健否，过瓜时见雁南归。"]'),
('song-ci-905','杵声齐・捣练子','贺铸','宋','宋词','song-ci','杵声齐・捣练子','[]','砧面莹，杵声齐。',32,'宋词/ci.song.3000.json','["砧面莹，杵声齐。", "捣就征衣泪墨题。", "寄到玉关应万里，戍人犹在玉关西。"]'),
('song-ci-906','夜如年・捣练子','贺铸','宋','宋词','song-ci','夜如年・捣练子','[]','斜月下，北风前。',32,'宋词/ci.song.3000.json','["斜月下，北风前。", "万杵千砧捣欲穿。", "不为捣衣勤不睡，破除今夜夜如年。"]'),
('song-ci-907','翦征袍・捣练子','贺铸','宋','宋词','song-ci','翦征袍・捣练子','[]','抛练杵，傍窗纱。',32,'宋词/ci.song.3000.json','["抛练杵，傍窗纱。", "巧翦征袍斗出花。", "想见陇头长戍客，授衣时节也思家。"]'),
('song-ci-908','望书归・捣练子','贺铸','宋','宋词','song-ci','望书归・捣练子','[]','边堠远，置邮稀。',32,'宋词/ci.song.3000.json','["边堠远，置邮稀。", "附与征衣衬铁衣。", "连夜不妨频梦见，过年惟望得书归。"]'),
('song-ci-909','醉厌厌・南歌子','贺铸','宋','宋词','song-ci','醉厌厌・南歌子','[]','紫陌青丝鞚，红尘白纻衫。',62,'宋词/ci.song.3000.json','["紫陌青丝鞚，红尘白纻衫。", "谁怜绣户闭香奁。", "分付一春心事、两眉尖。", "怯冷重熏被，羞明半卷帘。", "欢归斜□□□□。", "□□□□□□、醉厌厌。"]'),
('song-ci-910','窗下绣・一落萦','贺铸','宋','宋词','song-ci','窗下绣・一落萦','[]','初见碧纱窗下绣。',57,'宋词/ci.song.3000.json','["初见碧纱窗下绣。", "寸波频溜。", "错将黄晕压檀花，翠袖掩、纤纤手。", "金缕一双红豆。", "情通色授。", "不应学舞爱垂杨，甚长为、春风瘦。"]'),
('song-ci-911','艳声歌・添声杨柳枝','贺铸','宋','宋词','song-ci','艳声歌・添声杨柳枝','[]','蜀锦尘香生袜罗。',48,'宋词/ci.song.3000.json','["蜀锦尘香生袜罗。", "小婆娑。", "个侬无赖动人多。", "是横波。", "楼角云开风卷幕，月侵河。", "纤纤持酒艳声歌。", "奈情何。"]'),
('song-ci-912','唤春愁・添声杨柳枝','贺铸','宋','宋词','song-ci','唤春愁・添声杨柳枝','[]','天与多情不自由。',48,'宋词/ci.song.3000.json','["天与多情不自由。", "占风流。", "云闲草远絮悠悠。", "唤春愁。", "试作小妆窥晚镜，淡蛾羞。", "夕阳独倚水边楼。", "认归舟。"]'),
('song-ci-913','花幕暗・添声杨柳枝','贺铸','宋','宋词','song-ci','花幕暗・添声杨柳枝','[]','绿绮新声隔坐闻。',48,'宋词/ci.song.3000.json','["绿绮新声隔坐闻。", "认殷勤。", "尊前为舞郁金裙。", "酒微醺。", "月转参横花幕暗，夜初分。", "阳台拼作不归云。", "任郎嗔。"]'),
('song-ci-914','晚云高・添声杨柳枝','贺铸','宋','宋词','song-ci','晚云高・添声杨柳枝','[]','秋尽江南叶未凋。',48,'宋词/ci.song.3000.json','["秋尽江南叶未凋。", "晚云高。", "情山隐隐水迢迢。", "接亭皋。", "二十四桥明月夜，弭兰桡。", "玉人何处教吹箫。", "可怜宵。"]'),
('song-ci-915','钓船归・添声杨柳枝','贺铸','宋','宋词','song-ci','钓船归・添声杨柳枝','[]','绿净春深好染衣。',48,'宋词/ci.song.3000.json','["绿净春深好染衣。", "际柴扉。", "溶溶漾漾白鸥飞。", "两忘机。", "南去北来徒自老，故人稀。", "夕阳长送钓船归。", "鳜鱼肥。"]'),
('song-ci-916','爱孤云・添声杨柳枝','贺铸','宋','宋词','song-ci','爱孤云・添声杨柳枝','[]','闲爱孤云静爱僧。',48,'宋词/ci.song.3000.json','["闲爱孤云静爱僧。", "得良朋。", "清时有味是无能。", "矫聋丞。", "况复早年豪纵过，病婴仍。", "如今痴钝似寒蝇。", "醉懵腾。"]'),
('song-ci-917','替人愁・添声杨柳枝','贺铸','宋','宋词','song-ci','替人愁・添声杨柳枝','[]','风紧云轻欲变秋。',48,'宋词/ci.song.3000.json','["风紧云轻欲变秋。", "雨初收。", "江城水路漫悠悠。", "带汀洲。", "正是客心孤回处，转归舟。", "谁家红袖倚津楼。", "替人愁。"]'),
('song-ci-918','梦江南・忆江南','贺铸','宋','宋词','song-ci','梦江南・忆江南','[]','九曲池头三月三。',48,'宋词/ci.song.3000.json','["九曲池头三月三。", "柳毵毵。", "香尘扑马喷金衔。", "涴春衫。", "苦笋鲥鱼乡味美，梦江南。", "阊门烟水晚风恬。", "落归帆。"]'),
('song-ci-919','愁风月・生查子','贺铸','宋','宋词','song-ci','愁风月・生查子','[]','风清月正圆，信是佳时节。',48,'宋词/ci.song.3000.json','["风清月正圆，信是佳时节。", "不会长年来，处处愁风月。", "心将熏麝焦，吟伴寒虫切。", "欲遽就床眠，解带翻成结。"]'),
('song-ci-920','绿罗裙・生查子','贺铸','宋','宋词','song-ci','绿罗裙・生查子','[]','东风柳陌长，闭月花房小。',48,'宋词/ci.song.3000.json','["东风柳陌长，闭月花房小。", "应念画眉人，拂镜啼新晓。", "伤心南浦波，回首青门道。", "记得绿罗裙，处处怜芳草。"]'),
('song-ci-921','陌上郎・生查子','贺铸','宋','宋词','song-ci','陌上郎・生查子','[]','西津海鹘舟，径渡沧江雨。',48,'宋词/ci.song.3000.json','["西津海鹘舟，径渡沧江雨。", "双橹本无情，鸦轧如人语。", "挥金陌上郎，化石山头妇。", "何物系君心，三岁扶床女。"]'),
('song-ci-922','卷春空・定风波','贺铸','宋','宋词','song-ci','卷春空・定风波','[]','墙上夭桃簌簌红。',73,'宋词/ci.song.3000.json','["墙上夭桃簌簌红。", "巧随轻絮入帘栊。", "自是芳心贪结子。", "翻使。", "惜花人恨五更风。", "露萼鲜浓妆脸靓。", "相映。", "隔年情事此门中。", "粉面不知何处在。", "无奈。", "武陵流水卷春空。"]'),
('song-ci-923','桃源行・蝶恋花','贺铸','宋','宋词','song-ci','桃源行・蝶恋花','[]','流水长烟何缥缈。',70,'宋词/ci.song.3000.json','["流水长烟何缥缈。", "诘□□□，□逗渔舟小。", "夹岸桃花烂□□。", "□□□□□□□。", "萧闲村落田畴好。", "避地移家，□□□□□。", "□□殷勤送归棹。", "闲边勿为他人道。"]'),
('song-ci-924','西笑吟・蝶恋花','贺铸','宋','宋词','song-ci','西笑吟・蝶恋花','[]','桃叶园林风日好。',70,'宋词/ci.song.3000.json','["桃叶园林风日好。", "曲径珍丛，处处闻啼鸟。", "翠珥金丸委芳草。", "袜罗尘动香裙扫。", "片帆乘兴东流早。", "每话长安，引领犹西笑。", "离索年多故人少。", "江南有燕无书到。"]'),
('song-ci-925','望长安・蝶恋花','贺铸','宋','宋词','song-ci','望长安・蝶恋花','[]','排办张灯春事早。',70,'宋词/ci.song.3000.json','["排办张灯春事早。", "十二都门，物色宜新晓。", "金犊车轻玉骢小。", "拂头杨柳穿驰道。", "莼羹鲈鲙非吾好。", "去国讴吟，半落江南调。", "满眼青山恨西照。", "长安不见令人老。"]'),
('song-ci-926','呈纤手・玉楼春','贺铸','宋','宋词','song-ci','呈纤手・玉楼春','[]','秦弦络络呈纤手。',64,'宋词/ci.song.3000.json','["秦弦络络呈纤手。", "宝雁斜飞三十九。", "徵韶新谱日边来，倾耳吴娃惊未有。", "文园老令难堪酒。", "蜜炬垂花知夜久。", "更须妩媚做腰肢，细学永丰坊畔柳。"]'),
('song-ci-927','归风便・玉楼春','贺铸','宋','宋词','song-ci','归风便・玉楼春','[]','津亭薄晚张离燕。',64,'宋词/ci.song.3000.json','["津亭薄晚张离燕。", "红粉□歌持酒劝。", "歌声煎泪欲沾襟，酒色□□□□□。", "□□会有归风便。", "休道相忘秋后□。", "□□□抵故人心，惆怅故人心不见。"]'),
('song-ci-928','续渔歌・玉楼春','贺铸','宋','宋词','song-ci','续渔歌・玉楼春','[]','中年多办收身具。',64,'宋词/ci.song.3000.json','["中年多办收身具。", "投老归来无著处。", "四肢安稳一渔舟，祗许樵青相伴去。", "沧洲大胜黄尘路。", "万顷月波难滓污。", "阿侬原是个中人，非谓鲈鱼留不住。"]'),
('song-ci-929','惜馀春・踏莎行','贺铸','宋','宋词','song-ci','惜馀春・踏莎行','[]','急雨收春，斜风约水。',68,'宋词/ci.song.3000.json','["急雨收春，斜风约水。", "浮红涨绿鱼文起。", "年年有子惜馀春，春归不解招游子。", "留恨城隅，关情纸尾。", "阑干长对西曛倚。", "鸳鸯俱是白头时，江南渭北三千里。"]'),
('song-ci-930','题醉袖・踏莎行','贺铸','宋','宋词','song-ci','题醉袖・踏莎行','[]','浅黛宜颦，明波欲溜。',68,'宋词/ci.song.3000.json','["浅黛宜颦，明波欲溜。", "逢迎宛似平生旧。", "低鬟促坐认弦声，霞觞艳艳持为寿。", "浓染吟毫，偷题醉袖。", "寸心百意分携后。", "不胜风月两厌厌，年来一样伤春瘦。"]'),
('song-ci-931','阳羡歌・踏莎行','贺铸','宋','宋词','song-ci','阳羡歌・踏莎行','[]','山秀芙蓉，溪明罨画。',68,'宋词/ci.song.3000.json','["山秀芙蓉，溪明罨画。", "真游洞穴沧波下。", "临风慨想斩蛟灵，长桥千载犹横跨。", "解组投簪，求田问舍。", "黄鸡白酒渝樵社。", "元龙非复少时豪，耳根清静功名话。"]'),
('song-ci-932','芳心苦・踏莎行','贺铸','宋','宋词','song-ci','芳心苦・踏莎行','[]','杨柳回塘，鸳鸯别浦。',68,'宋词/ci.song.3000.json','["杨柳回塘，鸳鸯别浦。", "绿萍涨断莲舟路。", "断无蜂蝶慕幽香，红衣脱尽芳心苦。", "返照迎潮，行云带雨。", "依依伺与骚人语。", "当年不肯嫁春风，无端却被秋风误。"]'),
('song-ci-933','平阳兴・踏莎行','贺铸','宋','宋词','song-ci','平阳兴・踏莎行','[]','凉叶辞风，流云卷雨。',68,'宋词/ci.song.3000.json','["凉叶辞风，流云卷雨。", "寥寥夜色沈钟鼓。", "谁调清管度新声，有人高卧平阳坞。", "草暖沧洲，潮平别浦。", "双凫乘雁方容与。", "深藏华屋锁雕笼，此生乍可输鹦鹉。"]'),
('song-ci-934','晕眉山・踏莎行','贺铸','宋','宋词','song-ci','晕眉山・踏莎行','[]','镜晕眉山，囊熏水麝。',68,'宋词/ci.song.3000.json','["镜晕眉山，囊熏水麝。", "凝然风度长闲暇。", "归来定解鹔鹴裘，唤时应倍骅骝价。", "殢酒伤春，添香惜夜。", "依惜待月西厢下。", "梨花庭院雪玲珑，微吟独倚秋千架。"]'),
('song-ci-935','思牛女・踏莎行','贺铸','宋','宋词','song-ci','思牛女・踏莎行','[]','楼角参横，庭心月午。',68,'宋词/ci.song.3000.json','["楼角参横，庭心月午。", "侵阶夜色凉经雨。", "轻罗小扇扑流萤，微云渡汉思牛女。", "拥髻柔情，扶肩昵语。", "可怜分破□□□。", "□□□□有佳期。", "人间底事长如许。"]'),
('song-ci-936','负心期・浣溪沙','贺铸','宋','宋词','song-ci','负心期・浣溪沙','[]','节物侵寻迫暮迟。',56,'宋词/ci.song.3000.json','["节物侵寻迫暮迟。", "可胜摇落长年悲。", "回首五湖乘兴地，负心期。", "惊雁失行风翦翦，冷云成阵雪垂垂。", "不拼尊前泥样醉，个能痴。"]'),
('song-ci-937','醉中真・浣溪沙','贺铸','宋','宋词','song-ci','醉中真・浣溪沙','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','不信芳春厌老人。',48,'宋词/ci.song.3000.json','["不信芳春厌老人。", "老人几度送春归。", "惜春行乐莫辞频。", "巧笑艳歌皆我意，恼花颠酒拼君嗔。", "物情惟有醉中真。"]'),
('song-ci-938','频载酒・浣溪沙','贺铸','宋','宋词','song-ci','频载酒・浣溪沙','[]','金斗城南载酒频。',48,'宋词/ci.song.3000.json','["金斗城南载酒频。", "东西飞观跨通津。", "漾舟聊送雨馀春。", "桃李趣行无算酌，桑榆收得自由身。", "酣歌一曲太平人。"]'),
('song-ci-939','掩萧斋・浣溪沙','贺铸','宋','宋词','song-ci','掩萧斋・浣溪沙','[]','落日逢迎朱雀街。',48,'宋词/ci.song.3000.json','["落日逢迎朱雀街。", "共乘青舫度秦淮。", "笑拈飞絮罥金钗。", "洞户华灯归别馆，碧梧红叶掩萧斋。", "愿随明月入君怀。"]'),
('song-ci-940','杨柳陌・浣溪沙','贺铸','宋','宋词','song-ci','杨柳陌・浣溪沙','[]','兴庆宫池整月开。',48,'宋词/ci.song.3000.json','["兴庆宫池整月开。", "□□□□缕金鞋。", "后庭芳草绿缘阶。", "祓禊归□杨柳陌，□□□落凤凰钗。", "细风抛絮入人怀。"]'),
('song-ci-941','换追风・浣溪沙','贺铸','宋','宋词','song-ci','换追风・浣溪沙','[]','掌上香罗六寸弓。',48,'宋词/ci.song.3000.json','["掌上香罗六寸弓。", "雍容胡旋一盘中。", "目成心许两匆匆。", "别夜可怜长共月。", "当时曾约换追风。", "草生金埒画堂空。"]'),
('song-ci-942','最多宜・浣溪沙','贺铸','宋','宋词','song-ci','最多宜・浣溪沙','[]','半解香绡扑粉肌。',48,'宋词/ci.song.3000.json','["半解香绡扑粉肌。", "避风长下绛纱帷。", "碧琉璃水浸琼枝。", "不学寿阳窥晓镜，何烦京兆画新眉。", "可人风调最多宜。"]'),
('song-ci-943','锦缠头・浣溪沙','贺铸','宋','宋词','song-ci','锦缠头・浣溪沙','[]','旧说山阴禊事休。',48,'宋词/ci.song.3000.json','["旧说山阴禊事休。", "漫书茧纸叙清游。", "吴门千载更风流。", "绕郭烟花莲茂苑，满船丝竹载凉州。", "一标争胜锦缠头。"]'),
('song-ci-944','将进酒・梅花引','贺铸','宋','宋词','song-ci','将进酒・梅花引','[]','城下路。',140,'宋词/ci.song.3000.json','["城下路。", "凄风露。", "今人犁田古人墓。", "岸头沙。", "带蒹葭。", "漫漫惜时，流水今人家。", "黄埃赤日长安道。", "倦客无浆马无草。", "开函关。", "掩函关。", "千古如何，不见一人闲。", "六国扰。", "三秦扫。", "初谓商山遗四老。", "驰单车。", "致缄书。", "裂荷焚芰，接武曳长裙。", "高流端得酒中趣。", "深入醉乡安稳处。", "生忘行。", "死忘名。", "谁论二豪，初不数刘伶。"]'),
('song-ci-945','行路难・梅花引','贺铸','宋','宋词','song-ci','行路难・梅花引','[]','缚虎手。',140,'宋词/ci.song.3000.json','["缚虎手。", "悬河口。", "车如鸡栖马如狗。", "白纶巾。", "扑黄尘。", "不知我辈，可是蓬蒿人。", "衰兰送客咸阳道。", "天若有情天亦老。", "作雷颠。", "不论钱。", "谁问旗亭，美酒斗十千。", "酌大斗。", "更为寿。", "青鬓常青古无有。", "笑嫣然。", "舞翩然。", "当垆秦女，十五语如弦。", "遗音能记秋风曲。", "事去千年犹恨促。", "揽流光。", "系扶桑。", "争奈愁来，一日却为长。"]'),
('song-ci-946','东邻妙・玉楼春','贺铸','宋','宋词','song-ci','东邻妙・玉楼春','[]','张灯结绮笼驰道。',64,'宋词/ci.song.3000.json','["张灯结绮笼驰道。", "六六洞天连夜到。", "韶华吹断紫云回，怊怅人间新梦觉。", "倾城犹记东邻妙。", "尊酒相逢留一笑。", "庐郎任老也多才，不数五陵狂侠少。"]'),
('song-ci-947','问歌颦・雨中花令','贺铸','宋','宋词','song-ci','问歌颦・雨中花令','[]','清滑京江人物秀。',67,'宋词/ci.song.3000.json','["清滑京江人物秀。", "富美发、丰肌素手。", "宝子馀妍，阿娇馀韵，独步秋娘后。", "奈倦客襟怀先怯酒。", "问何意、歌颦易皱。", "弱柳飞绵，繁花结子，做弄伤春瘦。"]'),
('song-ci-948','画楼空・诉衷情','贺铸','宋','宋词','song-ci','画楼空・诉衷情','[]','吴门春水雪初融。',54,'宋词/ci.song.3000.json','["吴门春水雪初融。", "触处小桡通。", "满城弄黄杨柳，著意恼春风。", "弦管闹，绮罗丛。", "月明中。", "不堪回首，双板桥东，罨画楼空。"]'),
('song-ci-949','偶相逢・诉衷情','贺铸','宋','宋词','song-ci','偶相逢・诉衷情','[]','采山涌起翠楼空。',54,'宋词/ci.song.3000.json','["采山涌起翠楼空。", "箫鼓沸春风。", "桂娥唤回清昼，夹路宝芙蓉。", "长步障，小纱笼。", "偶相逢。", "艳妆宜笑，隐语传情，半醉醒中。"]'),
('song-ci-950','步花间・诉衷情','贺铸','宋','宋词','song-ci','步花间・诉衷情','[]','凭陵残醉步花间。',54,'宋词/ci.song.3000.json','["凭陵残醉步花间。", "风棹佩珊珊。", "踏青解红人散，不耐日长闲。", "纤手指，小金环。", "拥云鬟。", "一声水调，两点春愁，先占眉山。"]'),
('song-ci-951','醉梦迷・采桑子','贺铸','宋','宋词','song-ci','醉梦迷・采桑子','[]','深坊别馆兰闺小，障掩金泥，灯映玻璃。',52,'宋词/ci.song.3000.json','["深坊别馆兰闺小，障掩金泥，灯映玻璃。", "一枕浓香醉梦迷。", "醒来拟作清晨散，草草分携。", "柳巷鸦啼。", "又是明朝日向西。"]'),
('song-ci-952','忍泪吟・采桑子','贺铸','宋','宋词','song-ci','忍泪吟・采桑子','[]','十年一觉扬州梦，雨散云沈。',52,'宋词/ci.song.3000.json','["十年一觉扬州梦，雨散云沈。", "隔水登临。", "扬子湾西夕照深。", "当时玉管朱弦句，忍泪重吟。", "半取沾襟。", "饾饤西风□□□。"]'),
('song-ci-953','凌・金人捧露盘','贺铸','宋','宋词','song-ci','凌・金人捧露盘','[]','控沧江。',104,'宋词/ci.song.3000.json','["控沧江。", "排青嶂，燕台凉。", "驻采仗、乐未渠央。", "岩花磴蔓，妒千门、珠翠倚新妆。", "舞闲歌悄，恨风流、不管馀香。", "繁华梦，惊俄顷，佳丽地，指沧茫。", "寄一笑、何与兴亡。", "量船载酒，赖使君、相对两胡床。", "缓调清管，更为侬、三弄斜阳。"]'),
('song-ci-954','秋风叹・燕瑶池','贺铸','宋','宋词','song-ci','秋风叹・燕瑶池','[]','琼钩褰幔。',65,'宋词/ci.song.3000.json','["琼钩褰幔。", "秋风观。", "漫漫。", "白云聊度河汉。", "长宵半。", "参旗烂烂。", "何时旦。", "命闺人、金徽重按。", "商歌弹。", "依稀广陵清散。", "低眉叹。", "危弦未断。", "肠先断。"]'),
('song-ci-955','断湘弦・万年欢','贺铸','宋','宋词','song-ci','断湘弦・万年欢','[]','淑质柔情，靓妆艳笑，未容桃李争妍。',125,'宋词/ci.song.3000.json','["淑质柔情，靓妆艳笑，未容桃李争妍。", "红粉墙东，曾记窥宋三年。", "不间云朝雨暮，向西楼、南馆留连。", "何尝信，美景良辰，赏心乐事难全。", "青门解袂，画桥回首，初沈汉佩，永断湘弦。", "漫写浓愁幽恨，封寄鱼笺。", "拟话当时旧好，问同谁、与醉尊前。", "除非是，明月清风，向人今夜依然。"]'),
('song-ci-956','子夜歌','贺铸','宋','宋词','song-ci','子夜歌','[]','三更月。',56,'宋词/ci.song.3000.json','["三更月。", "中庭恰照梨花雪。", "梨花雪。", "不胜凄断，杜鹃啼血。", "王孙何许音尘绝。", "柔桑陌上吞声别。", "吞声别。", "陇头流水，替人呜咽。"]'),
('song-ci-957','独倚楼・更漏子','贺铸','宋','宋词','song-ci','独倚楼・更漏子','[]','上东门，门外柳。',58,'宋词/ci.song.3000.json','["上东门，门外柳。", "赠别每烦纤手。", "一叶落，几番秋。", "江南独倚楼。", "曲阑干，凝伫久。", "薄暮更堪搔首。", "无际恨，见闲愁。", "侵寻天尽头。"]'),
('song-ci-958','翻翠袖・更漏子','贺铸','宋','宋词','song-ci','翻翠袖・更漏子','[]','绣罗垂，花蜡换。',58,'宋词/ci.song.3000.json','["绣罗垂，花蜡换。", "问夜何其将半。", "侵舄履，促杯盘。", "留欢不作难。", "令随阄，歌应弹。", "舞按霓裳前段。", "翻翠袖，怯春寒。", "玉阑风牡丹。"]'),
('song-ci-959','付金钗・更漏子','贺铸','宋','宋词','song-ci','付金钗・更漏子','[]','付金钗，平斗酒。',58,'宋词/ci.song.3000.json','["付金钗，平斗酒。", "未许解携纤手。", "吟警句，写清愁。", "浮骖为少留。", "旧游赊，新梦后。", "月映隔窗疏柳。", "闲砚席，剩衾绸。", "今秋似去秋。"]'),
('song-ci-960','伴登临・采桑子','贺铸','宋','宋词','song-ci','伴登临・采桑子','[]','中吴茂苑繁华地。',58,'宋词/ci.song.3000.json','["中吴茂苑繁华地。", "冠盖如林。", "桃李成阴。", "若个芳心、真个会琴心。", "高秋霁色清於水。", "月榭风襟。", "且伴登临。", "留与他年、尊酒话而今。"]'),
('song-ci-961','苗而秀・采桑子','贺铸','宋','宋词','song-ci','苗而秀・采桑子','[]','吴都佳丽苗而秀。',58,'宋词/ci.song.3000.json','["吴都佳丽苗而秀。", "燕样腰身。", "按舞华茵。", "促遍凉州、罗袜未生尘。", "□□□□□□透。", "歌怨眉颦。", "张燕宜频。", "□□□□、□□□□□。"]'),
('song-ci-962','东吴乐・尉迟杯','贺铸','宋','宋词','song-ci','东吴乐・尉迟杯','[]','胜游地。',131,'宋词/ci.song.3000.json','["胜游地。", "信东吴绝景饶佳丽。", "平湖底，见层岚，凉月下，闻清吹。", "人如秾李。", "泛金袂、香润苹风起。", "喜凌波、素袜逢迎，领略当歌深意。", "鄂君被。", "双鸳绮。", "垂杨阴，夷犹画舲相舣。", "宝瑟弦调，明珠佩委。", "回首碧云千里。", "归鸿后、芳音难寄。", "念怀县、青鬓今无几。", "枉分将、镜里华年，付与楼前流水。"]'),
('song-ci-963','台城游・水调歌头','贺铸','宋','宋词','song-ci','台城游・水调歌头','[]','南国本潇洒。',114,'宋词/ci.song.3000.json','["南国本潇洒。", "六代浸豪奢。", "台城游冶。", "襞笺能赋属宫娃。", "云观登临清夏。", "璧月留连长夜。", "吟醉送年华。", "回首飞鸳瓦。", "却羡井中蛙。", "访乌衣，成白社。", "不容车。", "旧时王谢。", "堂前双燕过谁家。", "楼外河横斗挂。", "淮上潮平霜下。", "墙影落寒沙。", "商女篷窗罅。", "犹唱后庭花。"]'),
('song-ci-964','潇湘雨・满庭芳','贺铸','宋','宋词','song-ci','潇湘雨・满庭芳','[]','一阕离歌，满尊红泪，解携十里长亭。',118,'宋词/ci.song.3000.json','["一阕离歌，满尊红泪，解携十里长亭。", "木兰归棹，犹倚采苹汀。", "鸦噪黄陵庙掩，因想像、鼓瑟湘灵。", "渔村远，烟昏雨淡，灯火两三星。", "愁听。", "墙影外，繁声骤点，□□□□。", "□□□□□，浓睡香屏。", "入梦难留□□，□□□、□□□□。", "□窗晓，云容四敛，江上数峰青。"]'),
('song-ci-965','念离群・沁园春','贺铸','宋','宋词','song-ci','念离群・沁园春','[]','宫烛分烟，禁池开钥，凤城暮春。',141,'宋词/ci.song.3000.json','["宫烛分烟，禁池开钥，凤城暮春。", "向落花香里，澄波影外，笙歌迟日，罗绮芳尘。", "载酒追游，联镳归晚，灯火平康寻梦云。", "逢迎处，最多才自负，巧笑相亲。", "离群。", "客浣漳滨。", "但惊见、来鸿归燕频。", "念日边消耗，天涯怅望，楼台清晓，帘暮黄昏。", "无限悲凉，不胜憔悴，断尽危肠销尽魂。", "方年少，恨浮名误我，乐事输人。"]'),
('song-ci-966','宛溪柳・六么令','贺铸','宋','宋词','song-ci','宛溪柳・六么令','[]','梦云萧散，帘卷画堂晓。',112,'宋词/ci.song.3000.json','["梦云萧散，帘卷画堂晓。", "残薰尽烛隐映，绮席金壶倒。", "尘送行鞭袅袅。", "醉指长安道。", "波平天渺。", "兰舟欲上，回首离愁满芳草。", "已恨归期不早。", "枉负狂年少。", "无奈风月多情，此去应相笑。", "心记新声缥缈。", "翻是相思调。", "明年春杪。", "宛溪杨柳，依旧青青为谁好。"]'),
('song-ci-967','伤春曲・满江红','贺铸','宋','宋词','song-ci','伤春曲・满江红','[]','火禁初开，深深院、尽重帘箔。',115,'宋词/ci.song.3000.json','["火禁初开，深深院、尽重帘箔。", "人自起、翠衾寒梦，夜来风恶。", "肠断残红和泪落。", "半随经雨飘池角。", "记采兰、携手曲江游，年时约。", "芳物大，都如昨。", "自怨别，疏行乐。", "被无情双燕，短封难托。", "谁念东阳销瘦骨。", "更堪白纻衣衫薄。", "向小窗、题满杏花笺，伤春作。"]'),
('song-ci-968','横塘路・青玉案','贺铸','宋','宋词','song-ci','横塘路・青玉案','[]','凌波不过横塘路。',80,'宋词/ci.song.3000.json','["凌波不过横塘路。", "但目送、芳尘去。", "锦瑟华年谁与度。", "月桥花院，琐窗朱户。", "只有春知处。", "飞云冉冉蘅皋暮。", "彩笔新题断肠句。", "若问闲情都几许。", "一川烟草，满城风絮。", "梅子黄时雨。"]'),
('song-ci-969','人南渡・感皇恩','贺铸','宋','宋词','song-ci','人南渡・感皇恩','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','兰芷满芳洲，游思横路。',83,'宋词/ci.song.3000.json','["兰芷满芳洲，游思横路。", "罗袜尘生步。", "迎顾。", "整鬟颦黛，脉脉两情难语。", "细风吹柳絮。", "人南渡。", "回首旧游，山无重数。", "花底深朱户。", "何处。", "半黄梅子，向晚一帘疏雨。", "断魂分付与。", "春将去。"]'),
('song-ci-970','薄幸','贺铸','宋','宋词','song-ci','薄幸','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','艳真多态。',131,'宋词/ci.song.3000.json','["艳真多态。", "更的的，频回眄睐。", "便认得、琴心相许，与写宜男双带。", "记画堂、斜月朦胧，轻颦微笑娇无奈。", "便翡翠屏开，芙蓉帐掩，与把香罗偷解。", "自过了收灯后，都不见、踏青挑菜。", "几回凭双燕，丁宁深意，往来翻恨重帘碍。", "约何时再。", "正春浓酒暖，人闲昼永无聊赖。", "厌厌睡起，犹有花梢日在。"]'),
('song-ci-971','伴云来・天香','贺铸','宋','宋词','song-ci','伴云来・天香','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','烟络横林，山沈远照，逦迤黄昏钟鼓。',116,'宋词/ci.song.3000.json','["烟络横林，山沈远照，逦迤黄昏钟鼓。", "烛映帘栊，蛩催机杼，共苦清秋风露。", "不眠思妇，齐应和、几声砧杵。", "惊动天涯倦宦，骎骎岁华行暮。", "当年酒狂自负。", "谓东君、已春相付。", "流浪征骖北道，客墙南浦。", "幽恨无人晤语。", "赖明月曾知旧游处。", "好伴云来，还将梦去。"]'),
('song-ci-972','念良游・满江红','贺铸','宋','宋词','song-ci','念良游・满江红','[]','山缭平湖，寒飙扬、六英粉泊。',115,'宋词/ci.song.3000.json','["山缭平湖，寒飙扬、六英粉泊。", "清镜晓、倚岩琪树，挠云朱阁。", "窈窕缯窗褰翠募，尊前浩齿歌梅落。", "信醉乡、绝境待名流，供行乐。", "时易失，今犹昨。", "欢莫再，情何薄。", "扁舟幸不系，会寻佳约。", "想见徘徊华表下，个身似是辽东鹤。", "访旧游、人与物俱非，空城郭。"]'),
('song-ci-973','寒松叹・声声慢','贺铸','宋','宋词','song-ci','寒松叹・声声慢','[]','鹊惊桥断，凤怨箫闲，彩云薄晚苍凉。',118,'宋词/ci.song.3000.json','["鹊惊桥断，凤怨箫闲，彩云薄晚苍凉。", "难致祖州灵草，方士神香。", "寒松半敧涧底，恨女萝、先委冰霜。", "宝琴尘网，□□□□，□□□□。", "依□履綦行处，酸心□，□□□□□□。", "□□帘垂窣地，簟竟空床。", "伤春燕归洞户，更悲秋、月皎回廊。", "同谁消遣，一年年夜夜长。"]'),
('song-ci-974','凤求凰・声声慢','贺铸','宋','宋词','song-ci','凤求凰・声声慢','[]','园林幕翠，燕寝凝香。',118,'宋词/ci.song.3000.json','["园林幕翠，燕寝凝香。", "华池缭绕飞廊。", "坐按吴娃清丽，楚调圆长。", "歌阑横流美眄，乍疑生、绮席辉光。", "文园属意，玉觞交劝，宝色高张。", "南薰难销幽恨，金徽上，殷勤彩凤求凰。", "便许卷收行雨，不恋高唐。", "东山胜游在眼，待纫阑、拮菊相将。", "双栖安稳，五云溪是故乡。"]'),
('song-ci-975','国门东・好女儿','贺铸','宋','宋词','song-ci','国门东・好女儿','[]','车马匆匆。',76,'宋词/ci.song.3000.json','["车马匆匆。", "会国门东。", "信人间、自古销魂处，指红尘北道，碧波南浦，黄叶西风。", "堠馆娟娟新月，从今夜、与谁同。", "想深闺独守空床思，但频占镜鹊，悔分钗燕，长望书鸿。"]'),
('song-ci-976','九回肠・好女儿','贺铸','宋','宋词','song-ci','九回肠・好女儿','[]','削玉销香。',77,'宋词/ci.song.3000.json','["削玉销香。", "不喜浓妆。", "倚高楼、望断章台路，但垂杨永巷，落花微雨，芳草斜阳。", "赖有雕梁新燕，试寻访，武陵狂。", "小华笺、付与西飞去，印一双愁黛，再三归字，□九回肠。"]'),
('song-ci-977','月先圆・好女儿','贺铸','宋','宋词','song-ci','月先圆・好女儿','[]','才色相怜。',77,'宋词/ci.song.3000.json','["才色相怜。", "难偶当年。", "屡逢迎、几许缠绵意，记秋千架底，摴蒲局上，祓禊池边。", "收贮一春幽恨，细书遍、砑绫笺。", "算蓬山、未抵屏山远，奈碧云易合，彩霞深闭，明月先圆。"]'),
('song-ci-978','绮筵张・好女儿','贺铸','宋','宋词','song-ci','绮筵张・好女儿','[]','绮绣张筵。',77,'宋词/ci.song.3000.json','["绮绣张筵。", "粉黛争妍。", "记六朝、旧数闺房秀，有长圆璧月，永新琼树，随步金莲。", "不减丽华标韵，更能唱、想夫怜。", "认情通、色受缠绵处，似灵犀一点，吴蚕八茧，汉柳三眠。"]'),
('song-ci-979','舞迎春・迎春乐','贺铸','宋','宋词','song-ci','舞迎春・迎春乐','[]','云鲜日嫩东风软。',63,'宋词/ci.song.3000.json','["云鲜日嫩东风软。", "雪初融、水清浅。", "粉□舞按迎春遍。", "似飞动、钗头燕。", "深折梅花曾寄远。", "问谁为、倚楼凄怨。", "身伴未归鸿，犹顾恋、江南暖。"]'),
('song-ci-980','城里钟・菩萨蛮','贺铸','宋','宋词','song-ci','城里钟・菩萨蛮','[]','厌厌别酒商歌送。',52,'宋词/ci.song.3000.json','["厌厌别酒商歌送。", "萧萧凉叶秋声动。", "小泊画桥东。", "孤舟月满篷。", "高城遮短梦。", "衾藉馀香拥。", "多谢五更风。", "犹闻城里钟。"]'),
('song-ci-981','望西飞・清商怨','贺铸','宋','宋词','song-ci','望西飞・清商怨','[]','十分持酒每□□。',52,'宋词/ci.song.3000.json','["十分持酒每□□。", "□□□□□。", "□计留春，春随人去远。", "东流□□□□。", "□□□、好凭双燕。", "望断西风，高楼帘暮卷。"]'),
('song-ci-982','东阳叹・清商怨','贺铸','宋','宋词','song-ci','东阳叹・清商怨','[]','流连狂乐恨景短。',52,'宋词/ci.song.3000.json','["流连狂乐恨景短。", "奈夕阳送晚。", "醉未成欢，醒来愁满眼。", "东阳消瘦带展。", "望日下、旧游天远。", "泪洒春风，春风谁复管。"]'),
('song-ci-983','要销凝・清商怨','贺铸','宋','宋词','song-ci','要销凝・清商怨','[]','雕梁寻巢旧燕侣。',52,'宋词/ci.song.3000.json','["雕梁寻巢旧燕侣。", "似向人欲语。", "试问来时，逢郎郎健否。", "春风深闭绣户。", "尽便旋、一庭花絮。", "要自销凝，吟郎长短句。"]'),
('song-ci-984','想车音・兀令','贺铸','宋','宋词','song-ci','想车音・兀令','[]','盘马楼前风日好。',100,'宋词/ci.song.3000.json','["盘马楼前风日好。", "雪销尘扫。", "楼上宫妆早。", "认帘箔微开，一面嫣妍笑。", "携手别院重廊，窈窕花房小。", "任碧罗窗晓。", "间阔时多书问少。", "镜鸾空老。", "身寄吴云杳。", "想轣辘车音，几度青门道。", "占得春色年年，随处随人到。", "恨不如芳草。"]'),
('song-ci-985','荆溪咏・渔家傲','贺铸','宋','宋词','song-ci','荆溪咏・渔家傲','["\u8861\u5c71"]','南岳去天才尺五。',72,'宋词/ci.song.3000.json','["南岳去天才尺五。", "荆溪笠泽相吞吐。", "十日一风仍再雨。", "宜禾黍。", "秋成处处宜禾黍。", "坊市万家连岛屿。", "长杨□□□□□。", "□□□□□□□。", "能歌舞。", "刘郎不□□□□。"]'),
('song-ci-986','吹柳絮・瑞鹧鸪','贺铸','宋','宋词','song-ci','吹柳絮・瑞鹧鸪','[]','月痕依约到西厢。',64,'宋词/ci.song.3000.json','["月痕依约到西厢。", "曾羡花枝拂短墙。", "初未识愁那得泪，每浑疑梦奈馀香。", "歌逢袅处眉先妩，酒半酣时眼更狂。", "闲倚绣帘吹柳絮，问何人似冶游郎。"]'),
('song-ci-987','江如练・蝶恋花','贺铸','宋','宋词','song-ci','江如练・蝶恋花','[]','睡鸭鲈寒熏麝煎。',70,'宋词/ci.song.3000.json','["睡鸭鲈寒熏麝煎。", "寂寂歌梁，无计留归燕。", "十二曲阑闲倚遍。", "一杯长待何人劝。", "不识当年桃叶面。", "吟咏佳词，想像犹曾见。", "两桨往来风与便。", "潮平月上江如练。"]'),
('song-ci-988','宴齐云・南歌子','贺铸','宋','宋词','song-ci','宴齐云・南歌子','[]','境跨三千里，楼侵尺五天。',62,'宋词/ci.song.3000.json','["境跨三千里，楼侵尺五天。", "碧鸳鸯瓦昼生烟。", "未信西山台观、压当年。", "野色分禾黍，秋声入管弦。", "闲挥弹麈襞吟笺。", "三十万家风月、共流连。"]'),
('song-ci-989','醉琼枝・定风波','贺铸','宋','宋词','song-ci','醉琼枝・定风波','[]','槛外雨波新涨，门前烟柳浑青。',72,'宋词/ci.song.3000.json','["槛外雨波新涨，门前烟柳浑青。", "寂寞文园淹卧久，推枕援琴涕自零。", "无人著意听。", "绪绪风披芸幌，锓锓月到萱庭。", "长记合欢东管夜，与解香罗掩绣屏。", "琼枝半醉醒。"]'),
('song-ci-990','□□□・更漏子','贺铸','宋','宋词','song-ci','□□□・更漏子','[]','酒三行，琴再弄。',58,'宋词/ci.song.3000.json','["酒三行，琴再弄。", "宛是和鸣双凤。", "罗斗帐，绣屏风。", "浓香夜夜同。", "去年欢，今夕梦。", "怊怅晓钟初动。", "休道梦，觉来空。", "当时亦梦中。"]'),
('song-ci-991','弄珠英・蓦山溪','贺铸','宋','宋词','song-ci','弄珠英・蓦山溪','[]','楚乡新岁。',102,'宋词/ci.song.3000.json','["楚乡新岁。", "不放残寒退。", "月晓桂娥闲，弄珠英、因风委坠。", "清淮铺练，十二玉峰前，上帘栊，招佳丽。", "置酒成高会。", "江南芳信，目断何人寄。", "应占镜边春，想晨妆、膏浓压翠。", "此时乘兴，半道忍回桡，五云溪，门深闭。", "碧月长相对。"]'),
('song-ci-992','梦相亲・玉楼春','贺铸','宋','宋词','song-ci','梦相亲・玉楼春','[]','清琴再鼓求凰弄。',64,'宋词/ci.song.3000.json','["清琴再鼓求凰弄。", "紫陌屡盘骄马鞚。", "远山眉样认心期，流水车音牵目送。", "归来翠被和衣拥。", "醉解寒生钟鼓动。", "此欢只许梦相亲，每向梦中还说梦。"]'),
('song-ci-993','罗敷歌・采桑子','贺铸','宋','宋词','song-ci','罗敷歌・采桑子','[]','高楼帘卷秋风里，目送斜阳。',52,'宋词/ci.song.3000.json','["高楼帘卷秋风里，目送斜阳。", "衾枕遗香。", "今夜还如昨夜长。", "玉人望月销凝处，应在西厢。", "半掩兰堂。", "惟有纱灯伴绣床。"]'),
('song-ci-994','罗敷歌・采桑子','贺铸','宋','宋词','song-ci','罗敷歌・采桑子','[]','河阳官罢文园病，触绪萧然。',52,'宋词/ci.song.3000.json','["河阳官罢文园病，触绪萧然。", "犀麈流连。", "喜见清蟾似旧圆。", "人生聚散浮云似，回首明年。", "何处尊前。", "怅望星河共一天。"]'),
('song-ci-995','罗敷歌・采桑子','贺铸','宋','宋词','song-ci','罗敷歌・采桑子','[]','东南自古繁华地，歌吹扬州。',52,'宋词/ci.song.3000.json','["东南自古繁华地，歌吹扬州。", "十二青楼。", "最数秦娘第一流。", "季鹰久负鲈鱼兴，不住今秋。", "已办归舟。", "伴我江湖作胜游。"]'),
('song-ci-996','罗敷歌・采桑子','贺铸','宋','宋词','song-ci','罗敷歌・采桑子','[]','自怜楚客悲秋思，难写丝桐。',52,'宋词/ci.song.3000.json','["自怜楚客悲秋思，难写丝桐。", "目断书鸿。", "平淡江山落照中。", "谁家水调声声怨，黄叶西风。", "罨画桥东。", "十二玉楼空更空。"]'),
('song-ci-997','罗敷歌・采桑子','贺铸','宋','宋词','song-ci','罗敷歌・采桑子','[]','东亭南馆逢迎地，几醉红裙。',52,'宋词/ci.song.3000.json','["东亭南馆逢迎地，几醉红裙。", "凄怨临分。", "四叠阳关忍泪闻。", "谁怜今夜篷窗雨，何处渔村。", "酒冷灯昏。", "不许愁人不断魂。"]'),
('song-ci-998','小重山','贺铸','宋','宋词','song-ci','小重山','[]','玉指金徽一再弹。',70,'宋词/ci.song.3000.json','["玉指金徽一再弹。", "新声传访戴，雪溪寒。", "两行墨妙破冰纨。", "牵情处，幽恨寄毫端。", "昵语强羞难。", "相逢真许似，镜中鸾。", "小梅疏影近杯盘。", "东风里，谁共倚阑干。"]'),
('song-ci-999','小重山','贺铸','宋','宋词','song-ci','小重山','[]','帘影新妆一破颜。',70,'宋词/ci.song.3000.json','["帘影新妆一破颜。", "玳筵回雪舞，小云鬟。", "琼枝擢秀望难攀。", "凝情处，千里望蓬山。", "歌断酒阑珊。", "画船箫鼓转，绿杨湾。", "坠钿残燎水堂关。", "斜阳里，双燕伴人闲。"]'),
('song-ci-0','小重山','贺铸','宋','宋词','song-ci','小重山','[]','枕上阊门五报更。',70,'宋词/ci.song.4000.json','["枕上阊门五报更。", "蜡灯香灺冷，恨天明。", "青苹风转彩帆轻。", "樯头燕，多谢伴人行。", "临镜想倾城。", "两尖愁黛浅，泪波横。", "艳歌重记遣离情。", "缠绵处，翻是断肠声。"]'),
('song-ci-1','小重山','贺铸','宋','宋词','song-ci','小重山','[]','月月相逢只旧圆。',70,'宋词/ci.song.4000.json','["月月相逢只旧圆。", "迢迢三十夜，夜如年。", "伤心不照绮罗筵。", "孤舟里，单枕若为眠。", "茂苑想依然。", "花楼连苑起，压漪涟。", "玉人千里共婵娟。", "清琴怨，肠断亦如弦。"]'),
('song-ci-2','河传','贺铸','宋','宋词','song-ci','河传','[]','华堂张燕。',73,'宋词/ci.song.4000.json','["华堂张燕。", "向尊前妙选，舞裙歌扇。", "彼美个人，的的风流心眼。", "恨寻芳来晚。", "曲街灯火香尘散。", "犹约晨妆，一觇春风面。", "惆怅善和坊里，平桥南畔。", "小青楼、帘不卷。"]'),
('song-ci-3','河传','贺铸','宋','宋词','song-ci','河传','[]','华堂重厦，向尊前更听，碧云新怨。',73,'宋词/ci.song.4000.json','["华堂重厦，向尊前更听，碧云新怨。", "玉指钿徽，总是挑人心眼。", "恨随红蜡短。", "彩旗影动船头转。", "双桨凌波，惟念人留恋。", "江上暮潮，隐隐山横南岸。", "奈离愁、分不断。"]'),
('song-ci-4','侍香金童','贺铸','宋','宋词','song-ci','侍香金童','[]','楚梦方回，翠被寒如水。',76,'宋词/ci.song.4000.json','["楚梦方回，翠被寒如水。", "尚想见、扬州桃李。", "姿秀韵闲何物比。", "玉管秋风，漫声流美。", "燕堂开，双按秦弦呈素指。", "宝雁参差飞不起。", "三五彩蟾明夜是。", "屈曲阑干，断肠千里。"]'),
('song-ci-5','凤栖梧・蝶恋花','贺铸','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','独立江东人婉娈。',70,'宋词/ci.song.4000.json','["独立江东人婉娈。", "粉本花真，千里依稀见。", "闲弄彩毫濡玉砚。", "缠绵春思□歌扇。", "爱我竹窗新句练。", "小砑凌笺、偷寄西风燕。", "乍可问名赊识面。", "十年多病风情浅。"]'),
('song-ci-6','更漏子','贺铸','宋','宋词','song-ci','更漏子','[]','芳草斜曛。',126,'宋词/ci.song.4000.json','["芳草斜曛。", "映画桥□□，翠阁临津。", "数阕清歌，两行红粉，厌厌别酒初曛。", "芳意赠我殷勤。", "罗巾双黛痕。", "便兰舟独上，洞府人闲，素手轻分。", "十里绮陌香尘。", "望紫云车远，已掩青门。", "迤逦黄昏，景阳钟动，临风隐隐犹闻。", "明朝水馆渔村。", "凭谁招断魂。", "恨不如今夜，明月多情，应待归云。"]'),
('song-ci-7','玉京秋','贺铸','宋','宋词','song-ci','玉京秋','[]','陇首霜晴，泗滨云晚，乍摇落。',127,'宋词/ci.song.4000.json','["陇首霜晴，泗滨云晚，乍摇落。", "废榭苍苔，破台荒草，西楚霸图冥漠。", "记登临事，九日胜游，千载如昨。", "更想像，晋客□归，谢生能赋继高作。", "飘泊。", "尘埃倦客，风月羁心，潘鬓晓来清镜觉。", "蜡屐纶巾，羽觞象管，且追随、隼旟行乐。", "东山□，应笑个侬风味薄。", "念故园黄花，自有年年约。"]'),
('song-ci-8','蕙清风','贺铸','宋','宋词','song-ci','蕙清风','[]','何许最悲秋，凄风残照。',86,'宋词/ci.song.4000.json','["何许最悲秋，凄风残照。", "临水复登山，莞然西笑。", "车马几番尘，自古长安道。", "问谁是、后来年少。", "飞集两悠悠，江滨海岛。", "乘雁与双凫，强分多少。", "传语酒家胡，岁晚从吾好。", "待做个、醉乡遗老。"]'),
('song-ci-9','虞美人','贺铸','宋','宋词','song-ci','虞美人','[]','粉娥齐敛千金笑。',66,'宋词/ci.song.4000.json','["粉娥齐敛千金笑。", "愁结眉峰小。", "渭城才唱浥轻尘。", "无奈两行红泪、湿香巾。", "伤心风月南城道。", "几纵朱轓到。", "明年载酒洛阳春。", "还念淮山楼上、倚阑人。"]'),
('song-ci-10','下水船','贺铸','宋','宋词','song-ci','下水船','[]','芳草青门路。',90,'宋词/ci.song.4000.json','["芳草青门路。", "还拂京尘东去。", "回想当年离绪。", "送君南浦。", "愁几许。", "尊酒流连薄暮。", "帘卷津楼风雨。", "凭阑语。", "草草蘅皋赋。", "分首惊鸿不驻。", "灯火虹桥，难寻弄波微步。", "漫凝伫。", "莫怨无情流水，明月扁舟何处。"]'),
('song-ci-11','点绛唇','贺铸','宋','宋词','song-ci','点绛唇','[]','见面无多，坐来百媚生馀态。',50,'宋词/ci.song.4000.json','["见面无多，坐来百媚生馀态。", "后庭春在。", "折取残红戴。", "小小兰舟，荡桨东风快。", "何愁载。", "缠绵难解。", "不似罗裙带。"]'),
('song-ci-12','渔家傲','贺铸','宋','宋词','song-ci','渔家傲','[]','莫厌香醪斟绣履。',72,'宋词/ci.song.4000.json','["莫厌香醪斟绣履。", "吐茵也是风流事。", "今夜夜寒愁不睡。", "披衣起。", "挑灯开卷花生纸。", "倩问尊前桃与李。", "重来若个犹相记。", "前度刘郎应老矣。", "行乐地。", "兔葵燕麦春风里。"]'),
('song-ci-13','感皇恩','贺铸','宋','宋词','song-ci','感皇恩','[]','歌笑见馀妍，情生眄睐。',82,'宋词/ci.song.4000.json','["歌笑见馀妍，情生眄睐。", "拥髻扬蛾黛。", "多态。", "小花深院，漏促离襟将解。", "恼人红蜡泪。", "啼相对。", "芳草唤愁，愁来难奈。", "兰叶犹堪向谁采。", "小楼妆晚，应念斑骓何在。", "碧云长有待。", "斜阳外。"]'),
('song-ci-14','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','彩舟载得离愁动。',52,'宋词/ci.song.4000.json','["彩舟载得离愁动。", "无端更借樵风送。", "波渺夕阳迟。", "销魂不自持。", "良宵谁与共。", "赖有窗间梦。", "可奈梦回时。", "一番新别离。"]'),
('song-ci-15','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','章台游冶金龟婿。',52,'宋词/ci.song.4000.json','["章台游冶金龟婿。", "归来犹带醺醺醉。", "花漏怯春宵。", "云屏无限娇。", "绛纱灯影背。", "玉枕钗声碎。", "不待宿酲销。", "马嘶催早朝。"]'),
('song-ci-16','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','曲门南与鸣珂接。',52,'宋词/ci.song.4000.json','["曲门南与鸣珂接。", "小园绿径飞胡蝶。", "下马访婵娟。", "笑迎妆阁前。", "鹧鸪声几叠。", "艳艳金蕉叶。", "未许被香鞯。", "月生楼外天。"]'),
('song-ci-17','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','绿窗残梦闻鶗鴂。',52,'宋词/ci.song.4000.json','["绿窗残梦闻鶗鴂。", "曲屏映枕春山叠。", "梳□发如蝉。", "镜生波上莲。", "绛裙金缕褶。", "学舞腰肢怯。", "帘下小凭肩。", "与人双翠钿。"]'),
('song-ci-18','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','绿杨眠后拖烟穗。',52,'宋词/ci.song.4000.json','["绿杨眠后拖烟穗。", "日长扫尽青苔地。", "香断入帘风。", "炉心檀烬红。", "兰溪修祓禊。", "上巳明朝是。", "不许放春慵。", "景阳临晓钟。"]'),
('song-ci-19','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','粉香映叶花羞日。',52,'宋词/ci.song.4000.json','["粉香映叶花羞日。", "窗间宛转蜂寻蜜。", "欢罢卷帘时。", "玉纤匀面脂。", "舞裙金斗熨。", "绛襭鸳鸯密。", "翠带一双垂。", "索人题艳诗。"]'),
('song-ci-20','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','子规啼梦罗窗晓。',52,'宋词/ci.song.4000.json','["子规啼梦罗窗晓。", "开奁拂镜严妆早。", "彩碧画丁香。", "背垂裙带长。", "钿筝寻旧曲。", "愁结眉心绿。", "犹恨夜来时。", "酒狂归太迟。"]'),
('song-ci-21','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','虚堂向壁青灯灭。',52,'宋词/ci.song.4000.json','["虚堂向壁青灯灭。", "觉来惊见横窗月。", "起看月平西。", "城头乌夜啼。", "兰衾羞更入。", "敧枕偷声泣。", "肠断数残更。", "望明天未明。"]'),
('song-ci-22','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','芭蕉衬雨秋声动。',52,'宋词/ci.song.4000.json','["芭蕉衬雨秋声动。", "罗窗恼破鸳鸯梦。", "愁倚□帘栊。", "灯花落地红。", "枕横衾浪拥。", "好夜无人共。", "莫道粉墙东。", "蓬山千万重。"]'),
('song-ci-23','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','朱甍碧树莺声晓。',52,'宋词/ci.song.4000.json','["朱甍碧树莺声晓。", "残醺残梦犹相恼。", "薄雨隔轻帘。", "寒侵白纻衫。", "锦屏人起早。", "惟见馀妆好。", "眉样学新蟾。", "春愁入翠尖。"]'),
('song-ci-24','菩萨蛮','贺铸','宋','宋词','song-ci','菩萨蛮','[]','炉烟微度流苏帐。',52,'宋词/ci.song.4000.json','["炉烟微度流苏帐。", "孤衾冷叠芙蓉浪。", "蟋蟀不离床。", "伴人愁夜长。", "玉人飞阁上。", "见月还相望。", "相望莫相忘。", "应无未断肠。"]'),
('song-ci-25','于飞乐','贺铸','宋','宋词','song-ci','于飞乐','[]','日薄云融。',88,'宋词/ci.song.4000.json','["日薄云融。", "满城罗绮芳丛。", "一枝粉淡香浓。", "几销魂，偏健羡、紫蝶黄蜂。", "繁华梦断，酒醒来、扫地春空。", "武陵原、回头何处，情随流水无穷。", "寄两行清泪，想几许残红。", "惜花人老，年年奈、依旧东风。"]'),
('song-ci-26','浣溪沙','贺铸','宋','宋词','song-ci','浣溪沙','[]','双鹤横桥阿那边。',56,'宋词/ci.song.4000.json','["双鹤横桥阿那边。", "静坊深院闭婵娟。", "五度花开三处见，两依然。", "水眄难禁频领□，歌云犹许小流连。", "破得尊前何限恨，不论钱。"]'),
('song-ci-27','品令','贺铸','宋','宋词','song-ci','品令','[]','怀彼美。',65,'宋词/ci.song.4000.json','["怀彼美。", "愁与泪。", "分占眉丛眼尾。", "求好梦、闲拥鸳鸯绮。", "恨啼鸟、唤人起。", "目断清淮楼上，心寄长洲坊里。", "迢迢地。", "七百三十里。", "几重山，几重水。"]'),
('song-ci-28','海月谣','贺铸','宋','宋词','song-ci','海月谣','[]','楼平叠巘。',80,'宋词/ci.song.4000.json','["楼平叠巘。", "瞰瀛海、波三面。", "碧云扫尽，桂轮滉玉，鲸波张练。", "化出无边宝界，是名壮观。", "追游汗漫。", "愿少借、长风便。", "麻姑相顾，□然笑指，寒潮清浅。", "顿觉蓬莱方丈，去人不远。"]'),
('song-ci-29','风流子','贺铸','宋','宋词','song-ci','风流子','[]','何处最难忘。',134,'宋词/ci.song.4000.json','["何处最难忘。", "方豪健，放乐五云乡。", "彩笔赋诗，禁池芳草，香鞯调马，辇路垂杨。", "绮筵上，扇偎歌黛浅，汗浥舞罗香。", "兰烛伴归，绣轮同载，闭花别馆，隔水深坊。", "零落少年场。", "琴心漫流怨，带眼偷长。", "无奈占床燕月，侵鬓吴霜。", "念北里音尘，鱼封永断，便桥烟雨，鹤表相望。", "好在后庭桃李，应记刘郎。"]'),
('song-ci-30','鹧鸪天','贺铸','宋','宋词','song-ci','鹧鸪天','[]','轰醉王孙玳瑁筵。',64,'宋词/ci.song.4000.json','["轰醉王孙玳瑁筵。", "渴虹垂地吸长川。", "侧商调里清歌送，破尽穷愁直几钱。", "孤棹舣，小江边。", "爱而不见酒中仙。", "伤心两岸官杨柳，已带斜阳又带蝉。"]'),
('song-ci-31','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','白纻春衫新制。',40,'宋词/ci.song.4000.json','["白纻春衫新制。", "准拟采兰修禊。", "遮日走京尘，何啻分阴如岁。", "留滞。", "留滞。", "不似行云难系。"]'),
('song-ci-32','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','日日春风楼上。',40,'宋词/ci.song.4000.json','["日日春风楼上。", "不见石城双桨。", "鸳枕梦回时，烛泪屏山相向。", "流荡。", "流荡。", "门外白苹溪涨。"]'),
('song-ci-33','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','相见时难别易。',40,'宋词/ci.song.4000.json','["相见时难别易。", "何限玉琴心意。", "眉黛只供愁，羞见双鸳鸯字。", "憔悴。", "憔悴。", "蜡烛销成红泪。"]'),
('song-ci-34','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','罗绮丛中初见。',40,'宋词/ci.song.4000.json','["罗绮丛中初见。", "理鬓横波流转。", "半醉不胜情，帘影犹招歌扇。", "留恋。", "留恋。", "秋夜辞巢双燕。"]'),
('song-ci-35','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','雨后一分春减。',40,'宋词/ci.song.4000.json','["雨后一分春减。", "深院落红如糁。", "柳外出秋千，度日彩旗风飐。", "销黯。", "销黯。", "门共宝奁长掩。"]'),
('song-ci-36','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','柳下玉骢双鞚。',40,'宋词/ci.song.4000.json','["柳下玉骢双鞚。", "蝉鬓宝钿浮动。", "半醉倚迷楼，聊送斜阳三弄。", "豪纵。", "豪纵。", "一觉扬州春梦。"]'),
('song-ci-37','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','何处偷谐心赏。',40,'宋词/ci.song.4000.json','["何处偷谐心赏。", "促坐绮罗筵上。", "不记下楼时，醉□月侵书幌。", "怀想。", "怀想。", "清丽歌声妆样。"]'),
('song-ci-38','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','江上潮回风细。',40,'宋词/ci.song.4000.json','["江上潮回风细。", "红袖倚楼凝睇。", "天际认归舟，但见平林如荠。", "迢递。", "迢递。", "人更远於天际。"]'),
('song-ci-39','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','梦想山阴游冶。',40,'宋词/ci.song.4000.json','["梦想山阴游冶。", "深径碧桃花谢。", "曲水稳流觞，暖絮芳兰堪藉。", "萧洒。", "萧洒。", "月棹烟蓑东下。"]'),
('song-ci-40','凤栖梧・蝶恋花','贺铸','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','挑菜踏青都过却。',70,'宋词/ci.song.4000.json','["挑菜踏青都过却。", "杨柳风轻，摆动秋千索。", "啼鸟自惊花自落。", "有人同在真珠箔。", "淡净衣裳妆□薄。", "闲凭银筝，睡鬓慵梳掠。", "试问为谁添瘦弱。", "娇羞只把眉颦著。"]'),
('song-ci-41','相思引','贺铸','宋','宋词','song-ci','相思引','[]','终日怀归翻送客。',92,'宋词/ci.song.4000.json','["终日怀归翻送客。", "春风祖席。", "南成陌。", "便莫惜。", "离觞频卷白。", "动管色。", "催行色。", "动管色。", "催行色。", "何处投鞍风雨夕。", "临水驿。", "空山驿。", "临水驿。", "空山驿。", "纵明月相思千里隔。", "梦咫尺。", "勤书尺。", "梦咫尺。", "勤书尺。"]'),
('song-ci-42','芳草渡・系裙腰','贺铸','宋','宋词','song-ci','芳草渡・系裙腰','[]','留征辔，送离杯。',71,'宋词/ci.song.4000.json','["留征辔，送离杯。", "羞泪下，拈青梅。", "低声问道几时回。", "秦筝雁促，此夜为谁排。", "君去也，远蓬莱。", "千里地，信音乖。", "相思成病底情怀。", "和烦恼，寻个便，送将来。"]'),
('song-ci-43','雨中花・夜行船','贺铸','宋','宋词','song-ci','雨中花・夜行船','[]','回首扬州，猖狂十载，依然一梦归来。',119,'宋词/ci.song.4000.json','["回首扬州，猖狂十载，依然一梦归来。", "但觉安仁愁鬓，几点尘埃。", "醉墨碧纱犹锁，春衫白纻新裁。", "认鸣珂曲里，旧日朱扉，闲闭青苔。", "人非物是，半晌鸾肠易断，宝勒空回。", "徒怅望、碧云销散，明月徘徊。", "忍过阳台折柳，难凭陇驿传梅。", "一番桃李，迎风无语，谁是怜才。"]'),
('song-ci-44','花心动','贺铸','宋','宋词','song-ci','花心动','[]','西郭园林，远尘烦，门临绿杨堤路。',127,'宋词/ci.song.4000.json','["西郭园林，远尘烦，门临绿杨堤路。", "画□簟长，水馆帘空，竟日素襟销暑。", "小湾红芰清香里，深隐映、风标鸳鹭。", "指□□，相将故故，背人飞去。", "翻念多情自苦。", "当置酒徵歌，梦云难驻。", "醉眼渐迷，花拂墙低，误认宋邻偷顾。", "彩阑倚遍平桥晚，空相望、凌波仙步。", "断魂处，黄昏翠荷□雨。"]'),
('song-ci-45','浪淘沙','贺铸','宋','宋词','song-ci','浪淘沙','[]','把酒欲歌骊。',64,'宋词/ci.song.4000.json','["把酒欲歌骊。", "浓醉何辞。", "玉京烟柳欲黄时。", "明日景阳门外路，相背春归。", "敛泪复牵衣。", "私语迟迟。", "可怜谁会两心期。", "惟有画帘斜月见，应共人知。"]'),
('song-ci-46','浪淘沙','贺铸','宋','宋词','song-ci','浪淘沙','[]','一十二都门。',64,'宋词/ci.song.4000.json','["一十二都门。", "梦想能频。", "无言桃李几经春。", "艳粉鲜香开自落，还为何人。", "白纻别时新。", "苒苒征尘。", "镜中消瘦老於真。", "赖有天涯风月在，依旧相亲。"]'),
('song-ci-47','浪淘沙','贺铸','宋','宋词','song-ci','浪淘沙','[]','潮涨湛芳桥。',64,'宋词/ci.song.4000.json','["潮涨湛芳桥。", "难渡兰桡。", "卷帘红袖莫相招。", "十二阑干今夜月，谁伴吹箫。", "烟草接亭皋。", "归思迢迢。", "兰成老去转无憀。", "偏恨秋风添鬓雪，不共魂销。"]'),
('song-ci-48','浪淘沙','贺铸','宋','宋词','song-ci','浪淘沙','[]','雨过碧云秋。',64,'宋词/ci.song.4000.json','["雨过碧云秋。", "烟草汀洲。", "远山相对一眉愁。", "可惜芳年桥畔柳，不系兰舟。", "为问木兰舟。", "何处淹留。", "相思今夜忍登楼。", "楼下谁家歌水调，明月扬州。"]'),
('song-ci-49','夜游宫','贺铸','宋','宋词','song-ci','夜游宫','[]','江面波纹皱縠。',71,'宋词/ci.song.4000.json','["江面波纹皱縠。", "江南岸、草和烟绿。", "初过寒食一百六。", "采苹游，□香裙，鸣佩玉。", "心事偷相属。", "赋春恨、彩笺双幅。", "今夜小楼吹凤竹。", "谢东风，寄情人，肠断曲。"]'),
('song-ci-50','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','莲叶初生南浦。',40,'宋词/ci.song.4000.json','["莲叶初生南浦。", "两岸绿杨飞絮。", "向晚鲤鱼风，断送彩帆何处。", "凝伫。", "凝伫。", "楼外一江烟雨。"]'),
('song-ci-51','忆仙姿・如梦令','贺铸','宋','宋词','song-ci','忆仙姿・如梦令','[]','彩舫解维官柳。',40,'宋词/ci.song.4000.json','["彩舫解维官柳。", "楼上谁家红袖。", "团扇弄微风，如为行人招手。", "回首。", "回首。", "云断武陵溪口。"]'),
('song-ci-52','菱花怨','贺铸','宋','宋词','song-ci','菱花怨','[]','叠鼓嘲喧，彩旗挥霍，苹汀薄晚，兰舟催解。',130,'宋词/ci.song.4000.json','["叠鼓嘲喧，彩旗挥霍，苹汀薄晚，兰舟催解。", "别浦潮平，小山云断，十幅饱帆风快。", "回想牵衣，愁掩啼妆，一襟香在。", "纨扇惊秋，菱花怨晚，谁共蛾黛。", "何处玉尊空，对松陵正美，鲈鱼苽菜。", "露洗凉蟾，潦吞平野，三万顷非尘界。", "览胜情无奈。", "恨难招、越人同载。", "会凭紫燕西飞，更约黄鹂相待。"]'),
('song-ci-53','望扬州・长相思慢','贺铸','宋','宋词','song-ci','望扬州・长相思慢','[]','铁瓮城高，蒜山渡阔，干云十二层楼。',128,'宋词/ci.song.4000.json','["铁瓮城高，蒜山渡阔，干云十二层楼。", "开尊待月，卷箔披风，依然灯火扬州。", "绣陌南头。", "记歌名宛转，乡号温柔。", "曲槛俯清流。", "想花阴、谁系兰舟。", "念凄绝秦弦，感深荆赋，相望几许凝愁。", "殷勤裁尺素，奈双鱼、难渡瓜洲。", "晓鉴堪羞。", "潘鬓点、吴霜渐稠。", "幸于飞、鸳鸯未老，不应同是悲秋。"]'),
('song-ci-54','定情曲','贺铸','宋','宋词','song-ci','定情曲','[]','沈水浓熏，眉粉淡妆，露华鲜映春晓。',123,'宋词/ci.song.4000.json','["沈水浓熏，眉粉淡妆，露华鲜映春晓。", "浅颦轻笑。", "真物外，一种闲花风调。", "可待合欢翠被，不见忘忧芳草。", "拥膝浑忘羞，回身就郎抱。", "两点灵犀心颠倒。", "念乐事稀逢，归期须早。", "五云闻道。", "星桥畔、油壁车迎苏小。", "引领西陵自远，携手东山偕老。", "殷勤制、双凤新声，定情永为好。"]'),
('song-ci-55','拥鼻吟・吴音子','贺铸','宋','宋词','song-ci','拥鼻吟・吴音子','[]','别酒初销，怃然弭棹蒹葭浦。',97,'宋词/ci.song.4000.json','["别酒初销，怃然弭棹蒹葭浦。", "回首不见高城，青楼更何许。", "大艑轲峨，越商巴贾。", "万恨龙锺，篷下对语。", "指征路。", "山缺处，孤烟起，历历闻津鼓。", "江豚吹浪，晚来风转夜深雨。", "拥鼻微吟，断肠新句。", "粉碧罗笺，封泪寄与。"]'),
('song-ci-56','思越人・朝天子','贺铸','宋','宋词','song-ci','思越人・朝天子','[]','京口瓜洲记梦间。',64,'宋词/ci.song.4000.json','["京口瓜洲记梦间。", "朱扉犹想映花关。", "东风太是无情思，不许扁舟兴尽还。", "春水漫，夕阳闲。", "乌樯几转绿杨湾。", "红尘十里扬州过，更上迷楼一借山。"]'),
('song-ci-57','清平乐','贺铸','宋','宋词','song-ci','清平乐','[]','吴波不动。',54,'宋词/ci.song.4000.json','["吴波不动。", "四际晴山拥。", "载酒一尊谁与共。", "回首江湖旧梦。", "长艚珠箔青篷。", "橹声鸦轧征鸿。", "泪□镂檀香枕，醉眠摇□春风。"]'),
('song-ci-58','清平乐','贺铸','宋','宋词','song-ci','清平乐','[]','宋邻东畔。',54,'宋词/ci.song.4000.json','["宋邻东畔。", "明月关深院。", "玉指金徽调旧怨。", "楚客归心欲断。", "城隅芳草初春。", "佳期重约临分。", "丽句漫题双带，也愁系住行云。"]'),
('song-ci-59','清平乐','贺铸','宋','宋词','song-ci','清平乐','[]','厌厌别酒。',54,'宋词/ci.song.4000.json','["厌厌别酒。", "更执纤纤手。", "指似归期庭下柳。", "一叶西风前后。", "无端不系孤舟。", "载将多少离愁。", "又是十分明月，照人两处登楼。"]'),
('song-ci-60','木兰花・玉楼春','贺铸','宋','宋词','song-ci','木兰花・玉楼春','[]','嫣然何啻千金价。',64,'宋词/ci.song.4000.json','["嫣然何啻千金价。", "意远态闲难入画。", "更无方便只尊前，说尽牵情多少话。", "别来乐事经春罢。", "枉度佳春抛好夜。", "如今触绪易销魂，最是不堪风月下。"]'),
('song-ci-61','木兰花・玉楼春','贺铸','宋','宋词','song-ci','木兰花・玉楼春','[]','朝来著眼沙头认。',64,'宋词/ci.song.4000.json','["朝来著眼沙头认。", "五两竿摇风色顺。", "佳期学取弄潮儿，人纵无情潮有信。", "纷纷花雨红成阵。", "冷酒青梅寒食近。", "漫将江水比闲愁，水尽江头愁不尽。"]'),
('song-ci-62','减字木兰花','贺铸','宋','宋词','song-ci','减字木兰花','[]','春容秀润。',52,'宋词/ci.song.4000.json','["春容秀润。", "二十四番花有信。", "鸾镜佳人。", "得得浓妆样样新。", "情无远近。", "水阔山长分不尽。", "一断音尘。", "泪眼花前只见春。"]'),
('song-ci-63','减字木兰花','贺铸','宋','宋词','song-ci','减字木兰花','[]','闲情减旧。',52,'宋词/ci.song.4000.json','["闲情减旧。", "无奈伤春能作瘦。", "桂楫兰舟。", "几送人归我滞留。", "西门官柳。", "满把青青临别手。", "谁共登楼。", "分取烟波一段愁。"]'),
('song-ci-64','减字木兰花','贺铸','宋','宋词','song-ci','减字木兰花','[]','南园清夜。',52,'宋词/ci.song.4000.json','["南园清夜。", "临水朱阑垂柳下。", "从坐莲花。", "潋滟觥船泛露华。", "酒阑歌罢。", "双□前愁东去也。", "回想人家。", "芳草平桥一径斜。"]'),
('song-ci-65','减字木兰花','贺铸','宋','宋词','song-ci','减字木兰花','[]','多情多病。',52,'宋词/ci.song.4000.json','["多情多病。", "万斛闲愁量有剩。", "一顾倾城。", "惟觉尊前笑不成。", "探香幽径。", "好住东风谁主领。", "多谢流莺。", "欲别频啼四五声。"]'),
('song-ci-66','摊破木兰花・木兰花','贺铸','宋','宋词','song-ci','摊破木兰花・木兰花','[]','南浦东风落暮潮。',70,'宋词/ci.song.4000.json','["南浦东风落暮潮。", "祓禊人归，相并兰桡。", "回身昵语不胜娇。", "犹碍华灯，扇影频摇。", "重泛青翰顿寂寥。", "魂断高城手漫招。", "佳期应待鹊成桥。", "为问行云，谁伴朝朝。"]'),
('song-ci-67','摊破木兰花・木兰花','贺铸','宋','宋词','song-ci','摊破木兰花・木兰花','[]','芳草裙腰一尺围。',70,'宋词/ci.song.4000.json','["芳草裙腰一尺围。", "粉郎香润，清洒蔷薇。", "为嫌风日下楼稀。", "杨柳青阴，深闭朱扉。", "枉是尊前调玉徽。", "彩鸾何事逐鸡飞。", "楚台赋客莫相违。", "留住行云，好待郎归。"]'),
('song-ci-68','南乡子','贺铸','宋','宋词','song-ci','南乡子','[]','秋半雨凉天。',66,'宋词/ci.song.4000.json','["秋半雨凉天。", "望后清蟾未破圆。", "二十四桥游冶处，留连。", "携手娇饶步步莲。", "眉宇有馀妍。", "初破瓜时正妙年。", "玉局弹棋无限意，缠绵。", "肠断吴蚕两处眠。"]'),
('song-ci-69','南乡子','贺铸','宋','宋词','song-ci','南乡子','[]','柳岸舣兰舟。',66,'宋词/ci.song.4000.json','["柳岸舣兰舟。", "更结东山谢氏游。", "红泪清歌催落景，回头。", "□出尊前一段愁。", "东水漫西流。", "谁道行云肯驻留。", "无限鲜飙吹芷若，汀洲。", "生羡鸳鸯得自由。"]'),
('song-ci-70','临江仙','贺铸','宋','宋词','song-ci','临江仙','[]','暂假临淮东道主，每逃歌舞华筵。',68,'宋词/ci.song.4000.json','["暂假临淮东道主，每逃歌舞华筵。", "经年未办买山钱。", "筋骸难强，久坐沐猴禅。", "行拥一舟称浪士，五湖春水如天。", "越人相顾足嫣然。", "何须绣被，来伴拥蓑眠。"]'),
('song-ci-71','罗敷歌・采桑子','贺铸','宋','宋词','song-ci','罗敷歌・采桑子','[]','东山未办终焉计，聊尔西来。',52,'宋词/ci.song.4000.json','["东山未办终焉计，聊尔西来。", "花苑平台。", "倦客登临第几回。", "连延复道通驰道，十二门开。", "车马尘埃。", "怅望江南雪后梅。"]'),
('song-ci-72','点绛唇','贺铸','宋','宋词','song-ci','点绛唇','[]','一幅霜绡，麝煤熏腻纹丝缕。',50,'宋词/ci.song.4000.json','["一幅霜绡，麝煤熏腻纹丝缕。", "掩妆无语。", "的是销凝处。", "薄暮兰桡，漾下苹花渚。", "风留住。", "绿杨归路。", "燕子西飞去。"]'),
('song-ci-73','南歌子','贺铸','宋','宋词','song-ci','南歌子','[]','绣幕深朱户，熏炉小象床。',62,'宋词/ci.song.4000.json','["绣幕深朱户，熏炉小象床。", "扶肩醉被冒明珰。", "绣履可怜分破、两鸳鸯。", "梦枕初回雨，啼钿半□妆。", "一钩新月渡横塘。", "谁认凌波微步、袜尘香。"]'),
('song-ci-74','南歌子','贺铸','宋','宋词','song-ci','南歌子','[]','心蹙黄金缕，梢垂白玉团。',62,'宋词/ci.song.4000.json','["心蹙黄金缕，梢垂白玉团。", "孤芳不怕雪霜寒。", "先向百花头上、探春□。", "傍水添新韵，横墙露粉颜。", "夜来和月起凭阑。", "认得暗香微度、有无间。"]'),
('song-ci-75','小重山','贺铸','宋','宋词','song-ci','小重山','[]','一叶西风生嫩凉。',70,'宋词/ci.song.4000.json','["一叶西风生嫩凉。", "彩舟旗影动，背斜阳。", "溪流几曲似回肠。", "高城远，今夜为谁长。", "正节号清狂。", "苎萝标韵美，倚新妆。", "月华歌调转清商。", "尊酒畔，好住伴刘郎。"]'),
('song-ci-76','清平乐','贺铸','宋','宋词','song-ci','清平乐','[]','林皋叶脱。',54,'宋词/ci.song.4000.json','["林皋叶脱。", "楼下清江阔。", "船里琵琶金捍拨。", "弹断么弦再抹。", "夜潮州渚生寒。", "城头星斗阑干。", "忍话旧游新梦，三千里外长安。"]'),
('song-ci-77','清平乐','贺铸','宋','宋词','song-ci','清平乐','[]','沈侯销瘦。',54,'宋词/ci.song.4000.json','["沈侯销瘦。", "八咏新题就。", "惆怅酒醒兼梦后。", "带眼如何复旧。", "几时一叶兰舟。", "画桡鸦轧东流。", "新市小桥西畔，有人长倚妆楼。"]'),
('song-ci-78','木兰花・玉楼春','贺铸','宋','宋词','song-ci','木兰花・玉楼春','[]','罗巾粉汗和香浥。',64,'宋词/ci.song.4000.json','["罗巾粉汗和香浥。", "纤指留痕红一捻。", "离亭再卜和欢期，寻见石榴双翠叶。", "危楼欲上危肠怯。", "纵得鸾胶难寸接。", "西风燕子会来时，好付小笺封泪帖。"]'),
('song-ci-79','玉连环・一落索','贺铸','宋','宋词','song-ci','玉连环・一落索','[]','别酒更添红粉泪。',58,'宋词/ci.song.4000.json','["别酒更添红粉泪。", "促成愁醉。", "相逢浅笑合微吟，撩惹到、缠绵地。", "花下解携重附耳。", "佳期深记。", "青翰舟稳绣衾香，谁禁断、东流水。"]'),
('song-ci-80','惜奴娇','贺铸','宋','宋词','song-ci','惜奴娇','[]','玉立佳人，韵不减、吴苏小。',94,'宋词/ci.song.4000.json','["玉立佳人，韵不减、吴苏小。", "赋深情、华年韶妙。", "叠鼓新歌，最能作、江南调。", "缥缈。", "似阳台、娇云弄晓。", "有客临风，梦后拟、池塘草。", "竟装怀、□愁多少。", "绿绮芳尊，映花月、东山道。", "正要。", "个卿卿、嫣然一笑。"]'),
('song-ci-81','蓦山溪','贺铸','宋','宋词','song-ci','蓦山溪','[]','画桥流水，宛是南州路。',102,'宋词/ci.song.4000.json','["画桥流水，宛是南州路。", "转柁绿杨湾，恍然间、青楼旧处。", "回肠断尽，犹剩尔多愁，记新声，怀昵语。", "依约对眉宇。", "袜罗香在，祗欠莲随步。", "无物比朝云，恨难续、高唐后赋。", "迢遥此夜，泪枕不成眠，月侵窗，灯映户。", "应见可怜许。"]'),
('song-ci-82','西江月','贺铸','宋','宋词','song-ci','西江月','[]','携手看花深径，扶肩待月斜廊。',58,'宋词/ci.song.4000.json','["携手看花深径，扶肩待月斜廊。", "临分少伫已伥伥。", "此段不堪回想。", "欲寄书如天远，难销夜似年长。", "小窗风雨碎人肠。", "更在孤舟枕上。"]'),
('song-ci-83','摊破木兰花・木兰花','贺铸','宋','宋词','song-ci','摊破木兰花・木兰花','[]','桂叶眉丛恨自成。',72,'宋词/ci.song.4000.json','["桂叶眉丛恨自成。", "锦瑟弦调，双凤和鸣。", "钗梁玉胜挂兰缨。", "帘影沈沈，月堕参横。", "屏护文茵翠织成。", "摘佩牵裾，燕样腰轻。", "清溪百曲可怜生。", "大抵新欢，此夜□情。"]'),
('song-ci-84','点绛唇','贺铸','宋','宋词','song-ci','点绛唇','[]','十二层楼，梦回缥缈非烟里。',50,'宋词/ci.song.4000.json','["十二层楼，梦回缥缈非烟里。", "此情何寄。", "赖尔荆江水。", "莫谓东君，触处逢桃李。", "留深意。", "温柔乡里。", "自有终焉计。"]'),
('song-ci-85','诉衷情','贺铸','宋','宋词','song-ci','诉衷情','[]','不堪回首卧云乡。',54,'宋词/ci.song.4000.json','["不堪回首卧云乡。", "羁宦负清狂。", "年来镜湖风月，鱼鸟两相忘。", "秦塞险，楚山苍。", "更斜阳。", "画桥流水，曾见扁舟，几度刘郎。"]'),
('song-ci-86','诉衷情','贺铸','宋','宋词','song-ci','诉衷情','[]','半销檀粉睡痕新。',54,'宋词/ci.song.4000.json','["半销檀粉睡痕新。", "背镜照樱唇。", "临风再歌团扇，深意属何人。", "轻调笑，浅凝颦。", "认情亲。", "最难堪酒，似不胜情，依样伤春。"]'),
('song-ci-87','怨三三','贺铸','宋','宋词','song-ci','怨三三','[]','玉津春水如蓝。',61,'宋词/ci.song.4000.json','["玉津春水如蓝。", "宫柳毵毵。", "桥上东风侧帽檐。", "记佳节、约是重三。", "飞楼十二珠帘。", "恨不贮、当年彩蟾。", "对梦雨廉纤。", "愁随芳草，绿遍江南。"]'),
('song-ci-88','醉春风','贺铸','宋','宋词','song-ci','醉春风','[]','楼外屏山秀。',78,'宋词/ci.song.4000.json','["楼外屏山秀。", "凭阑新梦后。", "归云何许误心期，候候候。", "到陇梅花，渡江桃叶，断魂招手。", "楚制汗衫旧。", "啼妆曾枕袖。", "东阳咏罢不胜情，瘦瘦瘦。", "隋岸伤离，渭城怀远，一枝烟柳。"]'),
('song-ci-89','忆秦娥','贺铸','宋','宋词','song-ci','忆秦娥','[]','晓朦胧。',56,'宋词/ci.song.4000.json','["晓朦胧。", "前溪百鸟啼匆匆。", "啼匆匆。", "凌波人去，拜月楼空。", "去年今日东门东。", "鲜妆辉映桃花红。", "桃花红。", "吹开吹落，一任东风。"]'),
('song-ci-90','忆秦娥','贺铸','宋','宋词','song-ci','忆秦娥','[]','风惊幕。',56,'宋词/ci.song.4000.json','["风惊幕。", "灯前细雨檐花落。", "檐花落。", "玉台清镜，泪淹妆薄。", "良时不再须行乐。", "王孙莫负东城约。", "东城约。", "一分春色，为君留著。"]'),
('song-ci-91','忆秦娥','贺铸','宋','宋词','song-ci','忆秦娥','[]','著春衫。',56,'宋词/ci.song.4000.json','["著春衫。", "玉鞭鞭马南城南。", "南城南。", "柔条芳草，留驻金衔。", "粉娥采叶供新蚕。", "蚕饥略许携纤纤。", "携纤纤。", "湔裙淇上，更待初三。"]'),
('song-ci-92','河满子','贺铸','宋','宋词','song-ci','河满子','[]','每恨相逢薄处，可怜欲去迟回。',86,'宋词/ci.song.4000.json','["每恨相逢薄处，可怜欲去迟回。", "犹记新声团扇□，殷勤再引馀杯。", "为问依依杨柳，秋风好住章台。", "疏雨忽随云断，斜阳却送潮回。", "桃叶青山长在眼，几时双楫迎来。", "如待碧阑红药，一年两度花开。"]'),
('song-ci-93','御街行','贺铸','宋','宋词','song-ci','御街行','[]','松门石路秋风扫。',94,'宋词/ci.song.4000.json','["松门石路秋风扫。", "似不许、飞尘到。", "双携纤手别烟萝，红粉清泉相照。", "几声歌管，正须陶写，翻作伤心调。", "岩阴暝色归云悄。", "恨易失、千金笑。", "更逢何物可忘忧，为谢江南芳草。", "断桥孤驿，冷云黄叶，相见长安道。"]'),
('song-ci-94','连理枝','贺铸','宋','宋词','song-ci','连理枝','[]','绣幌闲眠晓。',86,'宋词/ci.song.4000.json','["绣幌闲眠晓。", "处处闻啼鸟。", "枕上无情，斜风横雨，落花多少。", "想灞桥、春色老於人，恁江南梦杳。", "往事今何道。", "聊咏池塘草。", "怀县年来，萧萧壮发，可堪频照。", "赖醉乡、佳境许徜徉，惜归欤不早。"]'),
('song-ci-95','金凤钩','贺铸','宋','宋词','song-ci','金凤钩','[]','江南又叹流寓。',67,'宋词/ci.song.4000.json','["江南又叹流寓。", "指芳物、伴人迟暮。", "搅晴风絮。", "弄寒烟雨。", "春去更无寻处。", "石城楼观青霞举。", "想艇子、寄谁容与。", "断云荆渚。", "限潮湓浦。", "不见莫愁归路。"]'),
('song-ci-96','芳洲泊・踏莎行','贺铸','宋','宋词','song-ci','芳洲泊・踏莎行','[]','露叶栖萤，风枝袅鹊。',68,'宋词/ci.song.4000.json','["露叶栖萤，风枝袅鹊。", "水堂离燕褰珠箔。", "一声横玉吹流云，厌厌凉月西南落。", "江际吴边，山侵楚角。", "兰桡明夜芳洲泊。", "殷勤留语采香人，清尊不负黄花约。"]'),
('song-ci-97','水调歌头','贺铸','宋','宋词','song-ci','水调歌头','[]','彼美吴姝唱，繁会阖闾邦。',114,'宋词/ci.song.4000.json','["彼美吴姝唱，繁会阖闾邦。", "千坊万井，斜桥曲水小轩窗。", "缥缈关山台观。", "罗绮云烟相半。", "金石压掁撞。", "痴信东归虏，黑自死心降。", "范夫子，高标韵，秀眉庞。", "功成长往，有人同载世无双。", "物外聊从吾好。", "赖尔工颦妍笑。", "伴醉玉连缸。", "尽任扁舟路，风雨卷秋江。"]'),
('song-ci-98','摊破浣溪沙・山花子','贺铸','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','曲磴斜阑出翠微。',56,'宋词/ci.song.4000.json','["曲磴斜阑出翠微。", "西州回首思依依。", "风物宛然长在眼，只人非。", "绿树隔巢黄鸟并，沧洲带雨白鸥飞。", "多谢子规啼劝我，不如归。"]'),
('song-ci-99','江南曲・踏莎行','贺铸','宋','宋词','song-ci','江南曲・踏莎行','[]','蝉韵清弦，溪横翠縠。',68,'宋词/ci.song.4000.json','["蝉韵清弦，溪横翠縠。", "翩翩彩鹢帆开幅。", "黄帘绛幕掩香风，当筵灿灿人如玉。", "浅黛凝愁，明波转瞩。", "兰情似怨临行促。", "不辞寸断九回肠，殷勤更唱江南曲。"]'),
('song-ci-100','江南曲・踏莎行','贺铸','宋','宋词','song-ci','江南曲・踏莎行','[]','鸦轧齐桡，□冬叠鼓。',68,'宋词/ci.song.4000.json','["鸦轧齐桡，□冬叠鼓。", "浮骖晚下金牛渚。", "莫愁应自有愁时，篷窗今夜潇潇雨。", "杜若芳洲。", "芙蓉别浦。", "依依艳笑逢迎处。", "随潮风自石城来，潮回好寄人传语。"]'),
('song-ci-101','江南曲・踏莎行','贺铸','宋','宋词','song-ci','江南曲・踏莎行','[]','小苑浴兰，微波寄叶。',68,'宋词/ci.song.4000.json','["小苑浴兰，微波寄叶。", "石城回首山重沓。", "绮窗烟雨梦佳期，飞霞艇子雕檀楫。", "楼回披襟，廊长响屧。", "供愁麝月眉心帖。", "紫箫闲捻度新声，有人偷倚阑干掐。"]'),
('song-ci-102','楼下柳・天香','贺铸','宋','宋词','song-ci','楼下柳・天香','[]','满马京□，装怀春思，翩然笑度江南。',116,'宋词/ci.song.4000.json','["满马京□，装怀春思，翩然笑度江南。", "白鹭芳洲，青蟾雕舰，胜游三月初三。", "舞裙溅水，浴兰佩、绿染纤纤。", "归路要同步障，迎风会卷珠帘。", "离觞未容半酣。", "恨乌樯、已张轻帆。", "秋鬓重来淮上，几换新蟾。", "楼下会看细柳，正摇落清霜拂画檐。", "树犹如此，人何以堪。"]'),
('song-ci-103','吴门柳・渔家傲','贺铸','宋','宋词','song-ci','吴门柳・渔家傲','[]','窈窕盘门西转路。',72,'宋词/ci.song.4000.json','["窈窕盘门西转路。", "残阳映带青山暮。", "最是长杨攀折苦。", "堪怜许。", "清霜翦断和烟缕。", "春水归期端不负。", "依依照影临南浦。", "留取木兰舟少住。", "无风雨。", "黄昏月上潮平去。"]'),
('song-ci-104','吴门柳・渔家傲','贺铸','宋','宋词','song-ci','吴门柳・渔家傲','[]','啸度万松千步岭。',72,'宋词/ci.song.4000.json','["啸度万松千步岭。", "钱湖门外非尘境。", "见底碧漪如眼净。", "岚光映。", "镜屏百曲新磨莹。", "好月为人重破瞑。", "云头艳艳开金饼。", "传语桂娥应奈静。", "堪乘兴。", "尊前听我游仙咏。"]'),
('song-ci-105','雁後归・临江仙','贺铸','宋','宋词','song-ci','雁後归・临江仙','[]','巧翦合欢罗胜子，钗头春意翩翩。',70,'宋词/ci.song.4000.json','["巧翦合欢罗胜子，钗头春意翩翩。", "艳歌浅拜笑嫣然。", "愿郎宜此酒，行乐驻华年。", "未是文园多病客，幽襟凄断堪怜。", "旧游梦挂碧云边。", "人归落雁后，思发在花前。"]'),
('song-ci-106','雁後归・临江仙','贺铸','宋','宋词','song-ci','雁後归・临江仙','[]','鸦背夕阳山映断，绿杨风扫津亭。',70,'宋词/ci.song.4000.json','["鸦背夕阳山映断，绿杨风扫津亭。", "月生河影带疏星。", "青松巢白鸟，深竹逗流萤。", "隔水彩舟然绛蜡，碧窗想见娉婷。", "浴兰熏麝助芳馨。", "湘弦弹未半，凄怨不堪听。"]'),
('song-ci-107','雁後归・临江仙','贺铸','宋','宋词','song-ci','雁後归・临江仙','[]','翡翠楼高帘幕薄，温家小玉妆台。',70,'宋词/ci.song.4000.json','["翡翠楼高帘幕薄，温家小玉妆台。", "画眉难称怯人催。", "羞从面色起，娇逐语声来。", "门外木兰花艇子，垂杨风扫纤埃。", "平湖一镜绿萍开。", "缓歌轻调笑，薄暮采莲回。"]'),
('song-ci-108','鸳鸯梦・临江仙','贺铸','宋','宋词','song-ci','鸳鸯梦・临江仙','[]','午醉厌厌醒自晚，鸳鸯春梦初惊。',70,'宋词/ci.song.4000.json','["午醉厌厌醒自晚，鸳鸯春梦初惊。", "闲花深院听啼莺。", "斜阳如有意，偏傍小窗明。", "莫倚雕阑怀往事，吴山楚水纵横。", "多情人奈物无情。", "闲愁朝复暮，相应两潮生。"]'),
('song-ci-109','念彩云・夜游宫','贺铸','宋','宋词','song-ci','念彩云・夜游宫','[]','流水苍山带郭。',71,'宋词/ci.song.4000.json','["流水苍山带郭。", "寻尘迹、宛然如昨。", "犹记黄花携手约。", "误重来，小庭花，空自落。", "不怨兰情薄。", "可怜许、彩云漂泊。", "紫燕西飞书漫托。", "碧城中，几青楼，垂画幕。"]'),
('song-ci-110','烛影摇红','贺铸','宋','宋词','song-ci','烛影摇红','[]','波影翻帘，泪痕凝蜡青山馆。',58,'宋词/ci.song.4000.json','["波影翻帘，泪痕凝蜡青山馆。", "故人千里念佳期，襟佩如相款。", "惆怅更长梦短。", "但衾枕、馀芬剩暖。", "半窗斜月，照人肠断，啼鸟不管。"]'),
('song-ci-111','小重山','贺铸','宋','宋词','song-ci','小重山','[]','花院深疑无路通。',70,'宋词/ci.song.4000.json','["花院深疑无路通。", "碧纱窗影下，玉芙蓉。", "当时偏恨五更钟。", "分携处，斜月小帘栊。", "楚梦冷沈踪。", "一双金缕枕，半床空。", "画桥临水凤城东。", "楼前柳，憔悴几秋风。"]'),
('song-ci-112','绿头鸭・多丽','贺铸','宋','宋词','song-ci','绿头鸭・多丽','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','玉人家，画楼珠箔临津。',171,'宋词/ci.song.4000.json','["玉人家，画楼珠箔临津。", "托微风、彩箫流怨，断肠马上曾闻。", "燕堂开、艳妆丛里，调琴思、认歌颦。", "麝蜡烟浓，玉莲漏短，更衣不待酒初醺。", "绣屏掩、枕鸳相就，香气渐暾暾。", "回廊影，疏钟淡月，几许销魂。", "翠钗分、银笺封泪，舞鞋从此生尘。", "住兰舟、载将离恨，转南浦、背西曛。", "记取明年，蔷薇谢后，佳期应未误行云。", "凤城远，楚梅香嫩，先寄一枝春。", "青门外，祗凭芳草，寻访郎君。"]'),
('song-ci-113','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','秋水斜阳演漾金。',48,'宋词/ci.song.4000.json','["秋水斜阳演漾金。", "远山隐隐隔平林。", "几家村落几声砧。", "记得西楼凝醉眼，昔年风物似如今。", "只无人与共登临。"]'),
('song-ci-114','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','三扇屏山匝象床。',48,'宋词/ci.song.4000.json','["三扇屏山匝象床。", "背灯偷解素罗裳。", "粉肌和汗自生香。", "易失旧欢劳蝶梦，难禁新恨费鸾肠。", "今宵风月两相忘。"]'),
('song-ci-115','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','鼓动城头啼暮鸦。',48,'宋词/ci.song.4000.json','["鼓动城头啼暮鸦。", "过云时送雨些些。", "嫩凉如水透窗纱。", "弄影西厢侵户月，分香东畔拂墙花。", "此时相望抵天涯。"]'),
('song-ci-116','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','烟柳春梢蘸晕黄。',48,'宋词/ci.song.4000.json','["烟柳春梢蘸晕黄。", "井阑风绰小桃香。", "觉时帘幕又斜阳。", "望处定无千里眼，断来能有几回肠。", "少年禁取恁凄凉。"]'),
('song-ci-117','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','梦想西池辇路边。',48,'宋词/ci.song.4000.json','["梦想西池辇路边。", "玉鞍娇马小辎軿。", "春风十里斗婵娟。", "临水登山漂泊地，落花中酒寂寥天。", "个般情味已三年。"]'),
('song-ci-118','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','莲烛啼痕怨漏长。',48,'宋词/ci.song.4000.json','["莲烛啼痕怨漏长。", "吟蛩随月到回廊。", "一屏烟景画潇湘。", "连夜断无行雨梦，隔年犹有著人香。", "此情须信是难忘。"]'),
('song-ci-119','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','闲把琵琶旧谱寻。',48,'宋词/ci.song.4000.json','["闲把琵琶旧谱寻。", "四弦声怨却沈吟。", "燕飞人静画堂深。", "欹枕有时成雨梦，隔帘无处说春心。", "一从灯夜到如今。"]'),
('song-ci-120','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','鹦鹉无言理翠襟。',48,'宋词/ci.song.4000.json','["鹦鹉无言理翠襟。", "杏花零落昼阴阴。", "画桥流水半篙深。", "芳径与谁寻斗草，绣床终日罢拈针。", "小笺香管写春心。"]'),
('song-ci-121','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','鹦鹉惊人促下帘。',48,'宋词/ci.song.4000.json','["鹦鹉惊人促下帘。", "碧纱如雾隔香奁。", "雪儿窥镜晚蛾纤。", "乌鹊桥边河络角，鸳鸯楼外月西南。", "门前嘶马弄金衔。"]'),
('song-ci-122','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','宫锦袍熏水麝香。',48,'宋词/ci.song.4000.json','["宫锦袍熏水麝香。", "越纱裙染郁金黄。", "薄罗依约见明妆。", "绣陌不逢携手伴，绿窗谁是画眉郎。", "春风十里断人肠。"]'),
('song-ci-123','减字浣溪沙・浣溪沙','贺铸','宋','宋词','song-ci','减字浣溪沙・浣溪沙','[]','青翰舟中祓禊筵。',48,'宋词/ci.song.4000.json','["青翰舟中祓禊筵。", "粉娥窥影两神仙。", "酒阑飞去作非烟。", "重访旧游人不见，雨荷风蓼夕阳天。", "折花临水思茫然。"]'),
('song-ci-124','水龙吟','晁补之','宋','宋词','song-ci','水龙吟','[]','水晶宫绕千家，卞山倒影双溪里。',126,'宋词/ci.song.4000.json','["水晶宫绕千家，卞山倒影双溪里。", "白苹洲渚，诗成春晚，当年此地。", "行遍瑶台，弄英携手，月婵娟际。", "算多情小杜，风流未睹，空肠断、枝间子。", "一似君恩赐与，贺家湖、千峰凝翠。", "黄粱未熟，红旌已远，南柯旧事。", "常恐重来，夜阑相对，也疑非是。", "向松陵回首，平芜尽处，在青山外。"]'),
('song-ci-125','八声甘州','晁补之','宋','宋词','song-ci','八声甘州','["\u897f\u6e56"]','谓东坡、未老赋归来，天未遣公归。',118,'宋词/ci.song.4000.json','["谓东坡、未老赋归来，天未遣公归。", "向西湖两处秋波一种，飞蔼澄辉。", "又拥竹西歌吹，僧老木兰非。", "一笑千秋事，浮世危机。", "应倚平山栏槛，是醉翁饮处，江雨霏霏。", "送孤鸿相接，今古眼中稀。", "念平生、相从江海，任飘蓬、不遣此心违。", "登临事，更何须惜，吹帽淋衣。"]'),
('song-ci-126','八声甘州','晁补之','宋','宋词','song-ci','八声甘州','[]','谓东风、定是海冬来，海上最春先。',119,'宋词/ci.song.4000.json','["谓东风、定是海冬来，海上最春先。", "乍微阳破腊，梅心已省，柳意都远。", "雪后南山耸翠，平野欲生烟。", "记得相逢日，如上林边。", "莫叹春光易老，算今年春老，还有明年。", "叹人生难得，常好是朱颜。", "有随轩、金钗十二，为醉娇、一曲踏珠筵。", "功名事，算何如此，花下尊前。"]'),
('song-ci-127','满庭芳','晁补之','宋','宋词','song-ci','满庭芳','[]','鸥起苹中，鱼惊荷底，画船天上来时。',118,'宋词/ci.song.4000.json','["鸥起苹中，鱼惊荷底，画船天上来时。", "翠湾红渚，宛似武陵迷。", "更晚青山更好，孤云带、远雨丝垂。", "清歌里，金尊未掩，谁使动分携。", "竹林、高晋软，阿咸潇散，犹愧风期。", "便弃官终隐，钓叟苔矶。", "纵是鸣鸿云外，应念我、垂翼低飞。", "新词好，他年认取，天际片帆归。"]'),
('song-ci-128','凤凰台上忆吹箫','晁补之','宋','宋词','song-ci','凤凰台上忆吹箫','[]','千里相思，况无百里，何妨暮往朝还。',120,'宋词/ci.song.4000.json','["千里相思，况无百里，何妨暮往朝还。", "又正是、梅初淡伫，禽未绵蛮。", "陌上相逢缓辔，风细细、云日斑斑。", "新晴好，得意未妨，行尽青山。", "应携后房小妓，来为我，盈盈对舞花间。", "便拼了、松醪翠满，蜜炬红残。", "谁信轻鞍射虎，清世里、曾有人闲。", "都休说，帘外夜久春寒。"]'),
('song-ci-129','凤凰台上忆吹箫','晁补之','宋','宋词','song-ci','凤凰台上忆吹箫','[]','才短宫慵，命奇人弃，年年故里来远。',120,'宋词/ci.song.4000.json','["才短宫慵，命奇人弃，年年故里来远。", "记往岁、莲塘送我，远赴荆蛮。", "莫道风情似旧，青镜里、绿鬓新斑。", "佳人怪，把盏为我，微敛眉山。", "从来嗣宗高韵，独见赏，青云忧绝尘间。", "谩回首、平生醉语，一梦惊残。", "莫笑移花种柳，应备办、投老同闲。", "纵枯槁，松桧奈得霜寒。"]'),
('song-ci-130','摸鱼儿','晁补之','宋','宋词','song-ci','摸鱼儿','[]','买陂塘、旋栽杨柳，依稀淮岸江浦。',140,'宋词/ci.song.4000.json','["买陂塘、旋栽杨柳，依稀淮岸江浦。", "东皋嘉雨新痕涨，沙觜鸥来鹭聚。", "堪爱处。", "最好是、一川夜月光流渚。", "无人独舞。", "任翠幄张天，柔茵藉地，酒尽未能去。", "青绫被，莫忆金闺故步。", "儒冠曾把身误。", "弓刀千骑成何事，荒了邵平瓜圃。", "君试覰。", "满青镜、星星鬓影今如许。", "功名浪语。", "便似得班超，封侯万里，归计恐迟春。"]'),
('song-ci-131','永遇乐','晁补之','宋','宋词','song-ci','永遇乐','[]','松菊堂深，芰荷池小，长夏清暑。',128,'宋词/ci.song.4000.json','["松菊堂深，芰荷池小，长夏清暑。", "燕引雏还，鸠呼妇往，人静郊原趣。", "麦天已过，薄衣轻扇，试起绕园徐步。", "听衡宇、欣欣童稚，共说夜来初雨。", "苍菅径里，紫葳枝上，数点幽花垂露。", "东里催锄，西邻助晌，相戒清晨去。", "斜川归兴，け然满目，回首帝乡何处。", "只愁恐、轻鞭犯夜，灞陵旧路。"]'),
('song-ci-132','过涧歇','晁补之','宋','宋词','song-ci','过涧歇','[]','归去。',97,'宋词/ci.song.4000.json','["归去。", "奈故人、尚作青眼相期，未许明时归去。", "放怀处。", "买得东皋数亩，静爱园林趣。", "任过客、剥啄相呼昼扃户。", "堪笑儿童事业，华颠向谁语。", "草塘人悄，圆荷过微雨。", "都付邯郸，一枕清风，好梦初觉，砌下槐影方停午。"]'),
('song-ci-133','黄莺儿','晁补之','宋','宋词','song-ci','黄莺儿','[]','南园佳枝偏宜暑。',117,'宋词/ci.song.4000.json','["南园佳枝偏宜暑。", "两两三三修篁，新篁新出初齐，猗猗过檐侵户。", "听乱飐芰荷风，细洒梧桐雨。", "午馀帘影参差，远林蝉声，幽梦残处。", "凝伫。", "既往尽成空，暂遇何曾住。", "算人间事、岂足追思，依依梦中情绪。", "观数点茗浮花，一缕香萦炷。", "怪来人道陶潜，作得羲皇侣。"]'),
('song-ci-134','消息・永遇乐','晁补之','宋','宋词','song-ci','消息・永遇乐','[]','红日葵开，映墙遮牖，小斋端午。',128,'宋词/ci.song.4000.json','["红日葵开，映墙遮牖，小斋端午。", "杯展荷金，簪抽笋玉，幽事还数。", "绿窗纤手，朱奁轻缕。", "争斗彩丝艾虎。", "想沈江怨魄归来，空惆怅、对菰黍。", "朱颜老去，清风好在，未减佳辰欢聚。", "趣蜡酒深斟，菖葅细糁，围坐从儿女。", "还同子美，江村长夏，闲对燕飞鸥舞。", "算何须、楚王雄风，方消畏暑。"]'),
('song-ci-135','梁州令叠韵・梁州令','晁补之','宋','宋词','song-ci','梁州令叠韵・梁州令','[]','田野闲来惯。',118,'宋词/ci.song.4000.json','["田野闲来惯。", "睡起初惊晓燕。", "樵青走挂小帘钩，南园昨夜，细雨红芳遍。", "平芜一带烟光浅。", "过尽南归雁。", "俱远。", "凭阑送目空肠断。", "好景难常占。", "过眼韶华如箭。", "莫教鶗鴂送韶华，多情杨柳，为把长条绊。", "清尊满酌谁为伴。", "花下提壶劝。", "何妨醉卧花底，愁容不上春风面。"]'),
('song-ci-136','酒泉子','晁补之','宋','宋词','song-ci','酒泉子','[]','萱草戎葵，松菊堂深犹畏暑，晚云催雨霭帘栊。',54,'宋词/ci.song.4000.json','["萱草戎葵，松菊堂深犹畏暑，晚云催雨霭帘栊。", "满楼风。", "池莲翻倒小莲红。", "看扫鉴、天清似水，一轮明月却当空。", "画栏中。"]'),
('song-ci-137','归田乐','晁补之','宋','宋词','song-ci','归田乐','[]','春又去，似别佳人幽恨积。',63,'宋词/ci.song.4000.json','["春又去，似别佳人幽恨积。", "闲庭院，翠阴满，添昼寂。", "一枝梅最好，至今忆。", "正梦断，炉烟袅，参差疏帘隔。", "为何事、年年春恨，问花应会得。"]'),
('song-ci-138','诉衷情','晁补之','宋','宋词','song-ci','诉衷情','[]','东城南陌路歧斜。',54,'宋词/ci.song.4000.json','["东城南陌路歧斜。", "芳草遍藏遮。", "黄鹂自是来晚，莫恨海棠花。", "惊雪絮，满天涯。", "送春赊。", "问春莫是，忆著东君，自去还家。"]'),
('song-ci-139','金凤钩','晁补之','宋','宋词','song-ci','金凤钩','[]','春辞我向何处。',67,'宋词/ci.song.4000.json','["春辞我向何处。", "怪草草、夜来风雨。", "一簪华发，少欢饶恨，无计殢春且住。", "春回常恨寻无路。", "试向我、小园徐步。", "一阑红药，倚风含露。", "春自未曾归去。"]'),
('song-ci-140','金凤钩','晁补之','宋','宋词','song-ci','金凤钩','[]','雪消闲步花畔。',64,'宋词/ci.song.4000.json','["雪消闲步花畔。", "试屈指、早春将半。", "樱桃枝上最先到，却恨小梅芳浅。", "忽惊拂水双来燕。", "暗自忆、故人犹远。", "一分风雨占春愁，一来又对花肠断。"]'),
('song-ci-141','生查子','晁补之','宋','宋词','song-ci','生查子','[]','永日向人妍，百合忘忧草。',48,'宋词/ci.song.4000.json','["永日向人妍，百合忘忧草。", "午枕梦初回，远柳蝉声杳。", "藓井出冰泉，洗瀹烦襟了。", "却挂小帘钩，一缕炉烟袅。"]'),
('song-ci-142','行香子','晁补之','宋','宋词','song-ci','行香子','[]','前岁栽桃，今岁成蹊。',84,'宋词/ci.song.4000.json','["前岁栽桃，今岁成蹊。", "更黄鹂、久住相知。", "微行清露，细履斜晖。", "对林中侣，闲中我，醉中谁。", "何妨到老，常闲常醉，任功名、生事俱非。", "衰颜难强，拙语多迟。", "但酒同行，月同坐，影同嬉。"]'),
('song-ci-143','诉衷情','晁补之','宋','宋词','song-ci','诉衷情','[]','小园过午，便觉凉生翠柏。',91,'宋词/ci.song.4000.json','["小园过午，便觉凉生翠柏。", "戎葵闲出墙红，萱草静依径绿。", "还是去年，浮瓜沈李，追凉故绕池边竹。", "小筵促。", "忽忆杨梅正熟。", "下山南畔，画舸笙歌逐。", "愁凝目。", "使君彩笔，佳人锦字，断弦怎续。", "尽日栏干曲。"]'),
('song-ci-144','木兰花・玉楼春','晁补之','宋','宋词','song-ci','木兰花・玉楼春','[]','小楼新创堪临远。',64,'宋词/ci.song.4000.json','["小楼新创堪临远。", "一带寒山都入眼。", "人间应未觉春归，楼上已先变柳眼。", "风威自与微阳战。", "雪意不遮残腊换。", "少须文栋燕双回，来看东城花一片。"]'),
('song-ci-145','行香子','晁补之','宋','宋词','song-ci','行香子','[]','归鸟翩翩，楼上黄昏。',84,'宋词/ci.song.4000.json','["归鸟翩翩，楼上黄昏。", "黯天气、残照馀痕。", "曲阑干里，有个愁人。", "向不言中，千载事，一年春。", "春来似客，春归如云。", "付楼前、行路双轮。", "倾江变酒，举斛为尊。", "断浮生外，愁千丈，不关身。"]'),
('song-ci-146','阮郎归','晁补之','宋','宋词','song-ci','阮郎归','[]','小楼独上暮锺时。',56,'宋词/ci.song.4000.json','["小楼独上暮锺时。", "红霞楼外飞。", "烟中远鸟一双归。", "城门灯火微。", "横短吹，傍危梯。", "冰轮涌海迟。", "天涯幽恨有谁知。", "凉风时动衣。"]'),
('song-ci-147','引驾行','晁补之','宋','宋词','song-ci','引驾行','[]','梅梢琼绽，东君次第开桃李。',124,'宋词/ci.song.4000.json','["梅梢琼绽，东君次第开桃李。", "痛年年、好风景，无事对花垂泪。", "园里。", "旧赏处、幽葩柔条，一一动芳意。", "恨心事。", "春来间阻，忆年时、把罗袂。", "雅戏。", "樱桃红颗，为插边明丽。", "又渐是。", "樱桃尝新，忍把旧游重记。", "何意。", "便云收雨歇，瓶沈簪折两无计。", "谩追悔。", "凭谁向说，只厌厌地。"]'),
('song-ci-148','碧牡丹','晁补之','宋','宋词','song-ci','碧牡丹','[]','渐老闲情减。',89,'宋词/ci.song.4000.json','["渐老闲情减。", "春山事、撩心眼。", "似血桃花，似雪梨花相间。", "望极雅川，阳焰迷归雁。", "征鞍方长坂。", "正魂乱。", "旧事如云散。", "良游盛年俱换。", "罢说功名，但觉青山归晚。", "记插宫花，扶醉蓬莱殿。", "如今霜尘满。"]'),
('song-ci-149','江神子・江城子','晁补之','宋','宋词','song-ci','江神子・江城子','[]','双鸳池沼水融融。',86,'宋词/ci.song.4000.json','["双鸳池沼水融融。", "桂堂东。", "又春风。", "今日看花，花胜去年红。", "把酒问花花不语，携手处，遍芳丛。", "留春且住莫匆匆。", "秉金笼。", "夜寒浓。", "沈醉插花，走马月明中。", "待得醒时君不见，不随水，即随风。"]'),
('song-ci-150','好事近','晁补之','宋','宋词','song-ci','好事近','[]','风雨过中秋，愁对画帘银烛。',53,'宋词/ci.song.4000.json','["风雨过中秋，愁对画帘银烛。", "那更气迟节晚，负重阳金菊。", "月期花信尚参差。", "功名更难卜。", "何事四时俱好，□一杯一曲。"]'),
('song-ci-151','洞仙歌','晁补之','宋','宋词','song-ci','洞仙歌','[]','花恨月恼。',156,'宋词/ci.song.4000.json','["花恨月恼。", "更夏有凉风，冬轩雪皎。", "闲事不关心，算四时皆好。", "从来又说，春台登览，人意多同，常是惜、春过了。", "须痛饮，莫放欢情草草。", "年少。", "尚忆瑶阶，得隽寻芳，骖驔东城，适见垂鞭，酕醄南陌，又逢低帽。", "莺花荡眼，功名满意，无限嬉游，荣华事、如梦杳。", "伤富贵浮云，曾萦怀抱。", "为春醉倒。", "愿花更好。", "春休老。", "开口笑。", "占醉乡、莫教人到。"]'),
('song-ci-152','洞仙歌','晁补之','宋','宋词','song-ci','洞仙歌','[]','当时我醉，美人颜色，如花堪悦。',154,'宋词/ci.song.4000.json','["当时我醉，美人颜色，如花堪悦。", "今日美人去，恨天涯离别。", "青楼朱箔，婵娟蟾桂，三五初圆，伤二八、还又缺。", "空伫立，一望一见心绝。", "心绝。", "顿成凄凉，千里音尘，一梦欢娱，推枕惊巫山远，洒泪对湘江阔。", "美人不见，愁人看花，心乱含愁，奏绿绮、弦清切。", "何处有知音，此恨难说。", "怨歌未阕。", "恐暮雨收、行云歇。", "窗梅发。", "乍似睹、芳容冰洁。"]'),
('song-ci-153','水龙吟','晁补之','宋','宋词','song-ci','水龙吟','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','问春何苦匆匆，带风伴雨如驰骤。',126,'宋词/ci.song.4000.json','["问春何苦匆匆，带风伴雨如驰骤。", "幽葩细萼，小园低槛，壅培未就。", "吹尽繁红，占春长久，不如垂柳。", "算春常不老，人愁春老，愁只是、人间有。", "春恨十常八九。", "忍轻辜、芳醪经口。", "那知自是，桃花结子，不因春瘦。", "世上功名，老来风味，春归时候。", "纵樽前痛饮，狂歌似旧，情难依旧。"]'),
('song-ci-154','洞仙歌','晁补之','宋','宋词','song-ci','洞仙歌','[]','裙芳老尽，海棠花时候。',102,'宋词/ci.song.4000.json','["裙芳老尽，海棠花时候。", "雨过寒轻好清昼。", "最妖饶一段，全是初开，云鬟小，涂粉施朱未就。", "全开还自好，骀荡春馀，百样宫罗斗繁绣。", "纵无语也，心应恨我来迟，恰柳絮、将春归后。", "醉犹倚柔柯，怯黄昏，这一点愁，须共花同瘦。"]'),
('song-ci-155','洞仙歌','晁补之','宋','宋词','song-ci','洞仙歌','[]','年年青眼。',102,'宋词/ci.song.4000.json','["年年青眼。", "为江梅肠断。", "一句新诗思无限。", "向碧琼枝上，白玉葩中、春犹浅。", "一点龙香清远。", "谁抛倾国艳。", "昨夜前村，都恐东皇未曾见。", "正倚墙红杏，芳意浓时，惊千片。", "何许飘零仙馆。", "待冰雪丛中看奇姿，乍一笑能回，上林冬暖。"]'),
('song-ci-156','行香子','晁补之','宋','宋词','song-ci','行香子','[]','雪里清香，月下疏枝。',84,'宋词/ci.song.4000.json','["雪里清香，月下疏枝。", "更无花、比并琼姿。", "一年一见，千绕千回。", "向未开时，愁花放，恐花飞。", "芳樽移就，幽葩折取，似玉人，携手同归。", "杨州应记，东阁逢时。", "恨刘郎误，题诗句，怨桃溪。"]'),
('song-ci-157','盐角儿','晁补之','宋','宋词','song-ci','盐角儿','[]','开时似雪。',63,'宋词/ci.song.4000.json','["开时似雪。", "谢时似雪。", "花中奇绝。", "香非在蕊，香非在萼，骨中香彻。", "占溪风，留溪月。", "堪羞损、山桃如血。", "直饶更、疏疏淡淡，终有一般情别。"]'),
('song-ci-158','清平乐','晁补之','宋','宋词','song-ci','清平乐','[]','黄花过也。',54,'宋词/ci.song.4000.json','["黄花过也。", "月酒何曾把。", "寒蝶多情爱潇洒。", "晴日双双飞下。", "沈吟独倚朱阑。", "采芳贻向□边。", "枕上醉排金靥，幽香付与谁怜。"]'),
('song-ci-159','江神子・江城子','晁补之','宋','宋词','song-ci','江神子・江城子','[]','去年初见早梅芳。',86,'宋词/ci.song.4000.json','["去年初见早梅芳。", "一春忙。", "短红墙。", "马上不禁、花恼只颠狂。", "苏晋长斋犹好事，时唤我，举离觞。", "今年春事更茫茫。", "浅宫妆。", "断人肠。", "一点多情、天赐骨中香。", "赖有飞凫贤令尹，同我过，小横塘。"]'),
('song-ci-160','望海潮','晁补之','宋','宋词','song-ci','望海潮','[]','人间花老，天涯春去，扬州别是风光。',129,'宋词/ci.song.4000.json','["人间花老，天涯春去，扬州别是风光。", "红药万株，佳名千种，天然浩态狂香。", "尊贵御衣黄。", "未便教西洛，独占花王。", "困倚东风，汉宫谁敢斗新妆。", "年年高会维阳。", "看家夸绝艳，人诧奇芳。", "结蕊当屏，联葩就幄，红遮绿绕华堂。", "花面映交相。", "更秉菅观洧，幽意难忘。", "罢酒风亭，梦魂惊恐在仙乡。"]'),
('song-ci-161','夜合花','晁补之','宋','宋词','song-ci','夜合花','[]','百紫千红，占春多少，共推绝世花王。',119,'宋词/ci.song.4000.json','["百紫千红，占春多少，共推绝世花王。", "西都万家俱好，不为姚黄。", "谩肠断巫阳。", "对沈香、亭北新妆。", "记清平调，词成进了，一梦仙乡。", "天葩秀出无双。", "倚朝晖，半如酣酒成狂。", "无言自有，檀心一点偷芳。", "念往事情伤。", "又新艳、曾说滁阳。", "纵归来晚，君王殿后，别是风光。"]'),
('song-ci-162','下水船','晁补之','宋','宋词','song-ci','下水船','[]','百紫千红翠。',90,'宋词/ci.song.4000.json','["百紫千红翠。", "唯有琼花特异。", "便是当年，唐昌观中玉蕊。", "尚记得、月里仙人来赏，明日喧传都市。", "甚时又，分与扬州本，一朵冰姿难比。", "曾向无双亭边，半酣独倚。", "似梦觉，晓出瑶台十里。", "犹忆飞琼标致。"]'),
('song-ci-163','浣溪沙','晁补之','宋','宋词','song-ci','浣溪沙','[]','雨过园亭绿暗时。',48,'宋词/ci.song.4000.json','["雨过园亭绿暗时。", "樱桃红颗压枝低。", "绿兼红好眼中迷。", "荔子天教生处远，风流一种阿谁知。", "最红深处有黄鹂。"]'),
('song-ci-164','万年欢','晁补之','宋','宋词','song-ci','万年欢','[]','心忆春归，似佳人未来，香径无迹。',120,'宋词/ci.song.4000.json','["心忆春归，似佳人未来，香径无迹。", "雪里江梅，因甚早知消息。", "百卉芳心正寂。", "夜不寐、幽姿脉脉。", "图清晓、先作宫妆，似防人见偷得。", "真香媚情动魄。", "算当时寿阳，无此标格。", "应寄扬州，何郎旧曾相识。", "花似何郎鬓白。", "恐花笑、逢花羞摘。", "那堪羌管惊心。", "也随繁杏抛掷。"]'),
('song-ci-165','感皇恩','晁补之','宋','宋词','song-ci','感皇恩','[]','常岁海棠时，偷闲须到。',81,'宋词/ci.song.4000.json','["常岁海棠时，偷闲须到。", "多病寻芳懒春老。", "偶来恰值，半谢妖绕犹好。", "便呼诗酒伴，同倾倒。", "繁枝高荫，疏枝低绕。", "花底杯盘花影照。", "多情一片，恨我归来不早。", "断肠铺碎锦，门前道。"]'),
('song-ci-166','洞仙歌','晁补之','宋','宋词','song-ci','洞仙歌','[]','今春闰好。',101,'宋词/ci.song.4000.json','["今春闰好。", "怪重阳菊早。", "满槛煌煌看霜晓。", "唤金钱翠雨，不称标容，潇洒意、陶潜诗中能道。", "不应夸绝艳，曾妒春华，因甚东君意不到。", "又似锁，三千汉女，偏教明妃、怨西风边草。", "也何必、牛山苦沾衣，算只好龙山，醉狂吹帽。"]'),
('song-ci-167','喜朝天・踏莎行','晁补之','宋','宋词','song-ci','喜朝天・踏莎行','[]','众芳残。',126,'宋词/ci.song.4000.json','["众芳残。", "海棠正轻盈，绿鬓朱颜。", "碎锦繁绣，更柔柯映碧，纤搊匀殷。", "谁与将红间白，采熏笼、仙衣覆斑斓。", "如有意、浓妆淡抹，斜倚阑干。", "夭饶向晚春后，惯困欹晴景，愁怕朝寒。", "纵有狂雨，便离披损，不奈幽闲。", "素李来禽总俗，谩遮映、终羞格疏顽。", "谁采顾，斜风教舞，月下庭间。"]'),
('song-ci-168','生查子','晁补之','宋','宋词','song-ci','生查子','[]','青帝晓来风，偏傍梅梢紧。',48,'宋词/ci.song.4000.json','["青帝晓来风，偏傍梅梢紧。", "未放玉肌开，已觉龙香喷。", "此意比佳人，争奈非朱粉。", "惟有许飞琼，风味依稀近。"]'),
('song-ci-169','少年游','晁补之','宋','宋词','song-ci','少年游','["\u5e90\u5c71"]','庐山瑶草四时春。',60,'宋词/ci.song.4000.json','["庐山瑶草四时春。", "烟锁上宫门。", "记得南游，偶寻飞涧，一洗庾公尘。", "香炉高咏君家事，文采近前人。", "它日骑鲸，尚怜迷路，与问众仙真。"]'),
('song-ci-170','少年游','晁补之','宋','宋词','song-ci','少年游','[]','如今田野谩抛春。',61,'宋词/ci.song.4000.json','["如今田野谩抛春。", "红雨掩衡门。", "懒读诗书，欠伸扶杖，几案任生尘。", "纵教便向东山老，谁知是个中人。", "莫怪年来，倦寻城市，嫌我性情真。"]'),
('song-ci-171','满江红','晁补之','宋','宋词','song-ci','满江红','[]','华鬓春风，长歌罢、伤今感昨。',115,'宋词/ci.song.4000.json','["华鬓春风，长歌罢、伤今感昨。", "春正好、瑶墀已叹，侍臣冥寞。", "牙帐尘昏馀剑戟，翠帷月冷虚弦索。", "记往岁、龙坂误曾登，今飘泊。", "贤人命，从来薄。", "流水意，知谁托。", "绕南枝身似，未眠飞鹊。", "射虎山边寻旧迹，骑鲸海上追前约。", "便江湖、与世永相忘，还堪乐。"]'),
('song-ci-172','离亭宴','晁补之','宋','宋词','song-ci','离亭宴','[]','丹府黄香堪笑。',84,'宋词/ci.song.4000.json','["丹府黄香堪笑。", "章台坠鞭年少。", "细雨春风花落处，醉里中人传诏。", "却上五湖船，悲歌楚狂同调。", "青草荆江波渺。", "香炉紫霄簪小。", "人去江山长依旧，幼妇空传辞妙。", "洒泪作招魂，枫林子规啼晓。"]'),
('song-ci-173','千秋岁','晁补之','宋','宋词','song-ci','千秋岁','[]','江头苑外。',87,'宋词/ci.song.4000.json','["江头苑外。", "常记同朝退。", "飞骑轧，鸣珂碎。", "齐呕云绕扇，赵舞风回带。", "严鼓断，杯盘藉草犹相对。", "洒涕谁能会。", "醉卧藤阴盖。", "人已去，词空在。", "兔园高宴悄，虎观英游改。", "重感慨，惊涛自卷珠沈海。"]'),
('song-ci-174','迷神引','晁补之','宋','宋词','song-ci','迷神引','[]','黯黯青山红日暮。',123,'宋词/ci.song.4000.json','["黯黯青山红日暮。", "浩浩大江东注。", "馀霞散绮，向烟波路。", "使人愁，长安远，在何处。", "几点渔灯小，迷近坞。", "一片客帆低，傍前浦。", "暗想平生，自悔儒冠误。", "觉阮途穷，归心阻。", "断魂素月，一千里、伤平楚。", "怪竹枝歌，声声怨，为谁苦。", "猿鸟一时啼，惊岛屿。", "烛暗不成眠，听津鼓。"]'),
('song-ci-175','满江红','晁补之','宋','宋词','song-ci','满江红','[]','莫话南征，船头转、三千馀里。',115,'宋词/ci.song.4000.json','["莫话南征，船头转、三千馀里。", "未叹此、浮生飘荡，但伤佳会。", "满眼青山芳草外，半篙碧水斜阳里。", "问此中、何处芰荷深，渔人指。", "清时事，羁游意。", "尽付与，狂歌醉。", "有多才南阮，自为知己。", "不似朱公江海去，未成陶令田园计。", "便楚乡、风景胜吾乡，何人对。"]'),
('song-ci-176','古阳关・阳关引','晁补之','宋','宋词','song-ci','古阳关・阳关引','[]','暮草蛩吟噎。',96,'宋词/ci.song.4000.json','["暮草蛩吟噎。", "暗柳萤飞灭。", "空庭雨过，西风紧，飘黄叶。", "卷书帷寂静，对此伤离别。", "重感叹、中秋数日又圆月。", "沙觜樯杆上，淮水阔。", "有飞凫客，词珠玉，气冰雪。", "且莫教皓月，照影惊华发。", "问几时、清尊夜景共佳节。"]'),
('song-ci-177','玉蝴蝶','晁补之','宋','宋词','song-ci','玉蝴蝶','[]','暗忆少年豪气，烂南国、蓬岛风光。',123,'宋词/ci.song.4000.json','["暗忆少年豪气，烂南国、蓬岛风光。", "醉倚吴王宫殿，不解悲凉。", "舞犹慵、小腰似柳，歌尚怯、娇语如簧。", "好林塘。", "玳筵留住，彩舫携将。", "清狂。", "扬州一梦，中山千日，名利都忘。", "细数从前，眼中欢事尽成伤。", "去船迷，乱花流水，遗佩悄、寒草空江。", "黯愁肠。", "暮云吟断，青鬓成霜。"]'),
('song-ci-178','安公子','晁补之','宋','宋词','song-ci','安公子','[]','柳老荷花尽。',124,'宋词/ci.song.4000.json','["柳老荷花尽。", "夜来霜落平湖净。", "征雁横天鸥舞乱，鱼游清镜。", "又还是、当年我向江南兴。", "移画船、深渚蒹葭映。", "对半篙碧水，满眼青山魂凝。", "一番伤华鬓。", "放歌狂饮犹堪逞。", "水驿孤帆明夜事，此欢重省。", "梦回处、诗塘春草愁难整。", "官情与、归期终朝竞。", "记它年相访，认取斜川三迳。"]'),
('song-ci-179','惜分飞','晁补之','宋','宋词','song-ci','惜分飞','[]','山水光中清无暑。',58,'宋词/ci.song.4000.json','["山水光中清无暑。", "是我消魂别处。", "只有多情雨。", "会人深意留人住。", "不见梅花来已暮。", "未见荷花又去。", "图画他年覰。", "断肠千古苕溪路。"]'),
('song-ci-180','惜分飞','晁补之','宋','宋词','song-ci','惜分飞','[]','消暑楼前双溪市。',58,'宋词/ci.song.4000.json','["消暑楼前双溪市。", "尽住水晶宫里。", "人共荷花丽。", "更无一点尘埃气。", "不会史君匆匆至。", "又作匆匆去计。", "谁解连红袂。", "大家都把兰舟系。"]'),
('song-ci-181','离亭宴','晁补之','宋','宋词','song-ci','离亭宴','[]','忆向吴兴假守。',84,'宋词/ci.song.4000.json','["忆向吴兴假守。", "双溪四垂高柳。", "仪凤桥边兰舟过，映水雕甍华牖。", "烛下小红妆，争看史君归后。", "携手松亭难又。", "题诗水轩依旧。", "多少绿荷相倚恨，背立西风回首。", "怅望采莲人，烟波万重吴岫。"]'),
('song-ci-182','满庭芳','晁补之','宋','宋词','song-ci','满庭芳','["\u5e90\u5c71"]','欲买庐山，山前三亩，小桥横过松间。',118,'宋词/ci.song.4000.json','["欲买庐山，山前三亩，小桥横过松间。", "变名吴市，谁认旧容颜。", "最好栖贤峡外，应自此、都隔尘寰。", "人稀到，壶中化国，光景更堪闲。", "无心，求至道，柴门闭了，饱睡甘飡。", "幸儿成孙长，为扫家山。", "若问它年归去，蓦地也、双桨来还。", "愁难舍，清风万壑，高处正跻攀。"]'),
('song-ci-183','满庭芳','晁补之','宋','宋词','song-ci','满庭芳','[]','闲说秋来，乘槎心懒，梦回三岛波间。',118,'宋词/ci.song.4000.json','["闲说秋来，乘槎心懒，梦回三岛波间。", "便思黄帽，同我老山颜。", "上界仙人官府，何似我、萧散尘寰。", "云无止，流泉自急，此意本来闲。", "寂寥，松桂圃，陪君好语，亦可望飡。", "况琼枝玉蕊，秀满春山。", "若问幽栖何意，莫道是、飞鸟知还。", "无言处，孙登半岭，高韵更难攀。"]'),
('song-ci-184','满庭芳','晁补之','宋','宋词','song-ci','满庭芳','[]','归去来兮，名山何处，梦中庐阜嵯峨。',118,'宋词/ci.song.4000.json','["归去来兮，名山何处，梦中庐阜嵯峨。", "二林深处，幽士往来多。", "自画远公莲社，教儿诵、李白长歌。", "如重到，丹崖翠户，琼草秀金坡。", "生绡，双幅上，诸贤中屦，文彩天梭。", "社中客，禅心古井无波。", "我似渊明逃社，怡颜盼、百尺庭柯。", "牛闲放，溪童任懒，吾已废鞭蓑。"]'),
('song-ci-185','尾犯','晁补之','宋','宋词','song-ci','尾犯','["\u5e90\u5c71"]','庐山小隐。',122,'宋词/ci.song.4000.json','["庐山小隐。", "渐年来疏懒，浸浓归兴。", "彩桥飞过，深溪地底，奔雷馀韵。", "香炉照日，望处与、青霄近。", "想群仙，呼我应远，怪来须丝垂镜。", "海上云车回轫。", "少姑传、金母信。", "森翠裾琼佩，落日初霞，纷纭相映。", "谁见壶中景。", "花洞里、杳然渔艇。", "别是个、潇洒乾坤，世情尘土休问。"]'),
('song-ci-186','尉迟杯','晁补之','宋','宋词','song-ci','尉迟杯','[]','去年时。',129,'宋词/ci.song.4000.json','["去年时。", "正愁绝，过却红杏飞。", "沈吟杏子青时。", "追悔负好花枝。", "今年又春到，傍小阑、日日数花期。", "花有信，人却无凭，故教芳意迟迟。", "及至待得融怡。", "未攀条拈蕊，已叹春归。", "怎得春如天不老，更教花与月相随。", "都将命、拼与酬花，似岘山、落日客犹迷。", "尽归路，拍手拦街，笑人沈醉如泥。"]'),
('song-ci-187','八六子','晁补之','宋','宋词','song-ci','八六子','[]','喜秋晴。',109,'宋词/ci.song.4000.json','["喜秋晴。", "淡云萦缕，天高群雁南征。", "正露冷初减兰红，风紧潜雕柳翠，愁人漏长梦惊。", "重阳景物凄清。", "渐老何时无事，当歌好在多情。", "暗自想、朱颜并游同醉，官名缰锁，世路蓬萍。", "难相见，赖有黄花满把，从教渌酒深倾。", "醉休醒。", "醒来旧愁旋生。"]'),
('song-ci-188','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','尽说彭门新半刾，昆吾剸玉如泥。',70,'宋词/ci.song.4000.json','["尽说彭门新半刾，昆吾剸玉如泥。", "功名馀事不须为。", "才情诗里见，风味酒边知。", "好在阿咸同老也，青云往岁心期。", "千锺百首兴来时。", "伯伦从妇劝，元亮信儿痴。"]'),
('song-ci-189','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','十岁儿曹同砚席，华裾织翠如葱。',70,'宋词/ci.song.4000.json','["十岁儿曹同砚席，华裾织翠如葱。", "一生心事醉吟中。", "相逢俱白首，无语对西风。", "莫道尊前情调减，衰颜得酒能红。", "可怜此会意无穷。", "夜阑人总睡，独绕菊花丛。"]'),
('song-ci-190','蓦山溪','晁补之','宋','宋词','song-ci','蓦山溪','[]','谯园幽古，烟锁前朝桧。',102,'宋词/ci.song.4000.json','["谯园幽古，烟锁前朝桧。", "摇落枣红时，满园空、几株苍翠。", "史君才誉，金殿握兰人。", "将风调，改荒凉，便是嬉游地。", "刘郎莫问，去后桃花事。", "司马更堪怜，掩金觞、琵琶催泪。", "愁来不醉。", "不醉奈愁何，汝南周，东阳沈，劝我如何醉。"]'),
('song-ci-191','蓦山溪','晁补之','宋','宋词','song-ci','蓦山溪','[]','金樽玉酒，佳味名仙桧。',102,'宋词/ci.song.4000.json','["金樽玉酒，佳味名仙桧。", "恐是九龙泉，堪一饮、霜毛却翠。", "何须说此，只但饮陶陶，灯光底，百花春，自是仙家地。", "星郎早贵，惯见风流事。", "留我不须归，倒尊空、烛堆红泪。", "飞凫令尹，才调更翩翩，休吊古，枉伤神，有兴来同醉。"]'),
('song-ci-192','蓦山溪','晁补之','宋','宋词','song-ci','蓦山溪','[]','兰台仙史，好在多情否。',102,'宋词/ci.song.4000.json','["兰台仙史，好在多情否。", "不寄一行书，过西风、飞鸿去后。", "功名心事，千载与君同，只狂饮，只狂吟，绿鬓殊非旧。", "山歌村馆，愁醉浔阳叟。", "且借两州春，看一曲、樽前舞袖。", "古来毕竟，何处是功名，不同饮，不同吟，也劝时开口。"]'),
('song-ci-193','蓦山溪','晁补之','宋','宋词','song-ci','蓦山溪','[]','扬州全盛，往事今何处。',102,'宋词/ci.song.4000.json','["扬州全盛，往事今何处。", "帆锦两明珠，罥蔷薇、月中嬉语。", "朱衣白面，公子似神仙，登云屿。", "临烟渚。", "狂醉成怀古。", "兰舟归后，谁与春为主。", "吟笑我重来，倚琼花、东风日暮。", "吴霜点鬓，流落共天涯，竹西路。", "高阳侣。", "魂梦应相遇。"]'),
('song-ci-194','忆秦娥','晁补之','宋','宋词','song-ci','忆秦娥','[]','牵人意。',56,'宋词/ci.song.4000.json','["牵人意。", "高堂照碧临烟水。", "清秋至。", "东山时伴，谢公携妓。", "黄菊虽残堪泛蚁。", "乍寒犹有重阳味。", "应相记。", "坐中少个，孟嘉狂醉。"]'),
('song-ci-195','好事近','晁补之','宋','宋词','song-ci','好事近','[]','丝管闹南湖，湖上醉游时晚。',53,'宋词/ci.song.4000.json','["丝管闹南湖，湖上醉游时晚。", "独看小桥官柳，泪无言偷满。", "坐中谁唱解愁辞，红妆劝金盏。", "物是奈人非是，负东风心眼。"]'),
('song-ci-196','阮郎归','晁补之','宋','宋词','song-ci','阮郎归','[]','西城北渚旧追随。',56,'宋词/ci.song.4000.json','["西城北渚旧追随。", "荒台今是非。", "白苹无主绿蒲迷。", "停舟忆旧时。", "双鸭戏，乱鸥飞。", "人家烟雨西。", "不成携手折芳菲。", "兰绕惆怅归。"]'),
('song-ci-197','阮郎归','晁补之','宋','宋词','song-ci','阮郎归','[]','一濠秋水净涟漪。',56,'宋词/ci.song.4000.json','["一濠秋水净涟漪。", "红妆照水嬉。", "攀条寻藕怯船移。", "浮萍湿绣衣。", "临好景，惜轻归。", "夕阳州渚迷。", "城门灯火簇轮蹄。", "沙鸥飞去时。"]'),
('song-ci-198','阮郎归','晁补之','宋','宋词','song-ci','阮郎归','[]','儿童嬉戏杏花堤。',56,'宋词/ci.song.4000.json','["儿童嬉戏杏花堤。", "春归不解悲。", "重来草露湿人衣。", "无花空绕枝。", "曾学道，久望机。", "一尊甘若饴。", "平生鱼鸟与同归。", "临风心自知。"]'),
('song-ci-199','宴桃源・如梦令','晁补之','宋','宋词','song-ci','宴桃源・如梦令','[]','往岁真源谪去。',40,'宋词/ci.song.4000.json','["往岁真源谪去。", "红泪扬州留住。", "饮罢一帆东，去入楚江寒雨。", "无绪。", "无绪。", "今夜秦淮泊处。"]'),
('song-ci-200','一丛花','晁补之','宋','宋词','song-ci','一丛花','["\u6d1e\u5ead\u6e56"]','王孙眉宇凤凰雏。',94,'宋词/ci.song.4000.json','["王孙眉宇凤凰雏。", "天与世情疏。", "扬州坐上琼花底，佩锦囊、曾忆奚奴。", "金盏醉挥，满身花影，红袖竞来扶。", "十年一梦访林居。", "离缺重踯躇。", "应怜肺病临邛客，寄洞庭、春色双壶。", "天气未佳，梅花正好，曾醉燕堂无。"]'),
('song-ci-201','一丛花','晁补之','宋','宋词','song-ci','一丛花','[]','碧山无意解银鱼。',94,'宋词/ci.song.4000.json','["碧山无意解银鱼。", "花底且携壶。", "华颠又喜熊罴且，笑骐骥，老反为驹。", "文史渐抛，功名更懒，随处见真如。", "高情敢并汉庭疏。", "长揖去田庐。", "囊无上赐金堪散，也未妨、山猎溪渔。", "廉颇纵强，莫随年少，白马向黄榆。"]'),
('song-ci-202','一丛花','晁补之','宋','宋词','song-ci','一丛花','[]','飞凫仙令气如虹。',94,'宋词/ci.song.4000.json','["飞凫仙令气如虹。", "脱屐向尘笼。", "凌烟画像云台议，似眼前、百草春风。", "盏里圣贤，壶中天地，高兴更谁同。", "应怀得隽大明宫。", "无事老冯公。", "玉山且向花间倒，任从笑、老入花丛。", "三径步馀，一枝眠稳，心事付千锺。"]'),
('song-ci-203','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','曾唱牡丹留客饮，明年何处相逢。',70,'宋词/ci.song.4000.json','["曾唱牡丹留客饮，明年何处相逢。", "忽惊鹊起落梧桐。", "绿荷多少恨，回首背西风。", "莫叹今宵身是客，一尊未晓犹同。", "此身应似去来鸿。", "江湖春水阔，归梦故园中。"]'),
('song-ci-204','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','常记河阳花县里，恰如饭颗山逢。',70,'宋词/ci.song.4000.json','["常记河阳花县里，恰如饭颗山逢。", "春城何处满丝桐。", "纶巾并羽扇，君有古人风。", "重向梁王台畔见，黄花绿酒谁同。", "新诗别后寄南鸿。", "回头思照碧，人在白云中。"]'),
('song-ci-205','浣溪沙','晁补之','宋','宋词','song-ci','浣溪沙','[]','帐饮都门春浪惊。',48,'宋词/ci.song.4000.json','["帐饮都门春浪惊。", "东飞身与白鸥轻。", "淮山一点眼初明。", "谁使梦回兰芷国，却将春去凤凰城。", "樯乌风转不胜情。"]'),
('song-ci-206','忆少年','晁补之','宋','宋词','song-ci','忆少年','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','无穷官柳，无情画舸，无根行客。',56,'宋词/ci.song.4000.json','["无穷官柳，无情画舸，无根行客。", "南山尚相送，只高城人隔。", "罨画园林溪绀碧。", "算重来、尽成陈迹。", "刘郎鬓如此，况桃花颜色。"]'),
('song-ci-207','江神子・江城子','晁补之','宋','宋词','song-ci','江神子・江城子','[]','旧山铅椠倦栖迟。',86,'宋词/ci.song.4000.json','["旧山铅椠倦栖迟。", "叩宸闱。", "向淮圻。", "五马行春，初喜后车随。", "太守风流容客醉，花压帽，酒淋衣。", "隋宫烟外草萋萋。", "菊花时。", "动旌旗。", "起舞留公，且住慰相思。", "王粲诗成何处寄，人北去，雁南飞。"]'),
('song-ci-208','虞美人','晁补之','宋','宋词','song-ci','虞美人','[]','江南载酒平生事。',66,'宋词/ci.song.4000.json','["江南载酒平生事。", "游宦如萍寄。", "蓬山归路傍银台。", "还是扬州一梦、却惊回。", "年年后土春来早。", "不负金尊倒。", "明年珠履赏春时。", "应寄琼花一朵、慰相思。"]'),
('song-ci-209','金盏倒垂莲','晁补之','宋','宋词','song-ci','金盏倒垂莲','[]','诸阮英游，尽千锺饮量，百丈词源。',112,'宋词/ci.song.4000.json','["诸阮英游，尽千锺饮量，百丈词源。", "对舞春风，螺髻小双莲。", "念两处、登高临远，又伤芳物新年。", "此泪不待，桓伊危柱哀弦。", "身闲未应无事，趁栽梅径里，插柳池边。", "野鹤飘颻，幽兴在青田。", "也莫话、书生豪气，更铭功业燕然。", "毕竟得意，何如月下花前。"]'),
('song-ci-210','金盏倒垂莲','晁补之','宋','宋词','song-ci','金盏倒垂莲','[]','休说将军，解弯弓掠地，崑岭河源。',112,'宋词/ci.song.4000.json','["休说将军，解弯弓掠地，崑岭河源。", "彩笔题诗，绿水映红莲。", "算总是、风流馀事，会须行乐□年。", "况有一部，随轩脆管繁弦。", "多情旧游尚忆，寄秋风万里，鸿雁天边。", "未学元龙，豪气笑求田。", "也莫为、庭槐兴叹，便伤摇落凄然。", "后会一笑，犹堪醉倒花前。"]'),
('song-ci-211','西平乐','晁补之','宋','宋词','song-ci','西平乐','[]','凤诏传来绛阕，当宁思贤辅。',125,'宋词/ci.song.4000.json','["凤诏传来绛阕，当宁思贤辅。", "淮海甘棠惠化，霖雨商岩吉梦，熊虎周郊旧卜。", "千秋盛际，催促朝天归去。", "动离绪。", "空眷恋，难暂驻。", "新植双亭临水，风月佳名未睹。", "准拟金尊时举。", "况乐府、风流一部。", "妍歌妙舞，萦云回雪，亲教与，恨难诉。", "争欲攀辕借住。", "功成绣衮，重与江山作主。"]'),
('song-ci-212','御街行','晁补之','宋','宋词','song-ci','御街行','[]','年年不放春闲了。',90,'宋词/ci.song.4000.json','["年年不放春闲了。", "今岁衔杯少。", "来时柳上浅金黄，归路玉眠吹帽。", "惜春长似，五陵狂俊，不道朱颜老。", "斜烟薄雨青林杳。", "犹有莺声到。", "西园红艳绿盘龙，辜负一年春好。", "锦城乐事，不关愁眼，何似还家早。"]'),
('song-ci-213','生查子','晁补之','宋','宋词','song-ci','生查子','[]','宫里妒娥眉，十载辞君去。',48,'宋词/ci.song.4000.json','["宫里妒娥眉，十载辞君去。", "翠袖怯天寒，修竹无人处。", "今日近君家，望极香车骛。", "一水是红墙，有恨无由语。"]'),
('song-ci-214','青玉案','晁补之','宋','宋词','song-ci','青玉案','[]','十年不向都门道。',81,'宋词/ci.song.4000.json','["十年不向都门道。", "信匹马、羞重道。", "玉府骖鸾犹年少。", "宫花头上，御炉烟底，常日朝回早。", "霞觞翻手群仙笑。", "恨尘土人间易春老。", "白发愁占彤庭杳。", "红墙天阻，碧濠烟锁，细雨迷芳草。"]'),
('song-ci-215','水龙吟','晁补之','宋','宋词','song-ci','水龙吟','[]','去年暑雨钩盘，夜阑睡起同征辔。',126,'宋词/ci.song.4000.json','["去年暑雨钩盘，夜阑睡起同征辔。", "今年芳草，齐河古岸，扁舟同舣。", "萍梗孤踪，梦魂浮世。", "别离常是。", "念当时绿鬓，狂歌痛饮，今憔悴、东风里。", "此去济南为说。", "道愁肠、不醒犹醉。", "多情北渚，两行烟柳，一湖春水。", "还唱新声，后人重到，应悲桃李。", "待归时，揽取庭前皓月，也应堪寄。"]'),
('song-ci-216','南歌子','晁补之','宋','宋词','song-ci','南歌子','[]','霜细犹欺柳，风柔已弄梅。',62,'宋词/ci.song.4000.json','["霜细犹欺柳，风柔已弄梅。", "东园捶鼓赏新醅。", "唤取舞周歌沈、探春回。", "妙舞堪千盏，长歌可百杯。", "笑人将恨上春台。", "劝我十分一举、两眉开。"]'),
('song-ci-217','醉落魄・一斛珠','晁补之','宋','宋词','song-ci','醉落魄・一斛珠','[]','高鸿远骛。',67,'宋词/ci.song.4000.json','["高鸿远骛。", "溪山一带人烟簇。", "知君船近渔矶宿。", "轻素横溪，天淡挂寒玉。", "谁家红袖阑干曲。", "南陵风软波平绿。", "幽吟无伴芳尊独。", "清瘦休文，一夜伤单縠。"]'),
('song-ci-218','万年欢','晁补之','宋','宋词','song-ci','万年欢','[]','忆惜论心，尽青云少年，燕赵豪俊。',122,'宋词/ci.song.4000.json','["忆惜论心，尽青云少年，燕赵豪俊。", "二十南游，曾上会稽千仞。", "捐袂江中往岁，有骚人、兰荪遗韵。", "嗟管鲍、当日贫交，半成翻手难信。", "君知未遇元礼，肯抽身盛时，寻我幽隐。", "此事谈何容易，骥才方骋。", "彩舫红妆围定，笑西风、黄花班鬓。", "君欲问、投老生涯，醉乡歧路偏近。"]'),
('song-ci-219','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','谪宦江城无屋买，残僧野寺相依。',70,'宋词/ci.song.4000.json','["谪宦江城无屋买，残僧野寺相依。", "松间药臼竹间衣。", "水穷行到处，云起坐看时。", "一个幽禽缘底事，苦来醉耳边啼。", "月斜西院愈声悲。", "青山无限好，犹道不如归。"]'),
('song-ci-220','虞美人','晁补之','宋','宋词','song-ci','虞美人','[]','原桑飞尽霜空杳。',68,'宋词/ci.song.4000.json','["原桑飞尽霜空杳。", "霜夜愁难晓。", "油灯野店怯黄昏。", "穷途不减酒杯深。", "故人心。", "羊山古道行人少。", "也送行人老。", "一般别语重千金。", "明年过我小园林。", "话如今。"]'),
('song-ci-221','安公子','晁补之','宋','宋词','song-ci','安公子','[]','少日狂游好。',126,'宋词/ci.song.4000.json','["少日狂游好。", "阆苑花间同低帽。", "不恨千金轻散尽，恨花残莺老。", "命小辔、翩翩随处金尊倒。", "从市人、拍手拦街笑。", "镇琼楼归卧，丽日三竿未觉。", "迷路桃源了。", "乱山沈水何由到。", "拨断朱弦成底事，痛知音人悄。", "似近日、曾教青鸟传佳耗。", "学凤箫、拟入烟萝道。", "问刘郎何计，解使红颜却少。"]'),
('song-ci-222','绿头鸭・多丽','晁补之','宋','宋词','song-ci','绿头鸭・多丽','[]','新秋近，晋公别馆开筵。',170,'宋词/ci.song.4000.json','["新秋近，晋公别馆开筵。", "喜清时、衔杯乐圣，未饶绿野堂边。", "绣屏深、丽人乍出，坐中雷雨起鵾弦。", "花暖间关，冰凝幽咽，宝钗摇动坠金钿。", "未弹了、昭君遗怨，四坐已凄然。", "西风里、香街驻马，嬉笑微传。", "算从来、司空惯，断肠初对云鬟。", "夜将阑、井梧下叶，砌蛩收响悄林蝉。", "赖得多愁，浔阳司马，当时不在绮筵前。", "竞叹赏、檀槽倚困，沈醉到觥船。", "芳春调、红英翠萼，重变新妍。"]'),
('song-ci-223','水龙吟','晁补之','宋','宋词','song-ci','水龙吟','[]','满湖高柳摇风，坐看骤雨来湖面。',126,'宋词/ci.song.4000.json','["满湖高柳摇风，坐看骤雨来湖面。", "跳珠溅玉，圆荷翻倒，轻鸥惊散。", "堂上凉生，槛前暑退，罗裾凌乱。", "想东山谢守，纶巾羽扇，高歌下、青天半。", "应记狂饮司马，去年时、黄花高宴。", "竹枝苦怨，琵琶多泪，新年鬓换。", "常恐归时，眼中物是，日边人远。", "望隋河一带，伤心雾霭，遣离魂断。"]'),
('song-ci-224','惜奴娇','晁补之','宋','宋词','song-ci','惜奴娇','[]','歌阕琼筵，暗失金貂侣。',91,'宋词/ci.song.4000.json','["歌阕琼筵，暗失金貂侣。", "说衷肠、丁宁嘱付。", "棹举帆开，黯行色、秋将暮。", "欲去。", "待却回、高城已暮。", "渔火烟村，但触目伤离绪。", "此情向、阿谁分诉。", "那里思量，争知我，思量苦。", "最苦。", "睡不著、西风夜雨。"]'),
('song-ci-225','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','身外闲愁空满眼，就中欢事常稀。',70,'宋词/ci.song.4000.json','["身外闲愁空满眼，就中欢事常稀。", "明年应赋送君诗。", "试从今夜数，相会几多时。", "浅酒欲邀谁共劝，深情唯有君知。", "东溪春近好同归。", "柳垂江上影，梅谢雪中枝。"]'),
('song-ci-226','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','自古齐山重九胜，登临梦想依依。',70,'宋词/ci.song.4000.json','["自古齐山重九胜，登临梦想依依。", "偶来恰值菊花时。", "难逢开口笑，须插满头归。", "昨夜一江风色好，平明秋浦帆飞。", "可怜如赴史君期。", "且当酬令节，不用叹斜晖。"]'),
('song-ci-227','满庭芳','晁补之','宋','宋词','song-ci','满庭芳','[]','乡物牵情，家山回首，浩然归兴难收。',118,'宋词/ci.song.4000.json','["乡物牵情，家山回首，浩然归兴难收。", "报恩心事，投老拼悠悠。", "却笑当年牛下，轻自许、激烈寒讴。", "成何事，夷犹桂楫，兰芷咏芳洲。", "人生，萍梗迹，谁非乐土，何处吾州。", "算不须，临歧惝恍迟留。", "要看香炉瀑布，丹枫乱、江色凝秋。", "真堪与，潇湘暮雨，图上画扁舟。"]'),
('song-ci-228','定风波','晁补之','宋','宋词','song-ci','定风波','[]','跨鹤扬州一梦回。',73,'宋词/ci.song.4000.json','["跨鹤扬州一梦回。", "东风佛面上平台。", "阆苑花前狂覆酒。", "拍手。", "东风骑凤却教来。", "谪好伯阳丹井畔。", "官满。", "平台还见片帆开。", "上界虽然官府好。", "总道。", "散仙无事好追陪。"]'),
('song-ci-229','千秋岁','晁补之','宋','宋词','song-ci','千秋岁','[]','玉京仙侣，同受琅函结。',87,'宋词/ci.song.4000.json','["玉京仙侣，同受琅函结。", "风雨隔，尘埃绝。", "霞觞翻手破，阆苑花前别。", "鹏翼敛，人间泛梗无由歇。", "岂忆山中酒，还共溪边月。", "愁闷火，时间灭。", "何妨心似水，莫遣头如雪。", "春近也，江南雁识归时节。"]'),
('song-ci-230','千秋岁','晁补之','宋','宋词','song-ci','千秋岁','[]','叶舟容易。',87,'宋词/ci.song.4000.json','["叶舟容易。", "行尽江南地。", "南雁断，无书至。", "怜君羁旅处。", "见我飘蓬际。", "如梦寐。", "当年阆苑曾相对。", "休说深心事。", "但付狂歌醉。", "那更话，孤帆起。", "水精溪绕户。", "云母山相砌。", "君莫去。", "只堪伴我溪山里。"]'),
('song-ci-231','鹧鸪天','晁补之','宋','宋词','song-ci','鹧鸪天','[]','欲上南湖采舫嬉。',64,'宋词/ci.song.4000.json','["欲上南湖采舫嬉。", "还思北渚与岚漪。", "圆荷盖水垂杨暗，鸂鶒鸳鸯总下时。", "持此意，遣谁知。", "清波还照鬓间丝。", "西楼重唱池塘好，应有红妆敛翠眉。"]'),
('song-ci-232','清平乐','晁补之','宋','宋词','song-ci','清平乐','[]','炎天畏景。',54,'宋词/ci.song.4000.json','["炎天畏景。", "午漏那堪永。", "何苦相仍愁簿领。", "短壑清溪牵兴。", "瑶台月下曾逢。", "何由却睹冰容。", "一笑为驱烦暑，故人元是清风。"]'),
('song-ci-233','虞美人','晁补之','宋','宋词','song-ci','虞美人','[]','荒城又见重阳到。',66,'宋词/ci.song.4000.json','["荒城又见重阳到。", "狂醉还吹帽。", "人生开口笑难逢。", "何况良辰一半，别离中。", "平台朱履登高处。", "犹自怀人否。", "且簪黄菊满头归。", "惟有此花风韵、似年时。"]'),
('song-ci-234','浣溪沙','晁补之','宋','宋词','song-ci','浣溪沙','[]','江上秋高风怒号。',48,'宋词/ci.song.4000.json','["江上秋高风怒号。", "江声不断雁嗷嗷。", "别魂调递为君销。", "一夜不眠孤客耳，耳边愁听雨萧萧。", "碧纱窗外有芭蕉。"]'),
('song-ci-235','万年欢','晁补之','宋','宋词','song-ci','万年欢','[]','十里环溪，记当年并游，依旧风景。',122,'宋词/ci.song.4000.json','["十里环溪，记当年并游，依旧风景。", "采舫红妆，重泛九秋清镜。", "莫叹歌台蔓草，喜相逢、欢情犹胜。", "苹洲畔、横玉惊鸾，半天云正愁凝。", "中秋醉魂未醒。", "又佳辰授衣，良会堪更。", "早岁功名，豪气尚凌汝颍。", "能致黄金一井，也莫负、鸱夷高兴。", "别有个、潇洒田园，醉乡天地同永。"]'),
('song-ci-236','一丛花','晁补之','宋','宋词','song-ci','一丛花','[]','东君密意在花心。',94,'宋词/ci.song.4000.json','["东君密意在花心。", "飞雪戏妆林。", "多情定怪春来晚，故穿花、千点深深。", "烟柳上轻，风丝漫袅，楼阁晚还阴。", "雕梁双燕悄来音。", "帘幕镇沈沈。", "西城未有花堪采，醉狂兴、冷落难禁。", "应约万红，商量细细，留向未开寻。"]'),
('song-ci-237','减字木兰花','晁补之','宋','宋词','song-ci','减字木兰花','[]','萍蓬行路。',52,'宋词/ci.song.4000.json','["萍蓬行路。", "来不多时还遣去。", "会有重来。", "还把清尊此地开。", "隋河杨柳。", "见我五年三执手。", "红泪多情。", "待得重来走马迎。"]'),
('song-ci-238','菩萨蛮','晁补之','宋','宋词','song-ci','菩萨蛮','[]','玉京不许尘容到。',52,'宋词/ci.song.4000.json','["玉京不许尘容到。", "疏慵只合疏慵老。", "鸥鸟共烟波。", "田夫与醉歌。", "忘怀无物我。", "莫似陈惊坐。", "勋业付长闲。", "西山爽气间。"]'),
('song-ci-239','鹧鸪天','晁补之','宋','宋词','song-ci','鹧鸪天','[]','吉梦灵蛇朱夏宜。',64,'宋词/ci.song.4000.json','["吉梦灵蛇朱夏宜。", "佳辰阿母会瑶池。", "竹风荷雨来消暑，玉李冰瓜可疗肌。", "心悟了，道成时。", "不劳龙女骋威仪。", "僧祗世界共游戏，贤懿光阴比寿期。"]'),
('song-ci-240','凤箫吟・芳草','晁补之','宋','宋词','song-ci','凤箫吟・芳草','[]','晓曈昽。',125,'宋词/ci.song.4000.json','["晓曈昽。", "雨和雨细，南园次第春融。", "岭梅犹妒雪，露桃云杏，已绽碧呈红。", "一年春正好，助人狂、飞燕游蜂。", "更吉梦良辰，对花忍负金锺。", "香浓。", "博山沈水，小楼清旦，佳气葱葱。", "旧游应未改，武陵花似锦，笑语相逢。", "蕊宫传妙诀，小金丹、同换冰容。", "况共有、芝田旧约，归去双峰。"]'),
('song-ci-241','梁州令','晁补之','宋','宋词','song-ci','梁州令','[]','二月春犹浅。',62,'宋词/ci.song.4000.json','["二月春犹浅。", "去年樱桃开遍。", "今年春色怪迟迟，红梅常早，未露胭脂脸。", "东君故遣春来缓。", "似会人深愿。", "蟠桃新镂，双盏相期，似此春长远。"]'),
('song-ci-242','引驾行','晁补之','宋','宋词','song-ci','引驾行','[]','春云轻锁，春风乍扇园林晓。',124,'宋词/ci.song.4000.json','["春云轻锁，春风乍扇园林晓。", "扫华堂，正桃李芳时，诞辰还到。", "年少。", "记绛蜡光摇，金猊香郁宝妆了。", "骤骏马、天街向晚，喜同车、咏窈窕。", "多少。", "卢家壶范，杜曲家声荣耀。", "庆孟光齐眉，冯唐白首，镇同欢笑。", "缥缈。", "待琅函深讨。", "芝田高隐去偕老。", "自别有、壶中永日，比人间好。"]'),
('song-ci-243','菩萨蛮','晁补之','宋','宋词','song-ci','菩萨蛮','[]','百花含蓓东风里。',52,'宋词/ci.song.4000.json','["百花含蓓东风里。", "南园小雨朱扉启。", "春色一年年。", "年年花共妍。", "清谈招隐去。", "莫认如宾处。", "华发好风光。", "林间此味长。"]'),
('song-ci-244','点绛唇','晁补之','宋','宋词','song-ci','点绛唇','[]','回雁风微，养花浓淡天容好。',50,'宋词/ci.song.4000.json','["回雁风微，养花浓淡天容好。", "似春知道。", "吉梦佳辰到。", "共乐春台，携手蓬莱小。", "同倾祷。", "愿春不老。", "岁岁寻芳草。"]'),
('song-ci-245','上林春・一落萦','晁补之','宋','宋词','song-ci','上林春・一落萦','[]','天惜中秋，三夜淡云，占得今宵明月。',127,'宋词/ci.song.4000.json','["天惜中秋，三夜淡云，占得今宵明月。", "孟陬岁好，金风气爽，清时挺生贤哲。", "相门出相，算锺庆、自应累叶。", "乍归来，暂燕处，共仰赤松高辙。", "想人生、会须自悦。", "浮云事，笑里尊前休说。", "旧有衮衣，公归未晚，千岁盛明时节。", "命圭相印，看重赏、晋公勋业。", "济生灵，共富寿，海山天阔。"]'),
('song-ci-246','杨柳枝','晁补之','宋','宋词','song-ci','杨柳枝','[]','素色清薰出俗华。',48,'宋词/ci.song.4000.json','["素色清薰出俗华。", "腊前花。", "轩前爱日扫云遮。", "几枝斜。", "月淡纱窗香暗透，白於纱。", "幽人独酌对芳葩。", "兴无涯。"]'),
('song-ci-247','蓦山溪','晁补之','宋','宋词','song-ci','蓦山溪','[]','凤凰山下，东畔青苔院。',102,'宋词/ci.song.4000.json','["凤凰山下，东畔青苔院。", "记得当初个，与玉人、幽欢小宴。", "黄昏风雨，人散不归家，帘旌卷。", "灯火颤。", "惊拥娇羞面。", "别来憔悴，偏我愁无限。", "歌酒情都减，也不独、朱颜改变。", "如今桃李，湖上泛舟时，青天晚。", "青山远。", "愿见无由见。"]'),
('song-ci-248','蓦山溪','晁补之','宋','宋词','song-ci','蓦山溪','[]','自来相识，比你情都可。',102,'宋词/ci.song.4000.json','["自来相识，比你情都可。", "咫尺千里算，惟孤枕、单衾知我。", "终朝尽日，无绪亦无言，我心里，忡忡也，一点全无那。", "香笺小字，写了千千个。", "我恨无羽翼，空寂寞、青苔院锁。", "昨朝冤我，却道不如休，天天天，不曾麽，因甚须冤我。"]'),
('song-ci-249','生查子','晁补之','宋','宋词','song-ci','生查子','[]','夜引别佳人，梅小犹飘雪。',48,'宋词/ci.song.4000.json','["夜引别佳人，梅小犹飘雪。", "忍泪一春愁，过却花时节。", "相见话相思，重与临风月。", "休似那回时，无事还轻别。"]'),
('song-ci-250','少年游','晁补之','宋','宋词','song-ci','少年游','[]','当年携手，是处成双，无人不羡。',62,'宋词/ci.song.4000.json','["当年携手，是处成双，无人不羡。", "自间阻、五年也，一梦拥、娇娇粉面。", "柳眉轻扫，杏腮微拂，依前双靥。", "盛睡里、起来寻觅，却眼前不见。"]'),
('song-ci-251','青玉案','晁补之','宋','宋词','song-ci','青玉案','[]','三年宋玉墙东畔。',79,'宋词/ci.song.4000.json','["三年宋玉墙东畔。", "怪相见、常低面。", "一曲文君芳心乱。", "匆匆依旧，吹散，月淡梨花馆。", "秋娘苦妒浮金盏。", "漏些子堪猜是娇盼。", "归去相思肠应断。", "五更无寐，一怀好事，依旧蓝桥远。"]'),
('song-ci-252','江城子','晁补之','宋','宋词','song-ci','江城子','[]','娉娉闻道似轻盈。',86,'宋词/ci.song.4000.json','["娉娉闻道似轻盈。", "好佳名。", "也堪称。", "楚观云归，重见小樊惊。", "豆蔻梢头春尚浅，娇未顾，已倾城。", "章台休咏旧青青。", "惹离情。", "恨难平。", "无事飞花，撩乱扑旗亭。", "不似刘郎春草小，能步步，伴人行。"]'),
('song-ci-253','青玉案','晁补之','宋','宋词','song-ci','青玉案','[]','彩云易散琉璃脆。',81,'宋词/ci.song.4000.json','["彩云易散琉璃脆。", "念往事、心将碎。", "只合人间十三岁。", "百花开尽，丁香独自，结恨春风里。", "小圆幽槛经行地。", "恨春草佳名谩抛弃。", "簇蝶罗裙休将施。", "香残烛烬，微风触幔，仿佛娇嚬是。"]'),
('song-ci-254','胜胜慢・声声慢','晁补之','宋','宋词','song-ci','胜胜慢・声声慢','[]','朱门深掩，摆荡春风，无情镇欲轻飞。',121,'宋词/ci.song.4000.json','["朱门深掩，摆荡春风，无情镇欲轻飞。", "断肠如雪，撩乱去点人衣。", "朝来半和细雨，向谁家、东馆西池。", "算未肯、似桃含红蕊，留待郎归。", "还记章台往事，别后纵青青，依旧时垂。", "灞岸行人多少，竟折柔枝。", "而今恨啼露叶，镇香街、抛掷因谁。", "又争可、妒郎夸春草，步步相随。"]'),
('song-ci-255','点绛唇','晁补之','宋','宋词','song-ci','点绛唇','[]','檀口星眸，艳如桃李情柔惠。',50,'宋词/ci.song.4000.json','["檀口星眸，艳如桃李情柔惠。", "据我心里。", "不肯相抛弃。", "哭怕人猜，笑又无滋味。", "忡忡地。", "系人心里。", "一句临歧誓。"]'),
('song-ci-256','永遇乐','晁补之','宋','宋词','song-ci','永遇乐','[]','银烛将残，玳筵初散，依旧愁绪。',128,'宋词/ci.song.4000.json','["银烛将残，玳筵初散，依旧愁绪。", "醉里凝眸，娇来纵体，此意难分付。", "怜伊只似，风前轻燕，好语暂来还去。", "重楼静，珠帘休下，待扫画梁留住。", "青娥浩齿，云鬓花面，见了绮罗无数。", "只你厌厌，教人竟日，一点无由诉。", "如今拼了，萦眠惹梦，没个顿身心处。", "深诚事，骖鸾解佩，是许未许。"]'),
('song-ci-257','虞美人','晁补之','宋','宋词','song-ci','虞美人','[]','梅花时候君轻去。',66,'宋词/ci.song.4000.json','["梅花时候君轻去。", "曾寄红笺句。", "胡麻好种少人知。", "正是归时何处、误芳期。", "谁教又作狂游远。", "归路杨花满。", "当年不负琐窗春。", "老向长楸走马、更愁人。"]'),
('song-ci-258','行香子','晁补之','宋','宋词','song-ci','行香子','[]','柳态纤柔，雪艳疏明。',84,'宋词/ci.song.4000.json','["柳态纤柔，雪艳疏明。", "问人来、人道轻盈。", "张琵莲脸，一寸横波。", "比潇洒处，犹难称，此嘉名。", "花前烛下，微频浅笑，要题诗、盏畔低声。", "司空自惯，狂眼须惊。", "也不辞写，双罗带，恐牵情。"]'),
('song-ci-259','感皇恩','晁补之','宋','宋词','song-ci','感皇恩','[]','终岁忆春回，西园行尽。',81,'宋词/ci.song.4000.json','["终岁忆春回，西园行尽。", "欢喜梅梢上春信。", "去年携手，暗约芳时还近。", "燕来莺又到，人无准。", "凭谁向道，流光一瞬。", "佳景闲无事衣褪。", "春归何处，又对飞花难问。", "旧欢都未遇，成新恨。"]'),
('song-ci-260','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','马上匆匆听鹊喜，朦胧月淡黄昏。',70,'宋词/ci.song.4000.json','["马上匆匆听鹊喜，朦胧月淡黄昏。", "碧罗双扇拥朝云。", "粉光先辨脸，朱色怎分唇。", "暂别宝奁蛛网遍，春风泪污榴裙。", "香笺小字寄行云。", "纤腰非学楚，宽带为思君。"]'),
('song-ci-261','碧牡丹','晁补之','宋','宋词','song-ci','碧牡丹','[]','院宇帘垂地。',92,'宋词/ci.song.4000.json','["院宇帘垂地。", "银筝雁、低春水。", "送出灯前，婀娜腰枝柳细。", "步蹙香裀，红浪随鸳履。", "梁州紧凤翘坠。", "悚轻体。", "绣带因风起。", "霓裳恐非人世。", "调促香檀，困入流波生媚。", "上客休辞，眼乱尊中翠。", "玉阶霜、透罗袂。"]'),
('song-ci-262','少年游','晁补之','宋','宋词','song-ci','少年游','[]','前时相见，楼头窗畔，尊酒望银蟾。',62,'宋词/ci.song.4000.json','["前时相见，楼头窗畔，尊酒望银蟾。", "如今间阻，银蟾又满，小阁下朱帘。", "愿得吴山山前雨，长恁晚帘纤。", "不见楼头婵娟月，且寂寞、闭窗眠。"]'),
('song-ci-263','西江月','晁补之','宋','宋词','song-ci','西江月','[]','似有如无好事，多离少会幽怀。',58,'宋词/ci.song.4000.json','["似有如无好事，多离少会幽怀。", "流莺过了又蝉催。", "肠断碧云天外。", "不寄书还可恨，全无梦也堪猜。", "秋风吹泪上楼台。", "只恐朱颜便改。"]'),
('song-ci-264','鹧鸪天','晁补之','宋','宋词','song-ci','鹧鸪天','[]','绣幕低低拂地垂。',64,'宋词/ci.song.4000.json','["绣幕低低拂地垂。", "春风何事入罗帏。", "胡麻好种无人种，正是归时君未归。", "临晚景，忆当时。", "愁心一动乱如丝。", "夕阳芳草本无恨，才子佳人空自悲。"]'),
('song-ci-265','满江红','晁补之','宋','宋词','song-ci','满江红','[]','月上西窗，书帏静、灯明又减。',115,'宋词/ci.song.4000.json','["月上西窗，书帏静、灯明又减。", "水漏涩、铜壶香炉，夜霜如雪。", "睡眼不曾通夕闭，梦魂争得连宵接。", "念碧云、川路古来长，无由越。", "鸾钗重，青丝滑。", "罗带缓，小腰怯。", "伊多感那更，恨离伤别。", "正是少年佳意气，渐当故里春时节。", "归去来、莫教子规啼，芳菲歇。"]'),
('song-ci-266','菩萨蛮','晁补之','宋','宋词','song-ci','菩萨蛮','[]','丝篁斗好莺羞巧。',52,'宋词/ci.song.4000.json','["丝篁斗好莺羞巧。", "红檀微映燕脂小。", "当□敛双蛾。", "曲中幽恨多。", "知君怜舞袖。", "舞要歌成就。", "独舞不成妍。", "因歌舞可怜。"]'),
('song-ci-267','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','离别寻常今白首，更须竹雨萧萧。',70,'宋词/ci.song.4000.json','["离别寻常今白首，更须竹雨萧萧。", "不应都占世间豪。", "清风居士手，杨柳洛城腰。", "文字功名真自误，从今好月良宵。", "只消怜取董娇饶。", "修门君自到，不用我词招。"]'),
('song-ci-268','临江仙','晁补之','宋','宋词','song-ci','临江仙','[]','君似苍崖千仞竹，一枝孤映蒿萧。',70,'宋词/ci.song.4000.json','["君似苍崖千仞竹，一枝孤映蒿萧。", "箪瓢不减万锺豪。", "闲情搔短发，佳句咏纤腰。", "罢酒兰舟回楚柂，相思何处今宵。", "淮南幽桂水云饶。", "他年春草恨，应有小山招。"]'),
('song-ci-269','紫玉箫','晁补之','宋','宋词','song-ci','紫玉箫','[]','罗绮丛中，笙歌丛里，眼狂初认轻盈。',123,'宋词/ci.song.4000.json','["罗绮丛中，笙歌丛里，眼狂初认轻盈。", "无花解比，似一钩新月，云际初生。", "算不虚得，都占与、第一佳名。", "轻归去，那知有人，别后牵情。", "襄王自是春梦，休谩说东墙，事更难凭。", "谁教慕宋，要题诗曾倚，宝柱低声。", "似瑶台晓，空暗想、众里飞琼。", "馀香冷、犹在小窗，一到魂惊。"]'),
('song-ci-270','斗百草','晁补之','宋','宋词','song-ci','斗百草','[]','别日常多，会时常少天难晓。',125,'宋词/ci.song.4000.json','["别日常多，会时常少天难晓。", "正喜花开，又愁花谢，春也似人易老。", "惨无言、念旧日朱颜，清欢莫笑。", "便苒苒如云，霏霏似雨，去无音耗。", "追想墙头梅下，门里桃边，名利为伊都忘了。", "血写香笺，泪封罗帕，记三日、离肠恨搅。", "如今事，十二楼空凭谁到。", "此情悄。", "拟回船、武陵路杳。"]'),
('song-ci-271','斗百草','晁补之','宋','宋词','song-ci','斗百草','[]','往事临邛，旧游雅态羞重忆。',125,'宋词/ci.song.4000.json','["往事临邛，旧游雅态羞重忆。", "解赋才高，好音情慧，琴里句中暗识。", "正当年、似阆苑琼枝，朝朝相倚。", "便涤器何妨，当炉正好，镇同比翼。", "谁使褰裳佩失，推枕云归，惆怅至今遗恨积。", "双鲤书来，大刀诗意，纵章台、青青似昔。", "重寻事，前度刘郎转愁寂。", "谩赢得。", "对东风、对花叹息。"]'),
('song-ci-272','斗百花','晁补之','宋','宋词','song-ci','斗百花','[]','小小盈盈珠翠。',96,'宋词/ci.song.4000.json','["小小盈盈珠翠。", "忆得眉长眼细。", "曾共映花低语，已解伤春情意。", "重向溪堂，临风看舞梁州，依旧照人秋水。", "转更添姿媚。", "舆问阶上，簸钱时节，记微笑，但把纤腰，向人娇倚。", "不见还休，谁教见了厌厌，还是向来情味。"]'),
('song-ci-273','斗百花','晁补之','宋','宋词','song-ci','斗百花','[]','脸色朝霞红腻。',96,'宋词/ci.song.4000.json','["脸色朝霞红腻。", "眼色秋波明媚。", "云度小钗浓鬓，雪透轻绮香臂。", "不语凝情，教人唤得回头，斜盼未知何意。", "百态生珠翠。", "低问石上，凿井何由及底。", "微向耳边，同心有缘千里。", "饮散西池，凉蟾正满纱窗，一语系人心里。"]'),
('song-ci-274','斗百花','晁补之','宋','宋词','song-ci','斗百花','[]','斜日东风深院。',95,'宋词/ci.song.4000.json','["斜日东风深院。", "绣幕低迷归燕。", "潇洒小屏娇面，仿佛灯前初见。", "与选筵中，银盆半拆姚黄，插向凤凰钗畔。", "微笑遮纨扇。", "教展香裀，看舞霓裳促遍。", "红飐翠翻，惊鸿乍拂秋岸。", "柳困花慵，盈盈自整罗巾，须劝倒金盏。"]'),
('song-ci-275','御街行','晁补之','宋','宋词','song-ci','御街行','[]','天街欲照珠帘粉。',90,'宋词/ci.song.4000.json','["天街欲照珠帘粉。", "亸辔曾相近。", "繁花乐事老来慵，对酒尚怜佳景。", "王孙年少，风流应更，无奈春愁闷。", "幽期莫误香闺恨。", "罗带今朝褪。", "月圆花好一般春，触处总堪乘兴。", "有人惆怅，何如归好，相见凭君问。"]'),
('song-ci-276','南歌子','晁补之','宋','宋词','song-ci','南歌子','[]','睡起临窗坐，妆成傍砌闲。',62,'宋词/ci.song.4000.json','["睡起临窗坐，妆成傍砌闲。", "春来莫卷绣帘看。", "嫌怕东风吹恨、在眉间。", "鹦鹉花前弄，琵琶月下弹。", "蓦然收袖倚栏干。", "一向思量何事、点云鬟。"]'),
('song-ci-277','清平乐','晁补之','宋','宋词','song-ci','清平乐','[]','寒风雁度。',54,'宋词/ci.song.4000.json','["寒风雁度。", "声向千门去。", "也到文闱校文处。", "也到文君绣户。", "背灯解带惊魂。", "长安此夜秋声。", "早是夜寒不寐，五更风雨无情。"]'),
('song-ci-278','好事近','晁补之','宋','宋词','song-ci','好事近','[]','归路苦无多，正值早秋时节。',53,'宋词/ci.song.4000.json','["归路苦无多，正值早秋时节。", "应是画帘灵鹊，把归期先说。", "就中风送马蹄轻，人意渐欢悦。", "此夜醉眠无梦，任西楼斜月。"]'),
('song-ci-279','调笑・调笑令','晁补之','宋','宋词','song-ci','调笑・调笑令','[]','肠断。',45,'宋词/ci.song.4000.json','["肠断。", "越江岸。", "越女江头纱自浣。", "天然玉貌铅红浅。", "自弄芙蓉日晚。", "紫骝嘶去犹回盼。", "笑入荷花不见。"]'),
('song-ci-280','调笑・调笑令','晁补之','宋','宋词','song-ci','调笑・调笑令','[]','将暮。',45,'宋词/ci.song.4000.json','["将暮。", "乱心素。", "上客风流名重楚。", "临街下马当窗户。", "饭煮凋胡留住。", "瑶琴促轸传深语。", "万曲梁尘不顾。"]'),
('song-ci-281','调笑・调笑令','晁补之','宋','宋词','song-ci','调笑・调笑令','[]','波恶。',45,'宋词/ci.song.4000.json','["波恶。", "倚江阁。", "大艑轲峨帆夜落。", "横堂朱户多行乐。", "大堤花容绰约。", "宜城春酒郎同酌。", "醉倒银缸罗幕。"]'),
('song-ci-282','调笑・调笑令','晁补之','宋','宋词','song-ci','调笑・调笑令','[]','相误。',45,'宋词/ci.song.4000.json','["相误。", "空凝伫。", "郑子江头逢二女。", "霞衣曳玉非尘土。", "笑解明珰轻付。", "月从云堕劳相慕。", "自有骖鸾仙侣。"]'),
('song-ci-283','调笑・调笑令','晁补之','宋','宋词','song-ci','调笑・调笑令','[]','寸结。',45,'宋词/ci.song.4000.json','["寸结。", "肝肠切。", "织锦机边音韵咽。", "玉琴尘暗薰炉歇。", "望尽床头秋月。", "刀裁锦断诗可灭。", "恨似连环难绝。"]'),
('song-ci-284','调笑・调笑令','晁补之','宋','宋词','song-ci','调笑・调笑令','[]','心记。',45,'宋词/ci.song.4000.json','["心记。", "好心事。", "玉刻容颜眉刷翠。", "杜郎生得真男子。", "况是东家妖丽。", "眉尖春恨难凭寄。", "笑作空中唐字。"]'),
('song-ci-285','调笑・调笑令','晁补之','宋','宋词','song-ci','调笑・调笑令','[]','相忆。',45,'宋词/ci.song.4000.json','["相忆。", "顿轻掷。", "春草佳名渐赠璧。", "长洲茂苑吴王国。", "自有芊绵碧色。", "根生土长铜驼陌。", "纵欲随君争得。"]'),
('song-ci-286','洞仙歌','晁补之','宋','宋词','song-ci','洞仙歌','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','青烟幂处，碧海飞金镜。',102,'宋词/ci.song.4000.json','["青烟幂处，碧海飞金镜。", "永夜闲阶卧桂影。", "露凉时、零乱多少寒螀，神京远，惟有蓝桥路近。", "水晶帘不下，云母屏开，冷浸佳人淡脂粉。", "待都将许多明，付与金尊，投晓共、流霞倾尽。", "更携取、胡床上南楼，看玉做人间，素秋千倾。"]'),
('song-ci-287','下水船','晁补之','宋','宋词','song-ci','下水船','[]','上客骊驹系。',91,'宋词/ci.song.4000.json','["上客骊驹系。", "惊唤银屏睡起。", "困倚妆台，盈盈正解罗髻。", "凤钗垂，缭绕金盘玉指。", "巫山一段云委。", "半窥镜、向我横秋水。", "斜颔花枝交镜里。", "淡拂铅华，匆匆自整罗绮。", "敛眉翠。", "虽有愔愔密意，空作江边解佩。"]'),
('song-ci-288','失调名','晁补之','宋','宋词','song-ci','失调名','[]','残腊初雪霁。',95,'宋词/ci.song.4000.json','["残腊初雪霁。", "梅白飘香蕊。", "依前又还是，迎春时候，大家都备。", "灶马门神，酒酌酴酥，桃符尽书吉利。", "五更催驱傩，爆竹起。", "虚耗都教退。", "交年换新岁。", "长保身荣贵。", "愿与儿孙、尽老今生，祝寿遐昌，年年共同守岁。"]'),
('song-ci-289','洞仙歌','晁补之','宋','宋词','song-ci','洞仙歌','[]','江陵种橘，尚比封侯贵。',106,'宋词/ci.song.4000.json','["江陵种橘，尚比封侯贵。", "何况江涛转千里。", "带天香，含洞乳，宜入春盘，红荔子，驰驿风流仅比。", "齿疏潘令老，怯咀冰霜，十颗金苞谩分遗。", "记觞前、须细认，别有馀甘，从此去，枉却栽桃种李。", "想相如酒渴对文君，迥不是人间，等闲风味。"]'),
('song-ci-290','洞仙歌','晁补之','宋','宋词','song-ci','洞仙歌','[]','温江异果，惟有泥山贵。',106,'宋词/ci.song.4000.json','["温江异果，惟有泥山贵。", "驿送江南数千里。", "半含霜，轻噀雾，曾怯吴姬，亲赠我，绿桔黄柑怎比。", "双亲云水外，游子空怀，惆怅无人可归遗。", "报周郎、须念我，物少情多，春酒醉，独胜甜桃醋李。", "况灯火楼台近元宵，似不减年时，袖中香味。"]'),
('song-ci-291','菩萨蛮','陈师道','宋','宋词','song-ci','菩萨蛮','[]','行云过尽星河烂。',52,'宋词/ci.song.4000.json','["行云过尽星河烂。", "炉烟未断蛛丝满。", "想得两眉颦。", "停针忆远人。", "河桥知有路。", "不解留郎住。", "天上隔年期。", "人间长别离。"]'),
('song-ci-292','菩萨蛮','陈师道','宋','宋词','song-ci','菩萨蛮','[]','东风乌鹊西飞燕。',52,'宋词/ci.song.4000.json','["东风乌鹊西飞燕。", "盈盈一水经年见。", "急雨洗香车。", "天回河汉斜。", "离愁千载上。", "相远长相望。", "终不似人间。", "回头万里山。"]'),
('song-ci-293','菩萨蛮','陈师道','宋','宋词','song-ci','菩萨蛮','[]','绮楼小小穿针女。',52,'宋词/ci.song.4000.json','["绮楼小小穿针女。", "秋光点点蛛丝雨。", "今夕是何宵。", "龙车乌鹊桥。", "经年谋一笑。", "岂解令人巧。", "不用问如何。", "人间巧更多。"]'),
('song-ci-294','菩萨蛮','陈师道','宋','宋词','song-ci','菩萨蛮','[]','银潢清浅填乌鹊。',52,'宋词/ci.song.4000.json','["银潢清浅填乌鹊。", "画檐急雨长河落。", "初月未成圆。", "明星惜此筵。", "愁来无断绝。", "岁岁年年别。", "不用泪红滋。", "年年岁岁期。"]'),
('song-ci-295','木兰花・玉楼春','陈师道','宋','宋词','song-ci','木兰花・玉楼春','[]','阴阴云日江城晚。',64,'宋词/ci.song.4000.json','["阴阴云日江城晚。", "小院回廊春已满。", "谁教言语似鹂黄，深闭玉笼千万怨。", "蓬莱易到人难见。", "香火无凭空有愿。", "不辞歌里断人肠，只怕有肠无处断。"]'),
('song-ci-296','南柯子・南歌子','陈师道','宋','宋词','song-ci','南柯子・南歌子','[]','故国山河在，新堂冰雪生。',62,'宋词/ci.song.4000.json','["故国山河在，新堂冰雪生。", "万家和气贺初成。", "人在笙歌声里、暗生春。", "今代无双士，当年第一人。", "杯行到手莫辞频。", "明日凤池归路、隔清尘。"]'),
('song-ci-297','西江月','陈师道','宋','宋词','song-ci','西江月','[]','楼上风生白羽，尊前笑出青春。',58,'宋词/ci.song.4000.json','["楼上风生白羽，尊前笑出青春。", "破红展翠恰如今。", "把酒如何不饮。", "绣幕灯深绿暗，画帘人语黄昏。", "晚云将雨不成阴。", "竹月风窗弄影。"]'),
('song-ci-298','菩萨蛮','陈师道','宋','宋词','song-ci','菩萨蛮','[]','喧喧车马西郊道。',52,'宋词/ci.song.4000.json','["喧喧车马西郊道。", "临行更觉人情好。", "住有一年情。", "去留千载名。", "离歌声欲尽。", "只作常时听。", "天上玉堂东。", "阳春是梦中。"]'),
('song-ci-299','虞美人','陈师道','宋','宋词','song-ci','虞美人','[]','城南观阁连云起。',66,'宋词/ci.song.4000.json','["城南观阁连云起。", "形像丹青里。", "使君笳鼓渡江来。", "尽带江南春色、放春回。", "青春欲住风催去。", "流水花无数。", "尊前触目一番新。", "只有玉楼明月、记游人。"]'),
('song-ci-300','木兰花・玉楼春','陈师道','宋','宋词','song-ci','木兰花・玉楼春','[]','湖平木落摇空阔。',64,'宋词/ci.song.4000.json','["湖平木落摇空阔。", "叶底流泉鸣复咽，酒边清漏往时同，花里朱弦纤手抹。", "风光过手春冰滑。", "十事违人常七八。", "不将白发并黄花，拟下清流揽明月。"]'),
('song-ci-301','南乡子','陈师道','宋','宋词','song-ci','南乡子','[]','晴野下田收。',66,'宋词/ci.song.4000.json','["晴野下田收。", "照影寒江落雁洲。", "禅榻茶炉深闭阁，飕飕。", "横雨旁风不到头。", "登览却轻酬。", "剩作新诗报答秋。", "人意自阑花自好，休休。", "今日看时蝶也愁。"]'),
('song-ci-302','南乡子','陈师道','宋','宋词','song-ci','南乡子','[]','潮落去帆收。',66,'宋词/ci.song.4000.json','["潮落去帆收。", "沙涨江回旋作洲。", "侧帽独行斜照里，飕飕。", "卷地风前更掉头。", "语妙后难酬。", "回雁峰南未得秋。", "唤取佳人听旧曲，休休。", "瘴雨无花孰与愁。"]'),
('song-ci-303','西江月','陈师道','宋','宋词','song-ci','西江月','[]','点点轻黄减白，垂垂重露生鲜。',58,'宋词/ci.song.4000.json','["点点轻黄减白，垂垂重露生鲜。", "肌香骨秀月中仙。", "雪满瑶台曳练。", "绰约却宜长见，清真不假馀妍。", "殷勤与插小婵娟。", "要试尊前玉面。"]'),
('song-ci-304','西江月','陈师道','宋','宋词','song-ci','西江月','[]','叶叶枝枝绿暗，重重密密红滋。',58,'宋词/ci.song.4000.json','["叶叶枝枝绿暗，重重密密红滋。", "芳心应恨赏春迟。", "不会春工著意。", "晚照酒生娇面，新妆睡污胭脂。", "凭将双叶寄相思。", "与看钗头何似。"]'),
('song-ci-305','菩萨蛮','陈师道','宋','宋词','song-ci','菩萨蛮','[]','髻钗初上朝云卷。',52,'宋词/ci.song.4000.json','["髻钗初上朝云卷。", "眼波翻动眉山远。", "一曲杜韦娘。", "当年枉断肠。", "佳期如好月。", "拟满还须缺。", "别易见应难。", "长须仔细看。"]'),
('song-ci-306','减字木兰花','陈师道','宋','宋词','song-ci','减字木兰花','[]','清尊白发。',52,'宋词/ci.song.4000.json','["清尊白发。", "曾是登临年少客。", "不似当年。", "人与黄花两并妍。", "来愁去恨。", "十载相看情不尽。", "莫更思量。", "梦破春回枉断肠。"]'),
('song-ci-307','满庭芳','陈师道','宋','宋词','song-ci','满庭芳','[]','闽岭先春，琅函联璧，帝所分落人间。',118,'宋词/ci.song.4000.json','["闽岭先春，琅函联璧，帝所分落人间。", "绮窗纤手，一缕破双团。", "云里游龙舞凤，香雾起、飞月轮边。", "华堂静，松风竹雪，金鼎沸湲潺。", "门阑。", "车马动，扶黄籍白，小袖高鬟。", "渐胸里轮囷，肺腑生寒。", "唤起谪仙醉倒，翻湖海、倾泻涛澜。", "笙歌散，风帘月幕，禅榻鬓丝斑。"]'),
('song-ci-308','南乡子','陈师道','宋','宋词','song-ci','南乡子','[]','急雨打寒窗。',66,'宋词/ci.song.4000.json','["急雨打寒窗。", "雨气侵灯暗壁缸。", "窗下有人挑锦字，行行。", "泪湿红绡减旧香。", "往事最难忘。", "更著秋声说断肠。", "曲渚圆沙风叶底，藏藏。", "谁使鸳鸯故作双。"]'),
('song-ci-309','清平乐','陈师道','宋','宋词','song-ci','清平乐','[]','休休莫莫。',54,'宋词/ci.song.4000.json','["休休莫莫。", "更莫思量著。", "记著不如浑忘著。", "百种寻思枉却。", "绣囊锦帐吹香。", "雄蜂雌蝶难双。", "眉上放开春色，眼前怜取新郎。"]'),
('song-ci-310','清平乐','陈师道','宋','宋词','song-ci','清平乐','[]','藏藏摸摸。',54,'宋词/ci.song.4000.json','["藏藏摸摸。", "好事争如莫。", "背后寻思浑是错。", "猛与将来放著。", "吹花卷絮无踪。", "晚妆知为谁红。", "梦断阳台云雨，世间不要春风。"]'),
('song-ci-311','南乡子','陈师道','宋','宋词','song-ci','南乡子','[]','阴重雨垂垂。',66,'宋词/ci.song.4000.json','["阴重雨垂垂。", "并马西郊试薄衣。", "红蕊未开花已过，迟迟。", "不见东风著意时。", "酒到更须辞。", "报答春光旧有期。", "勤苦著书妨作乐，痴痴。", "莫学衰翁万事非。"]'),
('song-ci-312','罗敷媚・采桑子','陈师道','宋','宋词','song-ci','罗敷媚・采桑子','[]','春风吹尽秋光照，瘦减初黄。',52,'宋词/ci.song.4000.json','["春风吹尽秋光照，瘦减初黄。", "改样新妆。", "特地相逢只认香。", "南台九日登临处，不共飞觞。", "镜里伊傍。", "独秀钗头殿众芳。"]'),
('song-ci-313','罗敷媚・采桑子','陈师道','宋','宋词','song-ci','罗敷媚・采桑子','[]','芙蓉不借韶华助，故著缃黄。',52,'宋词/ci.song.4000.json','["芙蓉不借韶华助，故著缃黄。", "宿面留妆。", "不出寒花只暂香。", "伤春不尽悲秋苦，落蕊浮觞。", "知在谁傍。", "一笑盈盈百种芳。"]'),
('song-ci-314','木兰花・玉楼春','陈师道','宋','宋词','song-ci','木兰花・玉楼春','[]','荣光休气天为瑞。',64,'宋词/ci.song.4000.json','["荣光休气天为瑞。", "道祖当天传宝裔。", "千年昌运此时逢，四海欢声今日沸。", "濛濛香雾沾衣腻。", "漠漠轻寒梅柳细。", "封人长有祝尧心，从此年年并岁岁。"]'),
('song-ci-315','木兰花减字・减字木兰花','陈师道','宋','宋词','song-ci','木兰花减字・减字木兰花','[]','娉婷娜袅。',52,'宋词/ci.song.4000.json','["娉婷娜袅。", "红落东风青子小。", "妙舞逶迤。", "拍误周郎却未知。", "花前月底。", "谁唤分司狂御史。", "欲语还休。", "唤不回头莫著羞。"]'),
('song-ci-316','木兰花减字・减字木兰花','陈师道','宋','宋词','song-ci','木兰花减字・减字木兰花','[]','娉娉袅袅。',52,'宋词/ci.song.4000.json','["娉娉袅袅。", "芍药枝头红玉小。", "舞袖迟迟。", "心到郎边客已知。", "当筵举酒。", "劝我尊前松柏寿。", "莫莫休休。", "白发簪花我自羞。"]'),
('song-ci-317','临江仙','陈师道','宋','宋词','song-ci','临江仙','[]','离别寻常今白首，更须竹雨萧萧。',70,'宋词/ci.song.4000.json','["离别寻常今白首，更须竹雨萧萧。", "不应都占世间豪。", "清风居士手，杨柳洛城腰。", "文字功名真自误，从今好月良宵。", "只消怜取董娇饶。", "修门君自到，不用我词招。"]'),
('song-ci-318','南柯子・南歌子','陈师道','宋','宋词','song-ci','南柯子・南歌子','[]','天上云为瑞，人间睡作魔，疏帘清簟汗成河。',62,'宋词/ci.song.4000.json','["天上云为瑞，人间睡作魔，疏帘清簟汗成河。", "酒醒梦回眵眼、费摩娑。", "但有寒喧问，初无凤鸟过。", "尘生铜碾网生罗。", "一喏十年犹未、意如何。"]'),
('song-ci-319','木兰花减字・减字木兰花','陈师道','宋','宋词','song-ci','木兰花减字・减字木兰花','[]','匀红点翠。',52,'宋词/ci.song.4000.json','["匀红点翠。", "取次梳妆谁得似。", "风柳腰肢。", "尽日纤柔属阿谁。", "娇娇小小。", "却是寻春人较老。", "著便休痴。", "付与风流幕下儿。"]'),
('song-ci-320','清平乐','陈师道','宋','宋词','song-ci','清平乐','[]','秋声隐地。',54,'宋词/ci.song.4000.json','["秋声隐地。", "叶叶无留意。", "冰簟流光团扇坠。", "惊起双栖燕子。", "夜堂帘合回廊。", "风帏吹乱凝香。", "卧看一庭名月，晓衾不耐初凉。"]'),
('song-ci-321','清平乐','陈师道','宋','宋词','song-ci','清平乐','[]','秋光烛地。',54,'宋词/ci.song.4000.json','["秋光烛地。", "帘幕生秋意。", "露叶翻风惊鹊坠。", "暗落青林红子。", "微行声断长廊。", "熏炉衾换生香。", "灭烛却延明月，揽衣先怯微凉。"]');
